(86, 'C251229006', '<p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">Tambahan komplain: </span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">1. Tembok depan pada retak </span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">2. Keramik pada ke angkat </span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">3. garasi ngebelah bawah nya trus keluar mata air saat hujan</span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">4. tembok2 udh pda retak Kya mau ambruk</span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">5. plafon kamar udh ambruk, </span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">6. depan ruang tamu mau ambruk plafon nya</span></p><p><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">7. kamar pertama&nbsp;</span><span style=\"color: rgb(33, 37, 41); font-family: &quot;Open Sans&quot;, sans-serif;\">mau ambruk plafon nya</span></p>', '2026-02-19 10:34:36', 10118, NULL),
