(33, 'C240614001', NULL, 5, 5, 'Sudah terpasang.. nanggapi komplain bisa lebih cepat saja .\nTerimaksih', '5', 5.0, '2025-02-26 14:26:35'),
(34, 'C240610001', NULL, 5, 5, 'Kepuasan sudah bagus.\nPelayan mkt juga cukup membantu.\nCuma respon bagian perbaikan harus d  sedikit d perbaiki. Mulai dri respon pengerjaan dan informasi nya. Terimaksih', '5', 5.0, '2025-02-26 14:31:22'),
(35, 'C240908002', NULL, 5, 5, 'Sudah bagus.. hanya saja perbaikan terlalu lama nunggunya.\nMinta tolong d perbaiki lagi ', '5', 5.0, '2025-02-26 14:45:25'),
(36, 'C240811001', NULL, 5, 5, 'Sudah cukup baik dalam perbaikan. Meskipun nunggu nya lumayan lama.\nPerbaiki cara perbaikannya saja . ', '5', 5.0, '2025-02-26 14:48:17'),
(37, 'C250220006', NULL, 5, 5, 'Secara menyeluruh semuanya bagus dalam melakukan pelayanan. \nSama marketing juga lebih puas lagi pelayanannya jangan sudah tahap mau akad kredit sedikit slow respon apalagi saya pembelian cash keras\nSaran : lebih cepat respon aja. Terimaksih', '5', 5.0, '2025-02-27 09:47:23'),
(38, 'C250114003', NULL, 5, 5, 'Sudah cukup baik pengerjaan nya.\nNext nya kalau ada komplain dri konsumen minta tolong segera d perbaiki jangan nunggu sampe lama . Untuk rumah trusmiland semoga sukses terus', '5', 5.0, '2025-02-27 10:41:23'),
