(41, 'C240921001', NULL, 5, 5, 'Pengerjaan cukup cepat dan sangat tangkap.\nMarketing juga lumayan cepat kasih infomasi nya. Semua nya bagus.', '5', 5.0, '2025-02-27 14:19:40'),
(42, 'C240619001', NULL, 5, 5, 'Semuanya sudah nyala listrik\nPengerjaan lumayan bagus.\nMarketing sangat membantu', '5', 5.0, '2025-02-27 14:23:53'),
(43, 'C240618001', NULL, 5, 5, 'Sudah terpasang dan sudah nyala semua. Semua bangunan juga udah bagus .\nMasukanya buat kedepanya promo ny d banyakin lagi ', '5', 5.0, '2025-02-27 14:26:49'),
