(113, 'C250225003', NULL, 5, 5, 'Untuk pemborong pembangunan mohon lebih di pantau bapak/ibu\nKarena untuk di getasan,yg saya alami bangunannya banyak yg kudu di benerin sendiri.\nUntuk tim marketing mah saya apresiasi terimakasih banyak karena bener2 di kawal dari 0 sampai akad,sampai after salespun tetep di dampingi.\n', '5', 5.0, '2025-03-03 15:07:38'),
(115, 'C240923003', NULL, 4, 4, 'Pemasangan PDAM sedikit terhambat.. \nNext nya langsung cepat d tanganin', '3', 3.7, '2025-03-04 10:36:12'),
(116, 'C240909004', NULL, 5, 5, 'Sudah terpasang', '5', 5.0, '2025-03-04 10:37:48'),
(117, 'C250111002', NULL, 4, 4, 'Keterlambatan respon. \nJadi saya inisiatif bangun sendiri kerusakan nya. \n\nMohon kedepanya agar lebih tangkap dan ada informasi yg terbaru. \n\nSaya sedikit kecewa. ', '3', 3.7, '2025-03-06 09:39:07'),
(118, 'C250225002', NULL, 4, 4, 'Saran si setiap sudah Sp3k itu langsung di bangun, biar cepet akad dan Sp3k tidak expired .. temen saya sudah sp3k tapi karena expired jadi riject saat update berkas.. terima kasih', '5', 4.3, '2025-03-07 08:37:50'),
(119, 'C250127001', NULL, 4, 4, 'Hasil perbaikan rumah contoh belum sesuai..masih belum rapi', '5', 4.3, '2025-03-08 11:34:17'),
(120, 'C250220004', NULL, 4, 4, 'Untuk pemasangan PDAM lumayan lama, kurang tanggap untuk merespon \nUntuk bangunan sih masih aman. \nKedepannya bisa lebih cepat respon. Terimakasih', '5', 4.3, '2025-03-10 08:08:44'),
(121, 'C250114001', NULL, 1, 1, 'hasil pembangunan rumah yang tidak sesuai ekspektasi bahkan kurang dari pada pembangunan rumah yang standar membuat saya kecewa dengan hal tersebut, bahkan setelah mengajuan aftersales hanya dikerjakan beberapa saja dari yang diajukan karena respon dari pihak developer, admin, marketing, pengawas juga tidak responsif, dilempar lempar sehingga saya sebagai customer dibuat lelah karena terus meminta perbaikan tapi tidak ada respon positif, meninggalkan beberapa bagian yang tidak diperbaiki. bahkan pengajuan untuk pergantian biaya PDAM (bulan desember) karena dipakai oleh tukang/pekerja sampai sekarang belum diganti, sebagai customer merasa dirugikan cicilan tetap berjalan tapi pembanguan tidak sesuai.\nsaya berharap untuk pembangunan selanjutnya sesuai standar pembangunan perumahan subsidi yang ada, tidak merugikan customer.', '1', 1.0, '2025-03-10 08:31:21'),
(122, 'C250303001', NULL, 4, 4, 'Sangat bagus, Denga adanya Devisi yg khusus Nangin complain, jadi jelas, keluhan sy terjawab...\n\nSemoga team projects bisa cepat merealisasikannya...\n\nAgar sy & keluarga bisa berlebaran di Rumah Baru ', '5', 4.3, '2025-03-10 16:14:18'),
(123, 'C250128001', NULL, 4, 4, 'Sudah lagi berjalan,\nUntuk penangananya kurang cepat alasanya d karena kurang orang katanya.\nUntuk kedepanya saya minta tolong keluhan warga segera d beresin.\nSaya soal nya banyak nerima komplain dri warga sekitar.\nKedepanya di tambah lagi orang biar segera cepat d tangani', '5', 4.3, '2025-03-11 11:08:13'),
(124, 'C250226001', NULL, 5, 4, 'Pemberian toren sangat lama .\nPerbaikan juga lumayan lama.\nRespon juga sangat kurang .\nKedepannya harus cepat tanggap.\n', '5', 4.7, '2025-03-11 13:25:15'),
