('C240501001', 4, 35, 'RN Indramayu', 'C37', 'CS2309270100', 'catimah', 'Infrastruktur', 'Mohon maaf pak sebelumnya saya ingin konfirmasi untuk perumahan saat ini hampir semua selesai , dan pihak devloper mengkonfirmasi segera menempati untuk rumahnya .\r\nNamun perlu diketahui untuk jalan di Blok C kami masih sangat hancur , tidak bisa diakses sama sekali baik motor maupun mobil .\r\nMohon dibantu agar layak dilalui saja dulu oleh motor atau mobil . Kami tidak berharap cepat untuk prosea pappingblok namun kami sangat memohon dilayak kan saja dlu , karena sebagian besar mereka ingin menempati dan meronavasi namun  terkendala oleh keadaan jalan yang masih sangat tidak layak . Terimakasih mohon segera ditindk lanjuti kembali m', 2, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-05-01 14:55:56', 5428, NULL, NULL, NULL, '2024-05-02 08:40:44', 5014, 'Silamba Syailendra', 'ok, tolong dibantu', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240503001', 10, 35, 'RN Indramayu', 'C37', 'CS2309270100', 'catimah', 'Aftersales', 'Mohon maaf pak, mohon ditindak lanjuti untuk Rumah sya Blok C37, untuk smua lantai keramiknya naik seperti gundukan baik di kamar 1 , 2 , ruang tamu dan juga Kamar mandi, sehingga untuk pintu kamar tidak bisa digerakan , dan beberapa lantai pecah akibat dari tanah yang naik .\r\nMohon ditindak lanjuti agar diperbaiki karena saat ini rumah blm ditempatin dan belum ada renovasi .\r\n', 6, 100, 2, 4, '2024-08-18 08:00:00', '2024-08-31 23:00:00', '2024-08-31', '2024-08-30 10:56:20', NULL, NULL, '2024-05-03 10:34:01', 5428, NULL, NULL, NULL, '2024-05-03 15:39:02', 5014, 'Silamba Syailendra', 'Tolong dibantu, terimakasih', 2964, 'Bregas Prakoso ', '2024-05-06 17:08:25', 'perbaikan akan dikerjakan setelah perbaikan jalan  untuk akses material', '5702', 'selesai perbaikan', '', 1, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240504001', 3, 42, 'RN Kendal', 'E67', NULL, 'Belum ada Customer', 'Keramik naik cett depan berlumut', '<p>Complain blok e67&nbsp;</p><p>* carport retak</p><p>*taman retak</p><p>*cet dinding depan berlumut dan mengelupas</p><p>*topi-topi jendela ambruk</p><p>*kramik ruang tamu naik</p><p>*keramik kamar 1 naik</p><p>*kramik kamar 2 naik</p><p>*krn shower belum terpasang</p><p>*dinding kamar 1 dan 2 retak</p><p>*pintu depan cet kusam</p><p>*dinding ruang tamu retak</p>', 3, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-05-04 10:40:08', 1207, NULL, NULL, NULL, '2024-05-04 10:42:26', 786, 'Abdul Goffar', 'Koordinasi sm after sales', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
