('C240801013', 3, 35, 'RN Indramayu', 'E32', 'CS2311280002', 'Salikun', 'Progres Bangunan', 'Teras rumah jebol, keramik naik turun ada yang blm di pasang juga setiap ruangan , bocor , atap genteng ada yang kabur, cat pudar , kran kamar mandi belum ada , jendela belum rapi \r\nTolong setiap vendor perhatikan bangunan seacara detail ', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 07:37:16', 5428, NULL, NULL, NULL, '2024-08-01 13:10:04', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek dahulu terkait komplain an ini dan segera progres', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:55:52', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
