('C240801015', 3, 35, 'RN Indramayu', 'B26', 'CS2305170196', 'Puspa rita', 'Progres Bangunan', 'Untuk bangunan rumah blm rapi, contohnya kaya cat, keramik naik turun , instalasi listrik belum di sambungin kedalam, Pintu engga bisa di dorong Kran kamar mandi blm ada Keramik pada kotor, jendela pada terkupas blm rapi , pintu blm rapi ada yang pecah', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 07:41:04', 5428, NULL, NULL, NULL, '2024-08-01 13:08:41', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek dahulu terkait komplain an ini dan segera progres', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:57:03', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801016', 10, 35, 'RN Indramayu', 'D36', 'CS2305190041', 'Siti Juariah', 'Aftersales', '\"\r\n\r\nRumah Ningrat\r\n\r\nForm Komplain\r\nForm komplain untuk customer Rumah Ningrat\r\n\r\nKeramik d sejumlah tempat yang rusak karena tanah yg masih belum stabil, keramik yg retak karena tanah yg menggembung d area ruang tamu, kamar 1, kamar 2.. Ada retakan d dinding dinding Ada retakan d pondasi teras yg sangat mudah roboh dan teras garasi yg retak2.. Jalan depan rumah yg tidak d aspal ada genangan air Tembok samping yang tidak d cat hanya d plester saja padahal sudah bayar 4 juta..', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 07:46:06', 5428, NULL, NULL, NULL, '2024-08-01 13:08:08', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek dahulu terkait komplain an ini dan segera progres', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801017', 10, 35, 'RN Indramayu', 'E45', 'CS2311070036', 'Pandu Adi Wardhana  S T', 'Aftersales', '-Carport rusak\r\n-lantai naik, tidak rata.\r\n-pintu depan seret tidak bisa dibuka karena lantai naik\r\n-tembok rembes dari bawah\r\n-kusen bagian gagang pintu depan rusak\r\n', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 09:46:44', 5428, NULL, NULL, NULL, '2024-08-01 14:50:44', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801018', 10, 35, 'RN Indramayu', 'E15', 'CS2311100239', 'Hardi wirawan', 'Aftersales', 'teras: tanah tidak rata,pembatas retak, keramik tidak rata,tembok ada retak,mengelupas,pintu tidak bisa buka tutup\r\n\r\nR.tamu: lantai naik retak dan pecah,tembok berlumut\r\n\r\nKamar 1: lantai naik ,retak dan pecah, pintu tidak bisa buka tutup,belum ada lubang kunci, tembok berlumut\r\n\r\nKamar 2: pintu tidak bisa buka tutup, belum ada lubang kunci,keramik naik,retak dan pecah,tembok berlumut,daun jendela belum ada gagangnya\r\n\r\nKamar mandi: pintu tdak bisa di tutup,plafon belum di tutup,keramik tidak rata,masih banyak celah\r\n\r\nBelakang: tanah belum rata,tembok ada retak,,pintu engsel rusak\r\n\r\n', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 10:23:44', 5428, NULL, NULL, NULL, '2024-08-01 15:24:56', 340, 'Muhammad Irfannudin ', 'Mohon untum dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801019', 10, 35, 'RN Indramayu', 'D13', 'CS2305020863', 'Maulana Fajar Aqsa', 'Aftersales', 'Akad dri tahun 2023 belum di tempatin tembok pada berlumut,keramik teras depan ga rata,plafon ada yg pecah,keran air ga ada drat,plafon wc pecah,lisplang jamuran,jendela kamer blakang ga bsa di kunci', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 11:41:02', 5428, NULL, NULL, NULL, '2024-08-01 16:42:06', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801020', 10, 35, 'RN Indramayu', 'B04', 'CS2305040657', 'Nanang Haris', 'Aftersales', 'Lisplang atas pecah,jendela miring susah dibuka atau di ttup, lis di pintu ga rapet,lis karet jendela pada kendor,pipa saluran wc pecah ketika di siram air ,kluar air di dpan setelah di cek pecah ,mohon segera dilakukan saya mau menepati secepat nya karena saya akad dari tahun 2023 ..terimakasih', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 11:45:30', 5428, NULL, NULL, NULL, '2024-08-01 16:47:03', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801021', 3, 35, 'RN Indramayu', 'A10', 'CS2402160295', 'KHOLIDAH', 'Progres Bangunan', 'Lantai ruang tamu, sebagian besar keramik amblas mohon diperbaiki', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 11:56:12', 5428, NULL, NULL, NULL, '2024-08-01 16:56:51', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek dan diprogres', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:57:48', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801022', 3, 35, 'RN Indramayu', 'B55', 'CS2305190045', 'ERIKA MAULIASARI', 'Progres Bangunan', 'Angin² depan tidak ada kaca, angin² kamar mandi tidak ada kaca, jendela belakang tidak ada slot, kramik kamar depan sedikit menggelembung, felafon angin-angin depan retak-retak. Pipa kamar mandi kebocoran, cat tembok tidak rapih, pintundepan tidak ada mur, parkiran depan minta di rapihkan, selokan pembuangan air minta di rapihkan dan di lebarkan ', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 11:57:34', 5428, NULL, NULL, NULL, '2024-08-01 17:37:49', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:58:35', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801023', 3, 35, 'RN Indramayu', 'A10', 'CS2402160295', 'KHOLIDAH', 'Progres Bangunan', 'Pintu kamar mandi tidak simetris dan susah untuk ditutup, lantai ruang tamu,lantai di kamar dibelakang amblas, tembok bekas pemasangan paralon listrik kurang rapih, plavon depan atas jendela kamar depan ada bekas bocor, coran teras retak retak, nat keramik kamar mandi pada buka, plavon kamar belakang retak rambut, kusen pintu depan dan belakang masih kosong tidak ada kompon,, ', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 12:02:54', 5428, NULL, NULL, NULL, '2024-08-01 17:04:02', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:59:28', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801024', 10, 35, 'RN Indramayu', 'E20', 'CS2305120773', 'Imam Hanapi', 'Aftersales', 'Keramik pintu rusak\r\nKamer utama keramik mumbul\r\nKamer kedua keramik mumbul\r\nPintu kamer tanah ambles\r\nCat berlumut', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 13:32:14', 5428, NULL, NULL, NULL, '2024-08-01 18:34:29', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801025', 10, 35, 'RN Indramayu', 'D07', 'CS2312090068', 'Kutim', 'Aftersales', 'Keramik mumbul pada retak/pecah pintu kamar mandi pada retak , WC minta di tinggikan karena terlalu datar, dinding berlumut minta di cat ulang \r\nBerikut kramik yang mumbul/retak: \r\n1.bagian depan \r\n2.kamar ke 1\r\n3.kamar ke2\r\n4.ruang tengah \r\nDinding berlumut \r\n\r\nPas mau di kramik alangkah baiknya minta di stempel dulu supaya padat , agar masang krmaik nya tidak asal asal.an supaya tidak cepat retak lagi \r\nSemoga cepat di ACC after sales nya supaya rumah bisa cepat di huni\r\nTrimaksih ,', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 13:34:43', 5428, NULL, NULL, NULL, '2024-08-01 18:35:57', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801026', 10, 35, 'RN Indramayu', 'E51', 'CS2404240051', 'Teguh Santoso', 'Aftersales', 'Keramik tidak rata & pecah jendela belakang belum ada , pintu tidak bisa di tutup,dan kayu pintu pecah\" plavon ambrol , kusen pintu dan jendela masih renggang,belum terplester, atap bolong,', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 13:53:30', 5428, NULL, NULL, NULL, '2024-08-01 18:54:32', 340, 'Muhammad Irfannudin ', 'Mohon jntuk di cek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801027', 3, 35, 'RN Indramayu', 'E43', 'CS2307281350', 'Andhika Purba', 'Progres Bangunan', 'Mohon untuk dipercepat untuk progres bangunan karena masih belum layak huni seperti semua pintu tidak bisa karena keramik nya mumbul, tembok retak2, engsel pintu renggang ', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-01 14:54:58', 5428, NULL, NULL, NULL, '2024-08-01 19:59:00', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 17:00:15', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240801028', 10, 35, 'RN Indramayu', 'D10', 'CS2305200162', 'Susani Fitriyani', 'Aftersales', '- cat depan mengelupas, harus dicat ulang\r\n- keramik depan, dan semua ruangan pecah serta tidak rata atau tanahnya bergelombang\r\n- jendela ruang utama dan kamar kedua sudah tidak bagus\r\n- ventilasi ruang utama jelek\r\n- tekstur bangunan di ruang tamu, kamar tidak rata bergelombang, harus didempul ulang\r\n- keran wc tidak ada\r\n- keramik wc ancur\r\n- pintu wc kurang bagus\r\n- tembok retak\r\n- plafon sudah tidak bagus', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-01 18:44:03', 5428, NULL, NULL, NULL, '2024-08-02 05:01:24', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802001', 10, 35, 'RN Indramayu', 'C30', 'CS2311080345', 'Robi Oktaria', 'Aftersales', '1. As tak kunjung terealisasi\r\n2. Surat surat ft shgb belum terima dari yg di jajikan 3bln dari akad\r\n3. Saat curah hujan tinggi debit air blok C lumayan tggu mohon pemadatan jalan dan perbaikan selokan\r\n4. Pemberian pembatas tembok samping empang khawatir anak2 bermain lolos pengawasan dan tercebur.\r\n5. Tidak dapat uang cashback 4jt \r\nSekian terima kasih\r\nSemoga jajaran RN bisa amanah,teranspara  jujur dan adil terhadap semua penghuni RN. ????????', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-02 00:58:48', 5428, NULL, NULL, NULL, '2024-08-02 06:12:59', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek Point 1', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802002', 10, 35, 'RN Indramayu', 'C24', 'CS2305171059', 'Nugie Fauzie', 'Aftersales', '1.keramik r tamu masih menggelembung karena pas aftersales pertama hanya tambal sulam tidak di lakukan pemadatan tanah dengan stemper.\r\n2. keramik belang karna pas aftersales pertama tidak di ganti semua sehinga banyak perbedaan warna\r\n3.tidak ada cover penutup MCB dalam rumah\r\n\r\n', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-02 03:04:39', 5428, NULL, NULL, NULL, '2024-08-02 08:26:09', 340, 'Muhammad Irfannudin ', 'Mohon untuk dcek dan ditinjau ulang', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802003', 3, 35, 'RN Indramayu', 'D60', 'CS2405030218', 'Rendi Antoro', 'Progres Bangunan', 'Mohon bagian bangunan yg rusak segera di perbaiki\r\n\r\n1.pintu\r\n2.lantai\r\n3.halaman depan + belakang\r\n4.atap depan\r\n\r\n25% bangunan pda rusak', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-02 06:24:51', 5428, NULL, NULL, NULL, '2024-08-02 11:28:52', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 17:01:59', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802004', 10, 35, 'RN Indramayu', 'D58', 'CS2306110061', 'Kerinih', 'Aftersales', 'Sepiteng bolong, keramik pecah,semua pintu tidak dapat di kunci ,kran kamer mandi belum ada, cat ngelupas, ', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-02 09:23:21', 5428, NULL, NULL, NULL, '2024-08-02 14:24:26', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802005', 3, 35, 'RN Indramayu', 'A27', 'CS2309020575', 'Tedi', 'Progres Bangunan', 'Keramik hancur , tidak rapi sama naik turun jadi pintu tidak bisa di dorong karena keramik tidak rapit, cat ulang pada pudar, kamar mandi keramik hancur blm ada yang di pasang , pekerjaaan tidak rapih percuma ada pengawas tapi tidak di perhatikan untuk bangunan , jendela kurang rapi , teras depan pada hancur ....', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-02 10:02:35', 5428, NULL, NULL, NULL, '2024-08-02 15:03:21', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 17:01:05', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240802006', 3, 35, 'RN Indramayu', 'B09', 'CS2310100011', 'Taryana', 'Progres Bangunan', 'Atap ada yang retak , jendela kurang rapi ada yang longgar, pintu tidak bisa di tutup , keramik kotor , teras depan rusak , cat pudar , \r\n\r\nMinta tolong di kerjain saya capek ngontrak udah hampir setahun belum di selesain, !!!!', 4, 0, 2, 3, '2024-09-25 08:00:00', '2024-09-30 23:00:00', '2024-09-30', NULL, NULL, NULL, '2024-08-02 10:15:26', 5428, NULL, NULL, NULL, '2024-08-02 15:16:49', 340, 'Muhammad Irfannudin ', 'Mohon untuk dcek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 17:02:47', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
