('C240809003', 10, 35, 'RN Indramayu', 'D01', 'CS2312120024', 'ririn trimiati', 'Aftersales', 'Kepada RAJA SUKSES PROPERTINDO,\r\nSaya ingin menyampaikan keluhan terkait status perbaikan rumah saya. Hingga saat ini, belum ada perbaikan yang dilakukan di rumah saya. Namun, saya tiba-tiba menerima pesan yang menyatakan bahwa \"konfirmasi rumah telah selesai perbaikan\" dan saya diminta untuk menandatangani Berita Acara (BA) tersebut. Situasi ini sangat tidak sesuai dengan kenyataan karena perbaikan belum pernah dilakukan sama sekali', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-09 16:12:18', 5428, NULL, NULL, NULL, '2024-08-09 21:47:11', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO `cm_task` (`id_task`, `id_category`, `id_project`, `project`, `blok`, `id_konsumen`, `konsumen`, `task`, `description`, `status`, `progress`, `priority`, `level`, `start`, `end`, `due_date`, `done_date`, `evaluation`, `file`, `created_at`, `created_by`, `created_by_contact_no`, `updated_at`, `updated_by`, `verified_at`, `verified_by`, `verified_name`, `verified_note`, `escalation_by`, `escalation_name`, `escalation_at`, `escalation_note`, `pic`, `pic_note`, `link`, `status_konsumen`, `reschedule`, `id_pekerjaan`, `id_sub_pekerjaan`, `id_detail_pekerjaan`, `divisi`, `so`, `si`, `tasklist`, `follow_up_at`, `follow_up_by`) VALUES
('C240810001', 10, 35, 'RN Indramayu', 'B43', 'CS2306220005', 'Muhammad ramadhan', 'Aftersales', 'Rumah Ningrat Blok B-43\r\nArea Teras Depan\r\n•Keran air \r\nketerangan : tolong di luruskan dan untuk tanahnya kurang rata\r\n•Tanah depan \r\nKeterangan : rumput sekalian di buang\r\n•Dinding dekat kamar jendela \r\nKeterangan : kurang rapih tolong di perbaiki\r\n•Dinding atas langit-langit dekat pintu\r\nKeterangan : kurang rapih tolong di perbaiki\r\n•Dinding atas langit-langit dekat jendela ruang tamu\r\nKeterangan : kurang rapih tolong di perbaiki & jendela nya kurang rapih \r\n•Lampu depan : tolong di perbaiki\r\n•Dinding atas jendela \r\nKeterangan : kurang rapih tolong perbaiki\r\n•Nomor rumah \r\nKeterangan : tolong di pasang\r\n•Tampak depan halaman\r\nketerangan : terlihat kumuh di dinding banyak lumut tolong di cat ulang\r\n.\r\n\r\nArea Ruang Tamu\r\n•Pintu:\r\nKeterangan : Semen di pintu kurang rapat tolong di perbaiki,\r\nPintu rusak tidak dapat terbuka di sebelah-sebelahnya tidak rata semennya tolong agar bisa di pakai dengan layak tolong di perbaiki\r\n•Keramik : \r\nKeterangan : tidak rata tolong di perbaiki agar merata (ini penting tolong)\r\n•Dinding: \r\nKeterangan : tidak rata banyak yang bolong kurang semen tolong di perbaiki agar merata\r\n•Jendela :\r\nKeterangan : kurang rapih tolong di perbaiki agar bisa di pakai dengan layak\r\n•Tanah :\r\nKeterangan : Belendung keramik tidak rata tolong di perbaiki agar bisa merata (ini penting)\r\nTampak banyak lumut di dinding tolong di cat ulang\r\n\r\n\r\nArea Kamar 1 ( kamar depan )\r\n•Keramik :\r\nKeterangan : tidak rata mohon untuk di ratakan tolong di perbaiki (ini penting)\r\n•Jendela : \r\nketerangan : kurang rapih (semen-semennya kurang rapih)\r\n•Pintu : \r\nKeterangan : kamar tidak bisa di buka karena tanah, Belendung pintu kamar rusak tolong di perbaiki \r\nkeramik tidak rata tanah Belendung\r\n\r\nArea Kamar 2 ( kamar belakang )\r\n•Keramik :\r\nKeterangan : tidak ada 1 di tengah alias kurang tolong di tambahkan agar pas keramiknya\r\nDan tanahnya Belendung tidak rata alhasil keramik tidak rata tolong di perbaiki (ini penting)\r\n•Jendela kamar : \r\nKeterangan : tolong di rapihkan agar layak di pakai tolong di perbaiki\r\n•Pintu kamar : \r\nketerangan : rusak tolong di perbaiki\r\n•Dinding :\r\nKeterangan : kurang rapih dekat keramik terlihat kumuh dan kurang rata cat nya tolong agar di cat ulang\r\n\r\nArea Kamar Mandi\r\n•Dinding keramik \r\nketerangan : tidak rata semennya kurang rapih tolong di perbaiki\r\n•Pintu : \r\nketerangan : kurang layak karena tidak rapih semen-semennya tidak rata\r\nAtap bolong tolong di perbaiki agar tidak bolong\r\nKran tidak berfungsi tolong di perbaiki\r\n\r\n\r\nArea Belakang\r\nKeterangan: Tolong di bersihkan agar tidak ada sampah atau bekas\" pembangunan \r\n•Tembok :\r\nKeterangan : bolong tolong di perbaiki\r\n•Pintu :\r\nKeterangan : tidak bisa di buka karena tanah Belendung tolong di perbaiki\r\n•Tanah : \r\nketerangan : Tanah Belendung tolong di perbaiki\r\n', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-10 04:52:54', 5428, NULL, NULL, NULL, '2024-08-10 09:58:11', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, 'https://drive.google.com/file/d/1xsEXPzpkmBjBvIFEn6V4v9DKGwDf7SZF/view?usp=drivesdk', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240810002', 10, 35, 'RN Indramayu', 'A06', 'CS2305160003', 'Amin purwito', 'Aftersales', 'Semua lantai menggelembung, pintu kamar depan tidak bisa ditutup, jendela kamar dan jendela depan juga tidak bisa dikunci. Cat area depan dan ruang tamu juga sudah mengelupas. Untuk foto dan video terlampir.', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-10 05:52:26', 5428, NULL, NULL, NULL, '2024-08-10 10:56:23', 340, 'Muhammad Irfannudin ', 'Mohon untuk\nDicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, 'https://drive.google.com/file/d/1HEkovj8SRxYlxxZbZwJyImNSCH8uybY1/view?usp=drivesdk', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240810003', 3, 35, 'RN Indramayu', 'E56', 'CS2309120056', 'Fera Febriyani', 'Progres Bangunan', 'semua ruangan keramik y pada mumbul dan tembok banyak yg rerak , atap juga ada yg jebol dan blm dicat , jendela belakang belum dicat dan bagian depan pada retak', 4, 0, 2, 3, '2024-10-09 08:00:00', '2024-10-13 23:00:00', '2024-10-13', NULL, NULL, NULL, '2024-08-10 12:09:13', 5428, NULL, NULL, NULL, '2024-08-10 18:57:01', 340, 'Muhammad Irfannudin ', 'Mohon untuk di cek', 1186, 'Idham Nurhakim Dipura', '2024-09-05 16:26:32', 'Perbaiki', '4402,2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240810004', 10, 35, 'RN Indramayu', 'B65', 'CS2305170189', 'Anin Suhastin', 'Aftersales', 'Semua keramik mengangkat \r\nSemua pintu kamar ga bisa ke buka\r\nDinding berlumut\r\nMasih ada sisa besi di tembok atap rumah\r\nJendela kamar longgar \r\nPlafon ada yg retak \r\nCarpot taman retak', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-10 12:37:10', 5428, NULL, NULL, NULL, '2024-08-10 18:58:11', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240810005', 10, 35, 'RN Indramayu', 'A02', 'CS2305110109', 'Dedi Supriyanto', 'Aftersales', 'HALAMAN DEPAN\r\n- Halam kurang tanah urugan\r\n- ⁠Metalroof tidak rata\r\n- ⁠Cat tembok mengelupas\r\n- ⁠Area jendela depan kotor\r\n- ⁠Dudukan lampu tidak ada\r\n\r\nRUANG TENGAH\r\n- Keramik tidak rata\r\n- ⁠Cat tidak rata, bekasan listrik\r\n- Engsel pintu tidak bisa ngunci\r\n\r\nKAMAR 1\r\n- Lantai tidak rata\r\n- ⁠Cat dinding mengelupas\r\n- ⁠Dudukan kunci pintu tidak ada\r\n\r\nKAMAR 2\r\n- Lantai tidak rata\r\n- ⁠Cat dinding mengelupas\r\n- ⁠Pintu tidak bisa nutup dan engsel tidak bisa ngunci\r\n\r\nKAMAR MANDI\r\n- Pemasangan slot pintu tidak bener\r\n- ⁠Pintu retak dan pecah\r\n- ⁠Engsel pintu belakang tidak bisa ngunci', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-10 12:41:36', 5428, NULL, NULL, NULL, '2024-08-10 18:58:51', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
