('C240830022', 3, 35, 'RN Indramayu', 'C31', 'CS2305230241', 'Wijdan Nabillah firdaus', 'Progres Bangunan', 'Lantai  keramik tidak rata karena pengerjaan tidak distemper, kamar mandi closet tidak presisi, dinding bagian bawah mengelupas dan berjamur, 2 pintu tidak bisa dibuka kuncinya dan jebol,  taman depan belum diurug, carport menggenang air.', 4, 0, 2, 3, '2024-10-19 08:00:00', '2024-10-23 23:00:00', '2024-10-23', NULL, NULL, NULL, '2024-08-30 12:13:55', 5428, NULL, NULL, NULL, '2024-08-30 17:20:51', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek ulang', 1186, 'Idham Nurhakim Dipura', '2024-09-05 10:34:22', 'Akan diperbaiki', '2951', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
