('C240831003', 10, 35, 'RN Indramayu', 'A13', 'CS2305290152', 'Rudi agung Setya apl', 'Aftersales', 'Keramik gelembung, ruang tamu, kamar 1,kamar2,tempat lampu teras temboknya pecah, tembok belakang dekan kamar 2 retak, pintu gak bisa di tutup, semua pintu, tembok depan ama dalam di cet ulang, kami sebagai konsumen hanya ingin bahanya aja seperti:\r\n- pasir\r\n- semen\r\n- cat depan ama dalam\r\n- kramik\r\nMon untuk depeloper bisa menyediakan bahan yg kami ajukan', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-31 04:28:40', 5428, NULL, NULL, NULL, '2024-08-31 09:30:03', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240831004', 10, 35, 'RN Indramayu', 'B23', 'CS2305030058', 'Bahiyatul firdausy/YOGI SEPTIAN', 'Aftersales', 'Handle pintu kamar 1dan 2 serta pintu utama rusak dan ganti karna kunci tidak bisa d gunakan,plafond d cat ulang,balok Selasar teras miring kaya deflovernya,cat dinding kotor kena material semen d taro d ruangan sini ', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-31 09:53:17', 5428, NULL, NULL, NULL, '2024-08-31 15:17:08', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240831005', 10, 35, 'RN Indramayu', 'B23', 'CS2305030058', 'Bahiyatul firdausy/YOGI SEPTIAN', 'Aftersales', 'Kunci handle semua ruangan g bisa d gunain handle pintu depan rusak d ganti,Keramik ganti,cat ulang plafond dan dinding Selasar teras miring balok jendela kurang acian dan plesteran semua ruangan d cat kembali ', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-08-31 10:15:21', 5428, NULL, NULL, NULL, '2024-08-31 15:17:59', 340, 'Muhammad Irfannudin ', 'Double input ', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240901001', 10, 35, 'RN Indramayu', 'D55', 'CS2304240456', 'Fauzan septyadi', 'Aftersales', 'Layanan garansi sangat lambat. Pembanguna RN Indramayu sudah mulai dari pertengahan tahun 2023 tapi sampai saat ini, September 2024 masih belum selesai juga. Bahkan kondisi rumah terbangun pun seperti rumah yang sudah lama ditinggal bertahun-tahun. Tidak layak huni. Meskipun rumah subsidi, dibandingkan dengan kualitas rumah subsidi dari perumahan sekitar seperti BDI dan Graha Alana sangat jauh. Keramik menyembul dan retak, finishing dinding banyak yang retak dan berjamur/basah, genteng bocor, carport ambrol, pemasangan kusen pintu tidak menempel pada dinding. Cicilan terus berjalan sedangkan rumah masih belum bisa ditempati. Solusinya bagaimana ya ini? Harap segera ditindak lanjuti agar rumah segera bisa ditempai dan layak huni! Kerugian yang saya alami pun secara materil dan imateril selagi menunggu rumah benar2 selesai mohon dipertanggungjawabkan!', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-01 03:43:24', 5428, NULL, NULL, NULL, '2024-09-01 08:45:57', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
