('C240909003', 10, 35, 'RN Indramayu', 'D23', 'CS2312020017', 'Useptiadi', 'Aftersales', '- Carport pada retak\r\n- ⁠Di bawah jendela depan ada retak\r\n- ⁠Pojok deket pintu depan pada retak\r\n- ⁠Pintu susah di buka atau ngegasruk\r\n- ⁠Kramik pintu depan retak\r\n- ⁠Halaman minta dibersihkan dan ditambah tanah urugan\r\n- ⁠Dideket pintu depan..kramik mau lepas\r\n- ⁠Chat di kamar nomor 1 dan dua juga sama kurang rapi dan merata terutama dibagian bawah\r\n- ⁠Chat pda ruang tamu kurang rapih\r\n- ⁠Pintu kamar nomor 1 digeser ny susah\r\n- ⁠Di ruang tamu kramik smua ny mumbul dan ga rapih\r\n- ⁠Pintu kamar nomor 2 juga susah digeser\r\n- ⁠Kamar nomor 1 atau kamar depan..hampir smua kramik agak mumbul ke atas sehingga tidak rapih\r\n- ⁠Kamar nomor dua..bnyak kramik yg kurang rapih di pasang dan kramik ny juga mumbul ke atas sehingga ga rapih\r\n- ⁠Ditembok ruang tamu bnyak cacad seperti itu..bolong bolong  bekas paku\r\n- ⁠Paku di pintu wc ilang satu\r\n- ⁠Bagian dpan rumah juga bnyak retakan\r\n- ⁠Baut engsel pintu mau lepas sehingga goyang goyang\r\n- ⁠Deket jendela depan kurang rapih\r\n- ⁠Tembok halaman retak', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-09 09:03:59', 5428, NULL, NULL, NULL, '2024-09-09 14:06:40', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek ', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
