('C240911001', 10, 35, 'RN Indramayu', 'C43', 'CS2311300006', 'Yuliana', 'Aftersales', 'pintu kamar dan pintu depan gabisa di dorong karna ganjel keramik, pintu utama rusak sampai mau roboh jika dibuka, semua ensel pintu tidak berfungsi dengan baik\r\nplafon bocor\r\ntanah tidak rata sehingga membuat keramik kebanyakan menonjol dan menggembung sehingga rentan retak\r\nsela sela pintu semuanya berjarak ', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-11 08:00:02', 5428, NULL, NULL, NULL, '2024-09-11 13:02:18', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240911002', 4, 65, 'TL Cempaka 2', 'Infrastruktur', 'CS2409060105', 'project cempaka 2 dan 3', 'plang/ petunjuk arah, Banner dan hording cempaka 2 dan 3 ', '<p>dengan adanya petunjuk dan banner memudahkan ketika cek lokasi tahu arah dan tempat project cempaka 2 dan 3</p><p><br></p>', 3, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-11 16:00:05', 2975, NULL, NULL, NULL, '2024-09-11 16:08:48', 323, 'Hendra Arya Cahyadi', 'Tidak jelas instruksi', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240911003', 12, 65, 'TL Cempaka 2', 'Infrastruktur', NULL, 'Project Cempaka 2 dan Cempaka 3', 'Plang/ petunjuk arah, Banner dan hording di Project Cempaka 2 dan Project Cempaka 3 ', '<p>Keterangan Informasi.</p><p><br></p><p>1. Plang ke 1 ( Pertama ) : Dipasang dibelokan pertama&nbsp;</p><p>&nbsp; &nbsp; &nbsp;- Plang Cempaka 2 dan cempaka 3&nbsp; &nbsp;←</p><p>&nbsp; &nbsp; &nbsp; &nbsp;Foto Terlampir.</p><p><br></p><p>2. Plang ke 2 ( kedua ) : Dipasang didekat tiang Listrik</p><p>&nbsp; &nbsp; &nbsp; - Plang Cempaka 3 ↑</p><p>&nbsp; &nbsp; &nbsp; - Plang Cempaka 2 →</p><p>&nbsp; &nbsp; &nbsp; &nbsp; Foto Terlampir</p><p><br></p><p>3. Plang ke 3 ( Ketiga ) : Dipasang di area tengah Hook Cempaka 2</p><p>&nbsp; &nbsp; &nbsp;- Plang Cempaka 2&nbsp; ←</p><p>&nbsp; &nbsp; &nbsp; &nbsp; Foto Terlampir</p><p><br></p><p>4. Buat Banner Cempaka 3 Ukuran :&nbsp; Panjang x Lebar ( 3 x 1 )</p><p>&nbsp; &nbsp; Foto Terlampir</p><p><br></p><p>5. Buat Banner Cempaka 2 Ukuran :&nbsp; Panjang x Lebar ( 3 x 1 )</p><p>&nbsp; &nbsp; Foto Terlampir</p><p><br></p><p>6. Buat Hording Cempaka 2 Ukuran menyesuaikan area dilapangan</p><p>&nbsp; &nbsp; Foto Terlampir</p><p><br></p><p>Mohon bantuannya untuk dapat di Approval</p><p>&nbsp; &nbsp;</p>', 3, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-11 17:19:04', 7113, NULL, NULL, NULL, '2024-09-24 08:53:36', 323, 'Hendra Arya Cahyadi', 'Info kurang jelas', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240911004', 12, 17, 'Trusmiland Pamengkang', 'Infrastruktur', NULL, 'rumah contoh trusmiland pamengkang', 'Pengecetan taman rumah contoh, perbaikan kerusakan carpot', 'pengecatan taman rumah contoh dan perbaikan kerusakan carport&nbsp;', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-11 17:29:15', 789, NULL, NULL, NULL, '2024-09-17 11:17:52', 323, 'Hendra Arya Cahyadi', 'Tolong ini fotonya ada plafon rusak, yg di komplainkan adalah Pengecata taman rumah dan carport. berikan inputna yang jelas', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912001', 10, 35, 'RN Indramayu', 'D16', 'CS2304171212', 'Nabila Maharani paramahitha', 'Aftersales', 'Rumah perlu perbaikan tidak layak huni, lantai pecah, tembok retak, pintu kamar mandi tidak dapat dibuka karna lantai terangkat keatas begitupun pintu kamar tidak bisa terbuka, jendela sulit dibuka, mohon perbaikan secepatnya karna akan segera ditempati dan setoran bank sudah 1 th tapi rumah sampai saat ini blm bisa ditempati.', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-12 04:18:43', 5428, NULL, NULL, NULL, '2024-09-12 09:32:32', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912002', 10, 35, 'RN Indramayu', 'D21', 'CS2304171222', 'Ruhaedi', 'Aftersales', 'Rumah perlu perbaikan tidak layak huni, lantai pecah, tembok retak, pintu kamar mandi tidak dapat dibuka karna lantai terangkat keatas begitupun pintu kamar tidak bisa terbuka, jendela sulit dibuka, mohon perbaikan secepatnya karna akan segera ditempati dan setoran bank sudah 1 th tapi rumah sampai saat ini blm bisa ditempati.', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-12 04:37:44', 5428, NULL, NULL, NULL, '2024-09-12 09:42:12', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912003', 12, 34, 'Trusmiland Caracas', 'Infrastruktur', NULL, 'No Customer', 'Perbaikan paving blok dan row akses jalan', '<ol><li>Kondisi paving blok akses masuk dari Blok B01 Caracas kondisinya rusak parah, minta segera diperbaiki dan memberikan feedback terkait progress dan leadtime pengerjaan</li><li>Row akses jalan yang ada jembatan untuk saluran air segera diperbaiki karena kondisinya mengganggu saat konsumen cek lokasi (Akses masuk Blok B, E, F)</li></ol>', 5, 0, 1, 0, '2024-09-19 13:41:31', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2024-09-12 09:59:18', 340, NULL, NULL, NULL, '2024-09-13 14:44:08', 323, 'Hendra Arya Cahyadi', 'Perbaikan oleh estate dan minta deadline W4', 2964, 'Bregas Prakoso ', '2024-09-19 13:43:01', 'msh dalam proses pengerjaan vendor dari project ', '', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912004', 10, 35, 'RN Indramayu', 'D01', 'CS2312120024', 'ririn trimiati', 'Aftersales', 'Kepada RAJA SUKSES PROPERTINDO, Saya ingin menyampaikan keluhan terkait status perbaikan rumah saya. Hingga saat ini, belum ada perbaikan yang dilakukan di rumah saya. Situasi ini sangat merugikan saya, karna sudah masuk cicilan ke 6 rumah belum dapat ditempatkan. Mohon klarifikasinya dan menghubungi saya / merespon komplain saya ini. ', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2024-09-12 08:05:28', 5428, NULL, NULL, NULL, '2024-09-12 13:28:51', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912005', 3, 35, 'RN Indramayu', 'E36', 'CS2305170065', 'Muhamad surip', 'Progres Bangunan', 'poni teras depan miring, keramik depan jeblos , angin angin engga ada kacanya , cat dalam cat luar , \r\nsaya mohon minta bahan metarial seperti keramik, semen , kaca , cat luar dalam dan besi , pasir .\r\n\r\n', 4, 0, 2, 3, '2024-10-04 08:00:10', '2024-10-09 23:00:25', '2024-10-09', NULL, NULL, NULL, '2024-09-12 08:32:01', 5428, NULL, NULL, NULL, '2024-09-12 13:33:08', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 1186, 'Idham Nurhakim Dipura', '2024-09-18 14:39:03', 'perbaiki', '4402,1637', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912006', 12, 15, 'Trusmiland Tengah Tani', 'G24', NULL, 'Kantor Pemasaran', 'Pintu Kantor Pemasaran Trusmiland Tengah Tani Rusak', 'Pak Minta dibetulkan untuk daun pintunya (gagang pintu) kantor pemasaran tengah tani, sulit dibuka tutup', 6, 100, 4, 2, '2024-09-14 17:21:33', '2024-09-14 23:00:00', '2024-09-14', '2024-09-17 08:31:23', NULL, NULL, '2024-09-12 17:08:01', 340, NULL, NULL, NULL, '2024-09-13 14:43:27', 323, 'Hendra Arya Cahyadi', 'Perbaikan oleh Helper estate segera', 2964, 'Bregas Prakoso ', '2024-09-13 17:22:22', 'proses perbaikan oleh helper estate ', '4466', 'Selesai pengerjaan pada tanggal 14 Septermber', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C240912007', 10, 34, 'Trusmiland Caracas', 'E24', 'CS2407170722', 'EDI ROHAEDI', 'Aftersales', 'Ada beberapa komplain yang ingin di perbaiki kembali :\r\n\r\n1. Lantai keramik abu kebiruan yang berbeda warna di ruang tamu dan area sekitar samping kamar mandi, ingin di samakan menjadi warna putih seperti area sekitar nya.. Kalau pun misalkan stok keramik warna putih nya memang belum ada, bisa mengambil keramik yang di teras depan saja, nanti keramik yang teras depan nya tidak apa-apa mau pakai warna abu kebiruan juga..\r\n\r\n2. Stop kontak di ruang tamu ada yang macet satu, jadi ga bisa di tekan.. \r\n\r\n3. Kunsen pintu kamar belakang alumunium nya sedikit penyok\r\n\r\n4. Pintu kamar mandi tidak bisa di tutup dari luar, jadi terbuka terus, seperti nya kurang pas dudukan nya..\r\n\r\n5. Pintu kayu kamar belakang agak kurang rapi\r\n\r\n6. Lubang pembuangan di kamar mandi, kalau bisa sekalian ingin yang tanpa warna saja (putih, stainless atau biru..)\r\n\r\n7. Cat pintu kayu yang agak kurang rapi ingin di rapikan sedikit', 5, 0, 2, 0, '2024-10-02 16:33:38', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2024-09-12 15:13:48', 5428, NULL, NULL, NULL, '2024-09-12 20:15:05', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 2964, 'Bregas Prakoso ', '2024-10-02 16:34:00', 'tolong marketing arahkan untuk input di web after sales terkait komplain atau permintaan perbaikan', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
