('C240917002', 10, 15, 'Trusmiland Tengah Tani', 'E11', 'CS2404170540', 'Sugiyono', 'kerapihan bangunan dan kebersihan halaman depan', '<p>1. tembok belakang belum full belum dipasang hebel&nbsp;</p><p>2. rumput dibagian depan halaman rumah belum dipotongin atau belum dirapihkan.</p><p>3. depan carpot masih ada kayu yang menghalangi.</p><p><br></p><p>foto terlampir</p>', 5, 0, 2, 0, '2024-09-17 11:12:59', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2024-09-17 10:18:14', 2975, NULL, NULL, NULL, '2024-09-17 11:06:36', 323, 'Hendra Arya Cahyadi', 'Di cek dahulu ini msuk ke AFS atau pemebresan projecyt, minta deadline pa bregas', 2964, 'Bregas Prakoso ', '2024-09-17 11:16:36', 'unit belom serah terima kunci  \ntidak sesuai persyaratan pengajuan AFS', '', NULL, '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
