('C250128002', 10, 19, 'RN Kayangan', 'J25', 'CS2403240063', 'MAULANA ISHAQ', 'Estate', 'Flapon bada bocor,dan sudah parahhh,tembok belakang itu rembes air dan tembok ruang depan sudah retak dan merenggang sampai 3-+5cm, dari bawah sampai ke flafon dan itu sisi kanan dan kiri sama seperti itu merenggang,lantai bawah pun mulai beruabah,dan tembok depan itu sudah retak**cuma gak separah yg d ruang tamu,flapon yg diruang tamu itu bukan cuma bocor tapi d sudut lain itu sudah retak dan dan hampir copott,sertadarikamar belakang itu selalu banjirr/mengeluarkan air darisela**pojok dan d jalur keramik itu mengeluarkan air tapi kalo hujanya lebat itu seperti nyukur air yg keluar itu lebih banyakkk seperti kerannn,kalo hujan sedang pun banjirrr,dan spitank itu gak di core melainkan hanya memakai triplek lalu diurug pake tanahhh dan itu sangat membahayakan penghuni rumahh,atap**gendeng pung banyak yg bocor terutama d belakang dan di depannn itu pada bocorrr sampe tembus ke flafon dan rembes ke tembokk,kondisi sekarang seperti ituu dan kalo hujankondisi makin parahhh,kalo dibiarkan bakal lebih parah dan makin banyak kerusakan kerusakanyaaa', 6, 100, 2, 3, '2025-03-03 16:19:10', '2025-03-11 23:00:00', '2025-03-11', '2025-06-09 09:20:08', NULL, NULL, '2025-01-28 15:04:26', 5428, NULL, NULL, NULL, '2025-01-28 15:05:22', 340, 'Muhammad Irfannudin ', 'Mohon untuk ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-02-15 16:20:03', 'tolong perbaiki', '168', 'sudah di kerjakan', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250129001', 12, 35, 'RN Indramayu', 'C30', 'CS2311080345', 'Robi Oktaria', 'Infrastruktur', 'Kena tipu maarketing padahal saya sdh cancel RN 1 pgn pindah RN 2. Tp di iming2i posisi hook blgnya ga banjir aman. Tidak sesuai ekspetasi semuanya. Dp mahal sendiri waduh. Lengkap RN 1. ', 6, 100, 2, 4, '2025-03-03 16:15:45', '2025-03-14 23:00:00', '2025-03-14', '2025-06-24 13:38:36', NULL, NULL, '2025-01-29 08:20:47', 5428, NULL, NULL, NULL, '2025-01-29 08:25:00', 340, 'Muhammad Irfannudin ', 'Mohon Segera ditindaklanjuti untuk infrastruktur ', 1186, 'Idham Nurhakim Dipura', '2025-02-15 16:17:05', 'tolong ditreatment Banjirnya Pak', '8066', 'done', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
