('C250129002', 4, 35, 'RN Indramayu', 'C30', 'CS2311080345', 'Robi Oktaria', 'Infrastruktur', 'Pembuangan talang air belakang tidak mengalir air genang. Hasilnya rembes ke dalam rumah. Acian tembok hook super tipis sdh di komplen tp ga ada progress sama sekali !!! Alhasil rembes air hujannya. Banjir rendam pembuangan air dr kamar mandi dan sepitank. Mantap paket lengkap! Ga sesuai moto ', 6, 100, 2, 4, '2025-03-03 16:17:59', '2025-04-11 23:00:00', '2025-04-11', '2025-04-11 22:44:03', NULL, NULL, '2025-01-29 19:56:20', 5428, NULL, NULL, NULL, '2025-01-29 19:57:21', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 1186, 'Idham Nurhakim Dipura', '2025-02-15 16:18:38', 'Tolong Perbaiki', '2842', '-', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250203001', 10, 29, 'Trusmiland Dawuan', 'B16', 'CS2311010187', 'Hilpian Nurpenda / Indri Putri Riani ', 'After Sales', '1. Atap Plafon kamar mandi bocor, dan dinding nya pada retak<div>2. Dinding kamar mandi yg retak</div><div>3. Kamar tidur belakang keliling pada retak</div><div>6. Kamar tidur depan keliling pada retak</div><div>7. Ruang tamu keliling pada retak</div><div>8. Teras depan dan belakang banyak rumput</div><div><br></div><div>Note : Konsumen tidak bisa pengajuan After Sales, Sudah Akad ditanggal 24 Januari 2025</div>', 6, 100, 2, 3, '2025-02-24 18:56:28', '2025-02-28 23:00:00', '2025-02-28', '2025-02-22 18:58:43', NULL, NULL, '2025-02-03 13:50:03', 3162, NULL, NULL, NULL, '2025-02-20 11:31:36', 340, 'Muhammad Irfannudin ', 'mohon ditindaklanjuti', 2842, 'Aris Kurniawan ', '2025-02-22 18:57:41', 'Tolong minta diperbaiki', '168', 'Sudah di ajukan after sales senin mau dikerjakan', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
