('C250205001', 12, 27, 'Trusmiland Diamond', 'D16', 'CS2401080262', 'Akhmad Fauzi S  Tr  T', 'Estate', 'Mohon untuk merapihkan semak-semak di depan rumah saya, karena menjadi sarang ULAT BULU\r\nULAT BULU datang setiap hari ke rumah yg menyebabkan saya dan penghuni rumah merasa gatal-gatal bahkan anak bayi saya gatal dan memerah.\r\nJika tidak segera dilakukan, saya akan membereskan sendiri dan menaruh sampah ranting dan daun di depan RUMAH CONTOH.', 6, 100, 2, 3, '2025-02-14 23:25:03', '2025-02-20 23:00:00', '2025-02-20', '2025-02-17 14:31:42', NULL, NULL, '2025-02-05 09:56:13', 5428, NULL, NULL, NULL, '2025-02-05 09:58:44', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek dan ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-02-14 23:26:25', 'Tolong segera dibenahi', '369', 'Sudah dibersihkan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
