('C250206001', 10, 15, 'Trusmiland Tengah Tani', 'E08', 'CS2405310215', 'Tuheri Suzanti', 'Aftersales', 'Bagaimana cara klaim garansi rumah? Krn kmren pas cek rumah lantai kamar belakang tiba2 ambles lntainya keangkat??', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-06 19:15:16', 5428, NULL, NULL, NULL, '2025-02-06 19:17:22', 340, 'Muhammad Irfannudin ', 'Halo Ibu sebelumnya sudah pernah akun perbaikan belum ya setelah akad klo belum web yang diinput disini salah ya Bu…terkait komplenan ini Ibu bsa koordinasikan dlu ya dengan Marketing agar bisa dibantu', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250209001', 10, 34, 'Trusmiland Caracas', 'B04', 'CS2406240423', 'Heri susilo/asyifa lugina', 'Aftersales', 'Rumah trusmiland caracas blok B 04 \r\nakad pada tanggal 21 Januari 2025\r\npengecekan tangal 8 Februari 2025 baru ada serah terima kunci dengan sales\r\nhasil pengecekan banyak PR yang harus diperbaiki\r\n1. plafon depan tampak depan bocor plafon warna hijau ada genangan air yg mengendap sehingga membuat konstruksi jadi rusak\r\n2. tampak depan area sekitar jendela depan cat tembok mengelupas & retak rambut\r\n3. area ruang tamu plafon pojok dekat area jendela bocor parah & ada retak dibelakang pintu utama\r\n4. area kamar pertama pintu tidak bisa menutup sempurna\r\n5. area kamar kedua bocor parah di dinding yang dekat batas tanah\r\n6. kamar mandi ada kekurangan keran & shower\r\nuntuk kunci kami titipkan kepada sales an Firda untuk dilakukan perbaikan terlebih dahulu\r\n', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-09 20:05:53', 5428, NULL, NULL, NULL, '2025-02-09 20:08:15', 340, 'Muhammad Irfannudin ', 'Mohon maaf untuk penginputan after sales bukan di web ini silahkan hubungin marketingnya untuk bisa di bantu penginputannya ', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
