('C250211003', 10, 20, 'Trusmiland 5', 'J09', 'CS2405120941', 'Rifky Ramadhan /Sutirah', 'Aftersales', 'Punten mau konfirmasi perihal aftersale udah ada pekerjaan belum ya\r\nKarna perbaikan nya di tgl 16 Desember 2024 s/d 03 Januari 2025\r\n\r\nDan kalau sudah ada di tgl berapa selesai nya soalnya sampe detik ini belum ada kabar perihal selesai nya aftersale dikarenakan saya sudah masuk angsuran ke 6 sampe detik ini belum ada kabar untuk selesai aftersale dll\r\n\r\n', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-11 14:19:40', 5428, NULL, NULL, NULL, '2025-02-11 14:29:33', 340, 'Muhammad Irfannudin ', 'Mohon untuk konfirmasi mktg terkait untuk meminta nomer pengaduan after salesnya ', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
