('C250215004', 3, 3, 'Trusmiland Awn Komersil', 'D13', 'CS2408160015', 'Rustaman', 'Progres Bangunan', 'Plapon ruang tamu, kamar utama, dan kamar ke dua bocor', 6, 100, 2, 3, '2025-02-22 15:51:52', '2025-03-15 23:00:00', '2025-03-15', '2025-02-26 08:49:07', NULL, NULL, '2025-02-15 17:38:34', 5428, NULL, NULL, NULL, '2025-02-15 18:15:22', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 1186, 'Idham Nurhakim Dipura', '2025-02-22 15:53:49', 'dikerjakan aftersalesnya', '168,2842', 'mintaa tolong hubungin marketing atau spvnya untuk di alihkan pengajuannya melalui web after sales https://trusmicorp.com/customer/login', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250216001', 10, 17, 'Trusmiland Pamengkang', 'H77', 'CS2411080007', 'Deika Safrin Ameylia Kelana', 'Aftersales', '1. septictank tidak ada lubang atasnya\r\n2. listik tidak menyala\r\n3. plang menghalangi  kelebihan tanah di belakang\r\n4. area teras : carport haancur, berlubang, retak\r\n5. area teras : pondasi di teras retak dan miring\r\n6. area teras : genting bocor, plafon berjamur, air mengalir di dinding sehingga lembab\r\n7. area ruang tamu : pintu utama sudah tidak layak, gagang pintu rusak, kunci sangat susah, plafon bocor bgt, rembes, berjamur, jendela rapuh dan tidak bisa ditutup\r\n8. area kamar 1 : plafon bocor, dinding lembab dan berjamur saampai hijau, cat mengelupas karena lembab parah, jendela tidak layak, tidak bisa ditutup, rapuh, pintu engsel nya aneh, tidak bisa nutup, lanta mengembang ke atas\r\n9. area kamar mandi : ada space atau jeda ruang di antara keramik lantai, kunci pintu tidak sinkron sehingga tidak bisa di tutup\r\n10. area kamar 2 : jendela tidak layak, plafon bocor buanget huhuhu, engsel pintu aneh, jadi tidak bisa nutup, lantai mengembang ke atas, plafon retak halus\r\n11. area dapur : pintu tidak layak bgt huhuhu, plafon atas bocor lembab dan berjamur, ada retaakan halus yang  tertutup cat', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-16 20:09:19', 5428, NULL, NULL, NULL, '2025-02-16 20:10:51', 340, 'Muhammad Irfannudin ', 'Untuk komplain after akad kredit silahkan input d web yg satunya silahkan hubungi marketing untuk info penginputan nya', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250217001', 10, 49, 'RN Getasan', 'B28', 'CS2407270021', 'Rizal Habibi', 'Aftersales', '1. Cat pager mulai memudar dan berkarat\r\n2. Tembok pagar belum di cat\r\n3. Pintu depan susah dibuka karena ngepres lantai, \r\n4. Pintu kamar 1 dan 2 gak bisa dibuka karena ngepres lantai\r\n5. Dinding atap retak di atas pintu kamar 1 dan 2\r\n6. Tidak ada tempat lampu di kamar mandi dan closet terlalu kecil (beda dengan ukuran closet rumah yang lain)\r\n7. Tempat lampu di teras rumah tidak berfungsi\r\n8. Dinding samping rumah belum di plester', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-17 10:58:05', 5428, NULL, NULL, NULL, '2025-02-17 11:02:52', 340, 'Muhammad Irfannudin ', 'Mohon untuk mengisi di web after sales silahkan hubungin mktg terkait untuk dbantu pengisian form after salesnay', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
