('C250217003', 10, 20, 'Trusmiland 5', 'J24', 'CS2410010015', 'Ayu Widyastuti', 'Aftersales', 'Tembok retak dan merembes air hujan, pohon di area belakang, lantai agar di nat kembali.', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-17 15:51:44', 5428, NULL, NULL, NULL, '2025-02-17 15:53:51', 340, 'Muhammad Irfannudin ', 'Mohon maaf silahkan isi komplenan di web komplen after sales silahkan kontak mktg ybs untuk membantu penginputan aftersales nya', 2842, 'Aris Kurniawan ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250219001', 10, 20, 'Trusmiland 5', 'K10', 'CS2311060489', 'Tien dwiyanti', 'Aftersales', 'Yth. Pimpinan PT Raja Sukses Propertindo\r\n\r\nSehubungan dengan rumah yang saya beli dan telah serah terima sekitar 7 bulan lalu (Juni 2024), saat ini sudah terjadi kerusakan parah, yaitu:\r\n1. Kamar belakang = keretakan parah pada dinding, lantai keramik yang rusak, dan pondasi yang amblas (nyaris ambruk seperti kena gempa)\r\n2. Ruang tengah = plafon gipsum ambruk/jatuh semua\r\n\r\nKondisi tersebut membuat saya sangat kecewa, dan bersama ini saya mengajukan permohonan perbaikan, dengan kualitas yang layak seperti tagline \"Rumah Ningrat, Harga Merakyat\". Demikian permohonan saya untuk dapat dipertimbangkan dan disetujui, terima kasih.\r\n', 6, 100, 2, 4, '2025-02-21 07:45:10', '2025-03-31 23:00:00', '2025-03-31', '2025-03-26 14:02:40', NULL, NULL, '2025-02-19 06:21:56', 5428, NULL, NULL, NULL, '2025-02-19 07:43:39', 340, 'Muhammad Irfannudin ', 'Mohon untuk dcek dan ditindaklanjuti ', 2842, 'Aris Kurniawan ', '2025-02-19 07:47:08', 'Penanggung jawab Trusmiland 5 pak tedi, mohon pak tedi sekiranya dapat dibantu', '168,1637', 'sudah di kerjakan', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
