('C250224009', 3, 19, 'RN Kayangan', 'J25', 'CS2403240063', 'MAULANA ISHAQ', 'Progres Bangunan', 'Keadaan rymahnya sudah parah pak \r\nBagian depan juga sudah mau ambles pak\r\nBagian dalem sudah pada retak pak \r\nKalo kerusakan2 kecil mungkin bisa kami atasi pak tapi ini sudah banyak kerusakan dan pergeseran pak, \r\nBagian dalem sudah pada retak pak\r\nSudah pernah ke kantor pusat juga tapi blm ada ti dakan apa apa sampai detik ini pak \r\nJangan sampai ada korban pak \r\nItu keadaan rumah sudah hampir roboh bahkan di rumah conyoh juga pak\r\nSudah pernah ke kantor pusat juga tapi blm ada ti dakan apa apa sampai detik ini pak \r\nJangan sampai ada korban pak \r\nItu keadaan rumah sudah hampir roboh bahkan di rumah conyoh juga pak\r\nJangan di biarkan saja pak \r\nJ25 itu paling parah pak \r\nWaktu awal nempatin pun sepitenk sudah bocor pak, kami renov sendiri tapi di rumah atasnya juga bocor sepitenk nya sampai ke halaman rumah kami pak\r\nKenapa tanggapannya begitu santai yah pak \r\nMaaf sebelumnya kalo saya marah2 \r\nSaya kecewa dengan pelayanan di sana\r\nRumah contoh udah parah pak \r\nRumah orang tua saya deket dengan rumah contoh pak\r\nKata proses cuma buat penenang konsumen yah pak \r\nSudah terlalu sering komplain dan balesannya sama di proses2 terus tapi enggak ada tindakan apa pun sampai detik ini', 6, 100, 2, 4, '2025-03-03 07:00:34', '2025-03-11 23:00:00', '2025-03-11', '2025-04-29 08:52:22', NULL, NULL, '2025-02-24 18:39:32', 5428, NULL, NULL, NULL, '2025-02-24 18:41:12', 340, 'Muhammad Irfannudin ', '\nMohon untuk dcek karena dr kmrn blm ada yg cek', 1186, 'Idham Nurhakim Dipura', '2025-02-26 19:09:39', 'tolong perbaiki', '168,1637', 'sudah di  kerjakan', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250225001', 12, 36, 'Arjawinangun 1 Tahap 3', 'M16', 'CS2401180076', 'Abu Abdullah', 'Keluhan Konsumen', 'Konsumen mengeluh dengan bangunan yg rapuh.. Konsumen minta tanggung jawab dari pihak trusmiland, (garansi bangunan).', 5, 0, 2, 0, '2025-02-28 06:34:32', '0000-00-00 00:00:00', '2025-03-10', NULL, NULL, NULL, '2025-02-25 07:52:20', 2768, NULL, NULL, NULL, '2025-02-25 08:25:28', 340, 'Muhammad Irfannudin ', 'Mohon untuk dicek', 1186, 'Idham Nurhakim Dipura', '2025-02-28 06:37:16', 'Garansi bangunan untuk periode akad per tgl brp?', '', NULL, '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
