('C250225004', 8, 49, 'RN Getasan', 'B05', 'CS2407280872', 'Ria Putri Sari', 'KWH Listrik', 'Aliran listrik blm masuk...\r\n\r\nInfo marketing hari Senin beres, info dari orang kantoran nya ,\r\n\r\nsampai hari ini blm', 6, 100, 2, 3, '2025-02-28 21:13:20', '2025-04-04 23:00:00', '2025-04-04', '2025-03-01 09:04:48', NULL, NULL, '2025-02-25 09:35:25', 5428, NULL, NULL, NULL, '2025-02-25 10:18:00', 340, 'Muhammad Irfannudin ', 'Mohon untuk ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-02-28 21:16:12', 'segera diperbaiki', '369', 'sudah diperbaiki', '.', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
