('C250226003', 4, 17, 'Trusmiland Pamengkang', 'G01', 'CS2407130711', 'Muhammad rifki', 'Infrastruktur', '1. Akses masuk ke G.01 tidak bisa dilalui mobil gundukan drainane terlalu tinggi\r\n2. Drainase ambruk tidak ada perbaikan\r\nSudah Mengajukan komplenan saat pengecekan qc dan sebelum terima kunci.\r\n1. Marketing galeri trusmiland\r\n2. Mas anggi marketing trusmiland\r\n3. Ibu Helis\r\n4. QC Ibu Tita Susilawaty\r\n5. Mas Rendi pic g01 pmk\r\n6. Tiktok @rumahningratofficial', 6, 100, 2, 4, '2025-02-28 06:24:12', '2025-03-17 23:00:00', '2025-03-17', '2025-03-17 16:26:28', NULL, NULL, '2025-02-26 12:40:25', 5428, NULL, NULL, NULL, '2025-02-26 12:41:46', 340, 'Muhammad Irfannudin ', 'Mohon ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-02-28 06:25:51', 'segera diperbaiki', '1293', 'sudah berjalan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
