('C250227003', 12, 33, 'Trusmiland Cempaka', 'C69', NULL, 'Rumah readystock', 'Land Klearing', '<p>Rumah readystock</p><p>Bangunan kumuh, banyak konsumen ceklok ga jadi ambil karena kondisi bangunan rapuh dan berantakan banyak rumput yg menjulang tinggi. Minta tolong diperbaiki dan dirapikan ????????????????????</p>', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-27 14:07:50', 3664, NULL, NULL, NULL, '2025-02-27 14:12:04', 340, 'Muhammad Irfannudin ', '-', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250227004', 10, 49, 'RN Getasan', 'B26', 'CS2407060962', 'Ramdansyah Qolby', 'Aftersales', '1. ada rembesan air di kamar 1 dan 2\r\n2. kondisi dinding lembab\r\n3. plafond kamar ada yg lepas\r\n4. plafond kamar mandi belum selesai (belum dipasang full dan di cat)\r\n5. keramik kamar mandi ada yg pecah\r\n6. keramik ruang tengah ada yg pecah\r\n7. keramik banyak yg kopong\r\n8. cat facade berbayang\r\n9. cat bawah kanopi berbayang\r\n10. cat pintu berbayang\r\n11. cat kamar 1 dan 2 berbayang dan mengelupas\r\n12. cat ruang tengah berbayang dan lembab\r\n13. lantai rumah kotor semua\r\n14. halaman rumah banyak rumput liar\r\n15. cat belakang berbayang dan kotor', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-27 15:59:26', 5428, NULL, NULL, NULL, '2025-02-27 16:10:54', 340, 'Muhammad Irfannudin ', 'Mohon untuk input ulang d web after sales', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250227005', 4, 17, 'Trusmiland Pamengkang', 'G04', 'CS2408280707', 'Muniah', 'Infrastruktur', 'Genteng atas nyaa acak-acakan (terbuka)\r\nDinding ruang tamu ada rembesan air \r\nKaca jendela retak seperti tergores \r\nTembok samping atas rumah minta di plester', 3, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-02-27 18:14:50', 5428, NULL, NULL, NULL, '2025-02-27 18:22:07', 340, 'Muhammad Irfannudin ', 'Mohon untuk menginput ulang d web after sales ibu/bapak info untuk mempermudah silahkan hub mktg ybs', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250228001', 3, 36, 'Arjawinangun 1 Tahap 3', 'L88', 'CS2407010001', 'Kardino', 'Progres Bangunan', 'Bangunan pda retak', 5, 0, 2, 0, '2025-03-03 17:41:37', '0000-00-00 00:00:00', '2025-03-04', NULL, NULL, NULL, '2025-02-28 10:55:54', 5428, NULL, NULL, NULL, '2025-02-28 10:57:22', 340, 'Muhammad Irfannudin ', 'Mohon ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-03 17:42:28', 'masuk sistem aftersales', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250228002', 10, 26, 'Trusmiland ITB Komersil', 'A17', 'CS2402260507', 'Muslinang Moestopo', 'mohon di bantu untuk kekurangan unit A17 ITB komersil(pemilik yayasan Kampus ITB),beliau tidak mau ST kunci dlu sebelum lengkap dan sesuai.', '<p>Berikut rincian kekuranganya :</p><p><br></p><p>.listrik di KWH ON,akan tetapi belum ada  arus di setiap colokan maupun lampu&nbsp;<div>.kebocoran tembok samping kanan</div><div>.cat ulang arae blakang&nbsp;</div><div>.pompa air belum di pasang(tidak bisa cek air),minta di pasang segera</div><div>.jendela depan  tidak bisa  dibuka</div><div>.kran depan tidak ada</div><div>. bangunan dak  atap depan miring</div><div>Mohon di bantu bapak/ibu divisi terkait di karenakan akan segara di tempati</div><div>note (;pengecekan terakhi dgn beliau di akhi januari)</div></p>', 5, 0, 2, 0, '2025-03-03 17:43:28', '0000-00-00 00:00:00', '2025-03-04', NULL, NULL, NULL, '2025-02-28 16:01:58', 3070, NULL, NULL, NULL, '2025-02-28 16:12:07', 340, 'Muhammad Irfannudin ', 'Mohon untuk ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-03 17:43:59', 'mohon dibantu masuk ke sistem aftersales', '', NULL, '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250228003', 10, 26, 'Trusmiland ITB Komersil', 'A18', 'CS2402260515', 'Muslinang Moestopo R', 'mohon di bantu untuk kekurangan unit A18 ITB komersil(pemilik yayasan Kampus ITB),beliau tidak mau ST kunci dlu sebelum lengkap dan sesuai.', '<p>Berikut rincian kekuranganya :</p><p>.kebocoran di area kamar mandi<div>.cat ulang arae blakang&nbsp;</div><div>.pompa air belum di pasang(tidak bisa cek air),minta di pasang segera</div><div>.kamar 2 cat ngelupas (minta di cat ulang)</div><div>.cat belum rapih area ruang tamu Dekat jendela depan ruang tamu</div><div>mohon di bantu bapak/ibu divisi terkait untuk segara di perbaiki di karenakan unit rumah tersebut akan segera di tempati.terimakasih</div><div>.kramik belakang kusam</div></p>', 5, 0, 2, 3, '2025-03-03 17:44:42', '0000-00-00 00:00:00', '2025-03-04', NULL, NULL, NULL, '2025-02-28 16:25:07', 3070, NULL, NULL, NULL, '2025-02-28 16:27:29', 340, 'Muhammad Irfannudin ', 'Mohon ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-03 17:45:43', 'mohon dibantu input via sistem aftersales', '', NULL, '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250228004', 10, 26, 'Trusmiland ITB Komersil', 'A03', 'CS2402050028', 'Iqbal', 'mohon di bantu litrik ITB blok A03 belum ada arus', '<p>listrik di KWH keteranganya masih tutup tidak ada arus listik yg masuk,kemudian belum bisa cek air dari pompa air di karnakan listrik belum tersedia.</p><p>mohon di bantu untuk bapak/ibu divisi terkait untuk segera di perbaiki,minggu ini konsumen akan menempati unit rumah tersebut terimkasih</p>', 6, 100, 2, 3, '2025-03-03 17:39:38', '2025-03-10 23:00:00', '2025-03-10', '2025-04-07 09:31:17', NULL, NULL, '2025-02-28 16:59:03', 3070, NULL, NULL, NULL, '2025-02-28 17:00:47', 340, 'Muhammad Irfannudin ', 'Mohon ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-03 17:40:11', 'segera diperbaiki', '8066', 'Sudah disampaikan untuk kendala ini ke timhousing untuk penyambungan listrik nya ', '', NULL, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
