('C250304001', 3, 36, 'Arjawinangun 1 Tahap 3', 'L88', 'CS2407010001', 'Kardino', 'Progres Bangunan', 'Sy ambil Unit konven, akad tgl 15 februari 2025... Bangunan dh pda retak seharus y kn ada garansi bkn y d tolak... Seharus y bangunan y d lihat dlu luar dalam... ', 6, 100, 2, 3, '2025-03-06 17:03:00', '2025-03-11 23:00:00', '2025-03-11', '2025-03-11 16:29:50', NULL, NULL, '2025-03-04 11:08:20', 5428, NULL, NULL, NULL, '2025-03-04 11:15:29', 340, 'Muhammad Irfannudin ', 'Mohon untuk ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-06 17:07:07', 'Dilaksanakan ya', '168', 'Sudah masuk ke web after sales double input', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250304002', 4, 20, 'Trusmiland 5', 'S19', 'CS220515116', 'Mochamad Nico Cheisar', 'Infrastruktur', 'Sudah 2 Tahun saya tinggal di klayan tahap 5 tapi kenapa permasalahan PENERANGAN JALAN UMUM tidak pernah di bereskan? Sudah banyak orang deh yang komplain bukan hanya saya tapi apa hasil nya? NIHIL. Saya kompalin lagi disini karena itu lampu jalan dari hari sabtu sampai detik ini belum nyala dan sering sekali LAMPU JALAN MATI. Kalian itu kerja nya apa sih merugikan konsumen aja dengan ke dzoliman kalian? Kalian pernah ga mikir dan ngerasain urgent untuk keluar malam, punya anak kecil dan hanya punya kendaraan motor tapi untuk penerangan jalan gak ada sangat gelap gulita. Bukan hanya itu kalau ibu-ibu pulang kerja malam dengan lampu yang penerangan nya minim bahkan gak ada itu gimana nasib nya?Apa kalian gak kasian ngeliatnya? Apa harus ada korban jiwa yg jatuh ke sawah atau bahkan di begal dulu baru kalian tindaklanjut ini? Coba deh kamu ke klayan tahap 5 jam 9 malam tanpa ada penerangan jalan gimana rasanya. Mikir ya tolong kalau kalian semua punya otak. Jangan sampai semuanya saya viralkan baru kalian bertindak.', 6, 100, 2, 2, '2025-03-09 17:10:54', '2025-03-09 23:00:00', '2025-03-09', '2025-03-25 14:37:30', NULL, NULL, '2025-03-04 12:48:11', 5428, NULL, NULL, NULL, '2025-03-04 12:49:04', 340, 'Muhammad Irfannudin ', 'Mohon ditindaklanjuti ', 1186, 'Idham Nurhakim Dipura', '2025-03-06 17:11:45', 'Segera diselesaikan', '8066', 'Done', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250304003', 4, 32, 'Trusmiland Cikoneng Majalengka', 'D74', 'CS2401120014', 'Moh  Fikar Fauzan', 'Infrastruktur', 'Plafon atap rumah roboh, yang di sebabkan oleh kebocoran pada genteng rumah sehingga air mengendap di plafon lalu mengakibatkan beban dari air hingga terjadinya roboh', 5, 0, 2, 0, '2025-03-06 17:07:54', '0000-00-00 00:00:00', '2025-03-11', NULL, NULL, NULL, '2025-03-04 13:54:10', 5428, NULL, NULL, NULL, '2025-03-04 13:55:40', 8070, 'Setyabudi Harimurti Satyanegara', 'Top urgent ', 1186, 'Idham Nurhakim Dipura', '2025-03-06 17:10:23', 'Rumah akad lama', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250305001', 3, 32, 'Trusmiland Cikoneng Majalengka', 'B18', 'CS2409250012', 'HERI WIRANTO', 'Progres Bangunan', 'Sangat buruk sekali trusmiland majalengka, saya sudah memilih posisi pojok dengan tambahan biaya dengan total 12jt agar bisa membuat pintu belakang di dapur akan tetapi desainnya tidak sesuai. Tolong ini bagaimana solusinya. Saya sangat kecewa sekali. Sebelum booking saya dijanjikan oleh marketing bahwa rumah yang posisi pojok sudah pasti bisa membuat pintu belakang untuk dapur tapi kenyataannya tidak. Belum lagi sampai saat ini pembangunan hanya baru pondasi saja padahal keluar sp3k sudah dari sejak 4 Oktober 2024 ini sudah hampir setengah tahun. Marketing yang lama sudah keluar tidak lagi bagian dari trusmiland saya dilepar ke marketing lain dan pada saat saya hubungi atau follow up terkait progres pembangunan alasannya vendor, tukang, kerjaan numpuk, bukan hanya melayani satu kustomer saja dan lain sebagainya. Kemudian Saya ingin memutuskan/membatalkan kelanjutan progres ini malah di tahan oleh pihak marketingnya. Bagaimana ini trusmiland katanya developer terbaik tapi nyatanya seperti ini. Apakah ada permainan?. Tolong untuk ditindak lanjuti di trusmiland majalengka.', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-03-05 08:39:11', 5428, NULL, NULL, NULL, '2025-03-05 09:14:42', 8070, 'Setyabudi Harimurti Satyanegara', 'Sudah dikerjakan 5 maret 2025, bukti ada', 1186, 'Idham Nurhakim Dipura', NULL, NULL, NULL, NULL, '-', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
