('C250408003', 3, 34, 'Trusmiland Caracas', 'B08', 'CS2410140422', 'Dede Supriyanto', 'Pembangunan tidak di teruskan', 'SP3K Pada tanggal 5 November 2025 dan DP sudah lunas tetapi bangunan tidak kunjung selesai yang menyebabkan plan akad yang seharusnya unit tersebut bisa akad menjadi tidak bisa akad. Memohon untuk bisa di percepat pembangunan agar bisa dilakukan akad kredit dan meminimalisir terjadinya riject sp3k.', 6, 100, 2, 4, '2025-04-11 18:06:10', '2025-05-06 23:00:00', '2025-05-06', '2025-06-02 13:45:24', NULL, NULL, '2025-04-08 11:00:04', 2896, NULL, NULL, NULL, '2025-04-08 11:00:04', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-08 18:06:48', 'Progres bangunan', '8890', 'progress pembangunan sudah 100%', '', NULL, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250408004', 3, 34, 'Trusmiland Caracas', 'B20', 'CS2408030231', 'Riki', 'Tidak ada kelanjutan pembangunan', '<p>SP3K September 2024</p><p>DP LUNAS</p><p>Pembangunan masih stuck dan lambat yang menyebabkan konsumen tidak bisa melakukan akad kredit yang seharusnya bisa di lakukan awal tahun 2025</p>', 6, 100, 2, 4, '2025-05-02 16:47:19', '2025-05-31 16:48:27', '2025-05-31', '2025-05-31 21:14:26', NULL, NULL, '2025-04-08 11:03:47', 2896, NULL, NULL, NULL, '2025-04-08 11:03:47', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-12 16:48:49', 'Progres unit', '8890', 'Sedang progres bangun, dr foto tersebut dapat dilihat dalam progres pembangunan', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250408005', 3, 42, 'RN Kendal', 'C33', 'CS2501280015', 'Iwan sapri', 'Progres Bangunan', 'Sudah akad bank, tapi \r\nbangunan belum ready, \r\npagar belum, \r\nhalaman tidak rata tanah dan puing2, , \r\nPlafon pecah, \r\nLantai tidak rata, belum lengkap, banyak sampah, \r\nCat kamar tidak rata, \r\nListrik belum, \r\nPdam belum', 6, 100, 2, 4, '2025-05-01 16:46:10', '2025-05-31 23:00:00', '2025-05-31', '2025-05-22 14:53:49', NULL, NULL, '2025-04-08 12:42:18', 5428, NULL, NULL, NULL, '2025-04-08 12:42:18', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-12 16:46:33', 'Progres unit', '2842', 'rumah sudah 100%', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250408006', 15, 49, 'RN Getasan', 'B12', 'CS2412080093', 'NURUL BADRIYYAH', 'Sales/Mkt (Area Cirebon)', 'Saya hanya mau komplain proses pembangunan saya yang cukup lama,  kurangnya informasi yang  saya dapatkan terkait hal tsb yang seharusnya dibantu oleh pihak marketing.  Ketika saya mengajukan komplain ke marketing terkait pembangunan, marketing selalu menjawab atau ngasih opsi untuk ganti unit padahal bukan jawaban tsb yang ingin saya dapatkan. Dan selalu ketika ditanya ganti unit prosesnya berapa lama pihak marketing tidak bisa menjawab karna hal tsb katanya masuk ke tanah nya bank. Padahal bisa di kasih tau estimasi waktu saja karna saya yakin konsumen dia bukan hanya sebelumnya . Tapi saya tidak ada jawaban setelah saya megjukan proses selanjutnya setelah akad ataupun Terima kunci sampai saya cukup muak dan saya akhirnya membatalkan dan mengundurkan diri.   Yang bikin saya lebih terkejut pembatalan say ini mendapatkan potongan ng cukup besar yaitu 50% yang tidak diinfokan ke saya ij awal pertemuan pada saat survey pertama kali terakit hal tsb. Pada proses pendirian marketing hnya mengatakan akan dipotong 20% ketika saya ditengah jalan ingin membatalkan proses pengambilan karna proses bank yang cukup lama.  Seharusnya dengan bangunan yang belum di bangun saya tidak mendapat kerugian atau potongan senilai 50%  karna informasi ini tidak dijelaskan di awal jujur ini sangat merugikan saya. ', 6, 100, 2, 4, '2025-04-10 23:05:27', '2025-04-12 23:00:00', '2025-04-12', '2025-04-11 23:31:50', NULL, NULL, '2025-04-08 20:30:21', 5428, NULL, NULL, NULL, '2025-04-08 20:30:21', 0, '', NULL, 340, 'Muhamad Irfannudin ', '2025-04-10 23:09:00', 'bm', '823,847', 'Sebelum nya kami memohon maaf yang sebesar2 nya..\nSetelah kami cek dan konfirmasi kpd sales,\nkarena sudah dilakukan pengembalian DP ,Maka komplain an ini saya anggap sudah done, terimakasih ', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250409001', 8, 42, 'RN Kendal', 'C29', 'CS2412140012', 'Anam Dharmawan', 'KWH Listrik', 'Kabel dari rumah belum menyambung ke KWH sehingga lampu tidak bisa menyala', 6, 100, 2, 3, '2025-04-26 16:43:03', '2025-04-30 23:00:00', '2025-04-30', '2025-05-01 18:45:41', NULL, NULL, '2025-04-09 10:07:51', 5428, NULL, NULL, NULL, '2025-04-09 10:07:51', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-12 16:44:07', 'KWh listrik', '8066', 'Tugas tim kami mengadakan Meteran KWH kalau ini terkait housing penyambungan meteran ke kabel tufur rumah, Untuk meteran sudah terpasang', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
