('C250410002', 3, 32, 'Trusmiland Cikoneng Majalengka', 'E32', 'CS2502160109', 'Lala Laelatul Musyarofah', 'Progres Bangunan', 'saya sudah acc OK sp3k dari 17 maret, tapi spk belum turun dan rumah juga belum dibangun sampai detik ini, tolong ini gimana perkembangan dan kelanjutannya. mohon segera ditangani', 6, 100, 2, 4, '2025-05-01 16:33:35', '2025-07-03 23:00:00', '2025-07-03', '2025-07-07 18:50:31', NULL, NULL, '2025-04-10 18:35:42', 5428, NULL, NULL, NULL, '2025-04-10 18:35:42', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-12 16:35:04', 'Pembangunan unit', '8889', 'pembangunan sudah selesai ', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250410003', 10, 20, 'Trusmiland 5', 'H17', 'CS2409240080', 'Ripai nurdin', 'Aftersales', 'Rumah sampai sekarang belum di beresin sama sekali kalau di jadwal s/d tgl 05 April 2025 tapi masih belum di garap,tolong segera di Fu lebih lanjut agar Rumah segera bisa di tempati', 6, 100, 2, 3, '2025-05-15 16:31:14', '2025-05-31 23:00:00', '2025-05-31', '2025-05-15 08:31:37', NULL, NULL, '2025-04-10 20:21:06', 5428, NULL, NULL, NULL, '2025-04-10 20:21:06', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-04-12 16:32:45', 'Perbaiki', '168', 'sudah di kerjakan', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250411001', 11, 29, 'Trusmiland Dawuan', 'C09', 'CS2501200006', 'Anwar sunandi', 'Finance', 'Maaf untuk pembangunan kapan di kerjakan soal ya saya sudah memenuhi kebutuhan finance dari DP saya sudah lunas. Pemberkasan sudah komplit persetujuan bank kami sudah di acc. Kemaren pihak trusmilend meminta persetujuan bank tapi sekarang kok lama banget ya pembangunannya. Ada apakah sebenar ya.', 6, 100, 2, 3, '2025-04-15 14:36:34', '2025-04-16 23:00:00', '2025-04-16', '2025-04-16 17:20:23', NULL, NULL, '2025-04-11 21:19:21', 5428, NULL, NULL, NULL, '2025-04-11 21:19:21', 0, '', NULL, 76, 'Yeyen Nuryenti', '2025-04-15 14:37:50', 'Mohon dibantu koordinasi dengan divisi project untuk info jadwal plan bangun blok terkait kemudian diinfokan ke konsumen. Diinfokan juga ke konsumen untuk ke depannya complain terkait pembangunan bisa ditujukan ke divisi project agar respon bisa lebih cep', '365', 'setelah dilakukan pengecekan, benar bahwa konsumen atas nama Anwar sunandi Blok C09 sudah melakukan pelunasan dan sudah SP3K.\nsudah di lakukan confirm kepada pihak terkait dan sudah mendapatkan jawaban bahwa atas unit tersebut akan dilakukan pembangunan s', '123456', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
