('C250529002', 1, 15, 'Trusmiland Tengah Tani', 'G33', 'CS2503190008', 'Yayan Panggih Hudiono', 'KUNCI RUMAH TIDAK KUNJUNG DI SERAHKAN KE ADMIN MARKETING', 'Konsumen mengeluh karena sudah akad tetapi kejelasan kunci belum ada, memohon agar segera proses pengembalian kunci karena rumah akan segera di tempati.&nbsp;', 5, 0, 2, 3, '2025-05-31 15:56:19', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-05-29 14:23:32', 2896, NULL, NULL, NULL, '2025-05-29 14:23:32', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-05-31 15:57:52', 'yang menghilangkan kunci pihak marketing', '', NULL, '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250529003', 4, 32, 'Trusmiland Cikoneng Majalengka', 'C32', 'CS2308151322', 'LIA FAHIRA LISNAENI', 'Infrastruktur', 'Dear rumah ningrat, mohon lebih maksimal dalam membangun infrastruktur perumahan. Banyak sekali lahan kosong yang seharusnya menjadi lahan terbuka hijau ditanami rumput, pohon, dll malah terbengkalai, menjadikan lingkungan tampak kumuh dan tidak rapih.  Mohon lebih maksimal karna perumahan yang bagus juga lingkungan yang bagus. Saya lampirkan video sebagai referensi rumah ningrat dalam menata lingkungan. Foto menyusul saya kumpulkan dulu foto fotonya', 6, 100, 3, 3, '2025-05-31 16:11:54', '2025-06-14 23:00:00', '2025-06-26', '2025-06-26 17:42:19', NULL, NULL, '2025-05-29 19:16:22', 5428, NULL, NULL, NULL, '2025-05-29 19:16:22', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-05-31 16:14:48', 'mohon di landclearing agar rapih', '8066', 'sudah mulai berprogress', 'https://www.instagram.com/reel/DEzhkHNzdjA/?igsh=NmJ6ZGlmcnc2aGVj', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250530001', 15, 19, 'RN Kayangan', 'I43', 'CS2502260090', 'Ruwendi', 'Sales/Mkt (Area Cirebon)', 'Saya tunggu secepatnya itikad baik dr sales br nama budi. Saya yg boking saya yg membrikan dp dan uang wayang tp setelah saya mundur setelah surat sp3 keluar dia budi mengganti org lain untuk melanjutkan kredit ini. Ruwendi adalah wayang saya. Saya hanya ingin uang saya kembali ', 6, 100, 2, 4, '2025-06-02 17:02:29', '2025-06-04 23:00:00', '2025-06-04', '2025-06-04 21:35:58', NULL, NULL, '2025-05-30 10:36:14', 5428, NULL, NULL, NULL, '2025-05-30 10:36:14', 0, '', NULL, 340, 'Muhamad Irfannudin ', '2025-06-02 17:04:47', 'hubungi dan temui konsumen dangan sales bernama budi untuk mengclearkan masalah ini', '2625,341', 'Sudah ketemu dengan konsumen\nAda mis komunikasi dengan markting dan konsumen', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250530002', 4, 20, 'Trusmiland 5', 'J48', 'CS2412260011', 'Yoga Pratama', 'Infrastruktur', 'Kondisi jalan depan rumah saya rusak dan belum diperbaiki hingga saat ini, serta ditambah terdapat pembuangan tanah yang dilakukan tetangga di area depan rumah saya membuat akses jalan menjadi susah dilewati', 6, 100, 3, 3, '2025-05-31 16:00:21', '2025-06-18 23:00:00', '2025-06-18', '2025-06-17 15:56:16', NULL, NULL, '2025-05-30 16:11:50', 5428, NULL, NULL, NULL, '2025-05-30 16:11:50', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-05-31 16:01:07', 'mohon diperbaiki', '2296', 'telah diperbaiki', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250602001', 10, 27, 'Trusmiland Diamond', 'C05', 'CS2506010526', 'EMA KHUZAEMAH', 'Perbaikan rumah contoh diamond klayan (sudah di booking cash)', '<p>Mohon di bantu perbaikan rumah contoh diamond klyan sudah laku terjual dan konsumen ingin perbaikan lbih cepat, berikut list yg perlu di perbaiki:</p><p>1.atap bocor area ruang tamu dan kamar 1 dekat carport&nbsp;</p><p>2.dak atas miring</p><p>3.knopi di bersihkan dan di cat ulang</p><p>4.handle pintu berkarat</p><p>5.jendela kamar 1 susah di buka tutup seret</p><p>6.kramik ada bercak yg tidak bisa di bersihkan</p><p>7.tembok sekat ruang tamu dan area belakang ada yg retak</p><p>8.plafond kamar 2 retak</p><p>9.aksesoris kamar mandi kran dan sower tidak ada</p><p>10.pdam ga ngalir ke area dalam rumah</p><p>11.instalasi listrik ada yg tidak ada arus listrik</p><p>13.carport di perbaiki dan cat ulang</p><p>14.cat ulang all ruangan</p><p>12.tulisan marketing office di lepas</p><p>13.neonbox rumah contoh di lepas</p>', 6, 100, 2, 4, '2025-06-03 13:20:17', '2025-07-16 23:00:00', '2025-07-16', '2025-07-17 19:35:56', NULL, NULL, '2025-06-02 14:29:32', 3070, NULL, NULL, NULL, '2025-06-02 14:29:32', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-03 13:21:32', 'mohon diperbaiki', '168,2842', 'pekerjaan sudah di lakukan sesuai note ', '', NULL, 2, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
