('C250609001', 15, 19, 'RN Kayangan', 'I43', 'CS2502260090', 'Ruwendi', 'Sales/Mkt (Area Cirebon)', 'Saya sudh menunggu begitu lama ???? dr tgl 6 mundur tgl 7 sekarang sudah tgl 9. Apa kah perumahan ningrat yg terkenal pelayan an bgth bagus sperti ini.  Saya cuma mau uang saya kembali dan kasih sangsi untuk sales brnama budi abdul kholik ???? pemalsuan dokumen itu ada hukum nya ????', 6, 100, 2, 4, '2025-06-11 17:15:01', '2025-06-13 23:00:00', '2025-06-13', '2025-06-13 10:22:52', NULL, NULL, '2025-06-09 09:28:54', 5428, NULL, NULL, NULL, '2025-06-09 09:28:54', 0, '', NULL, 340, 'Muhamad Irfannudin ', '2025-06-11 17:16:50', 'Mohon untuk diberikan keputusan untuk sales ybs agar kasus seperti ini bisa jadi efek jera untuk sales lain dan tidak terulang di kemudian hari. Rekomendasi sales dikenai SP 3', '9082,9400', 'Sudah terverifikasi case sudah clear, sales tersebut sudah  mengganti dana ke konsumen tersebut.\nrekomendasi SP2, Masih dikasih kesempatan untuk bekerja di RSP dengan komitmen tidak akan mengulangi case tersebut dikemudian hari\n', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250609002', 10, 32, 'Trusmiland Cikoneng Majalengka', 'A25', 'CS2411070022', 'Reva Dwi Utama', 'Aftersales', 'Bagian Dalam rumah terdapat kebocoran dan dinding pada retak', 5, 0, 0, 0, '2025-06-09 16:25:52', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-06-09 11:07:08', 5428, NULL, NULL, NULL, '2025-06-09 11:07:08', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-09 16:27:21', 'sedang dikerjakan , doubel input di web aftersales juga (konsumen sudah input di web aftersales)', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250611001', 10, 17, 'Trusmiland Pamengkang', 'L02', NULL, 'Rumah Contoh', 'Perbaikan Rumcon untuk Open House', '<p>1. Gerbang di Cat Ulang</p><p>2. Taman di rapihkan</p><p>3. Topi-an di cat ulang</p><p>4. Tembok Carport di cat ulang</p><p>5. WC dibersihkan</p><p>6. Tembok ruang tamu - belakang pintu retak</p><p>7. Tembok kamar depan retak</p><p>8. Pojokan tembok kamar depan dan plafon di cat ulang</p><p>9. Plafon kamar depan (posisi di belakang pintu) di perbaiki hampir jebol</p><p>10. Lantai seluruh unit dibersihkan</p><p>11. Tembok kamar belakang retak parah</p><p>12. Plafon kamar belakang kena bocoran</p><p>13. Tembok dapur retak parah</p><p>14. Tembok taman retak</p>', 6, 100, 2, 4, '2025-06-12 09:27:10', '2025-06-26 23:00:00', '2025-06-26', '2025-06-23 10:58:37', NULL, NULL, '2025-06-11 15:48:18', 3306, NULL, NULL, NULL, '2025-06-11 15:48:18', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-12 09:31:07', 'mohon diperbaiki', '2842', 'Perapihan dinding dan Plafond\r\nperapihan carport \r\nPelapisan no drop \r\nperapihan unit lainnya', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250611002', 10, 17, 'Trusmiland Pamengkang', 'L03', NULL, 'Rumah Contoh', 'Perbaikan Rumah Contoh untuk Open House', '<p>1. Decker carport berlubang</p><p>2. Tanaman dirapihkan</p><p>3. Topian di cat ulang</p><p>4. Retak tipis di WC</p><p>5. Plafon dapur dirapihkan kena bocor</p><p>6. Topian kamar belakang (posisi di dapur) di cat ulang</p><p>7. Selokan dibersihkan</p>', 6, 100, 2, 4, '2025-06-12 09:26:00', '2025-06-26 23:00:00', '2025-06-26', '2025-06-23 10:54:39', NULL, NULL, '2025-06-11 15:52:33', 3306, NULL, NULL, NULL, '2025-06-11 15:52:33', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-12 09:26:57', 'mohon diperbaiki', '2842,8066', 'pengecatan ulang \r\npelapisan no drop\r\nperbaikan Carport \r\nperapihan taman \r\nperapihan dinding dan plafond ', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250611003', 17, 53, 'Indramayu 2 (Margadadi)', 'F83', NULL, 'Darsana', 'minta pengembalian dana', 'saya ingin menyampaikan keluhan, sbelum nya saya minat rumah ningrat dan sudah mengumpulkan semua berkas dan persyaratan kepada sales sampe tahap BI checking kata sales nya pun lolos, lalu saya di mintai DP dan sudah saya DP full tpi ternyata kemudian tiba\" sales bilang saya tidak lolos di bank, jdi saya ingin DP saya kembali sampe skrng sales nya tidak bisa dihubungi', 6, 100, 1, 3, '2025-06-13 17:53:08', '2025-06-20 23:00:00', '2025-06-20', '2025-06-24 22:51:38', NULL, NULL, '2025-06-11 16:19:37', 9189, NULL, NULL, NULL, '2025-06-11 16:19:37', 0, '', NULL, 476, 'Angga Prabowo ', '2025-06-13 18:05:14', 'Tolong kroscek terlebih dahulu, berkasnya', '3013', 'DONE', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250611004', 3, 35, 'RN Indramayu', 'E02', 'CS2306020011', 'Rachmat rio feranto', 'Progres Bangunan', 'Rumah saya belum bener sudah hampir 2 tahun cicilan berjalan, ktanya developer terbaik tapi komplain gapernah dikerjain, gak ada kabar jelas, waktu saat proses pengajuan KPR di buru-buru, sedangkan pas komplain lambat sekali, bahkan tidak dilakukan proses komplainnya! parah banget rumah ningrat\r\n\r\nsaya mau komplain lagi!\r\n1. Atap rumah/plafon jebol\r\n2. Pintu Depan tidak bisa dikunci\r\n3. Tembok di kusen pintu depan depan sudah pada ambrol/runtuh\r\n4. Tembok-tembok sekitar kusen yang lainnya juga sudah runtuh\r\n5. Pintu kamar depan tidak bisa dikunci\r\n6. Tembok Kotor\r\n7. Jendela Kamar melongo / tidak pas\r\n\r\ntolong kerjakan secepatnya saya mau tempatin rumah ini!', 6, 100, 2, 4, '2025-06-13 10:17:33', '2025-06-30 23:00:00', '2025-06-30', '2025-06-26 15:45:55', NULL, NULL, '2025-06-11 17:12:59', 5428, NULL, NULL, NULL, '2025-06-11 17:12:59', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-13 10:20:37', 'mohon diperbaiki', '2842', 'sudah selesai tanggal 26 juni 2025', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
