('C250617001', 13, 90, 'RN Sampora', 'K16', NULL, 'novita priyanti utami', 'minta uang nya dikemablikan', 'minta uang saya dikembalikan, dan ingin bertemu dengan owner pa ibnu', 6, 100, 1, 4, '2025-06-17 11:09:25', '2025-06-17 23:00:00', '2025-06-17', '2025-06-17 18:23:35', NULL, NULL, '2025-06-17 11:08:08', 9189, NULL, NULL, NULL, '2025-06-17 11:08:08', 0, '', NULL, 2397, 'Firman Tigoastomo Basuki ', '2025-06-17 11:10:35', 'Lakukan pemeriksaan Konsumen tersebut, eskalasi ke Audit untuk penanganan lebih lanjut', '97', 'konsumen melakukan pengambilan 2 unit :\n1. case unit sudah clear uang wayang sudah di kembalikan\n2, untuk unit kedua, uang wayang dan bendera belum kembali dikarenakan sales bersangkutan sudah tidak lagi bekerja trusmiland, sehingga komitmen dari spv sale', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250618001', 15, 40, 'Arjawinangun ByPass', 'E67', 'CS2501270200', ' LIS ANISA FAZRIN', 'Pengembalian Konsumen tidak sesuai dengan ketentuan ', 'Ceritanya kk saya dia ambil perumahan di awn trusmiland, sudah dp sekitar 6jt klo ngga salah. Tbtb di cancel sama yg bersangkutan dengan alasan yg menurut kami bkn sepenuhny salah kami. Kemudian ada info dana akan di refund, dan ada sekian persen dana hangus, masih ada sekitar 2jt dana blm dikembalikan sdh 9bulan lebih. Info dari mba nandanya finance salah input, makannya baru di tf 3,2 jt.. yg 2,8 menyusul katanya tapi sampe sekarang blm juga di tf lagi. Ini kan marketing resmi dari rumah ningkat bahkan dia ada di office, kecuali dia external yg memang sengaja ambil keuntungan diluar dari tanggung jwb kantor/perusahaan. Bukan cust yg nggak jeli karna tf ke rek cust, tapi karna udah ada trust kalo marketing ini resmi karyawan trusmiland, ketika marketing minta di tf ke no rek bersangkutan ya cust percaya dong? Kembali lagi “marketing ini resmi karyawan trusmiland kan” jd harap ditangani hingga clear. Kak mohon maaf bgt ini, sy udah mau setahun ngurusin ini ngga ada solusi. Udah jelas yg di tf 6jt booking&nbsp;', 6, 100, 2, 4, '2025-06-18 10:51:19', '2025-06-20 23:00:00', '2025-06-20', '2025-06-25 09:42:41', NULL, NULL, '2025-06-18 09:38:36', 5655, NULL, NULL, NULL, '2025-06-18 09:38:36', 0, '', NULL, 340, 'Muhamad Irfannudin ', '2025-06-18 10:56:49', 'coba langsung kontak dan temuin konsumennya ', '847', 'Uang konsumen senilai 2 jt sudah dibayarkan oleh Nanda', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250618002', 10, 26, 'Trusmiland ITB Komersil', 'C03', 'CS2410130013', 'Pusparida', 'List kekurangan ITB komersil blok C03,setelah ST Kunci rumah', 'Mohon di bantu bapak/ibu departemen terkait,berikut list kekurangan ITB Komersil Blok C03<br>1.sanyo belum terpasang(tidak bisa cek air)<br>2.intslasi listrik tidak ada arus listrik udah di coba pasang lampu dan tespen stiap colokan ga ada arus listrik<br>3.sikring kurang menempel<br>Mohon di bantu cek dan di lengkapi,rencana minggu depan di tempati', 6, 100, 2, 3, '2025-06-24 15:25:57', '2025-06-26 23:00:00', '2025-06-26', '2025-06-25 10:08:11', NULL, NULL, '2025-06-18 10:29:50', 3070, NULL, NULL, NULL, '2025-06-18 10:29:50', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-06-18 15:26:50', 'Mohon diperbaiki', '2842', 'sudah selesai', '', NULL, 1, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
