('C250711003', 8, 32, 'Trusmiland Cikoneng Majalengka', 'B18', 'CS2409250012', 'HERI WIRANTO', 'Permisi saya mau komplain terkait listrik, waktu itu saya dapat info pemasang listrik sudah selesai tapi belum sempat saya cek karna belum akad dan setelah akad juga saya tidak bisa langsung cek karna belum serah terima kunci rumah. Sekarang saya sudah se', 'Permisi saya mau komplain terkait listrik, waktu itu saya dapat info pemasang listrik sudah selesai tapi belum sempat saya cek karna belum akad dan setelah akad juga saya tidak bisa langsung cek karna belum serah terima kunci rumah. Sekarang saya sudah serah terima kunci rumah pas cek listrik tidak menyala.', 6, 100, 3, 3, '2025-07-14 17:28:09', '2025-07-21 23:00:00', '2025-07-21', '2025-07-18 11:05:41', NULL, NULL, '2025-07-11 14:51:16', 9189, NULL, NULL, NULL, '2025-07-11 14:51:16', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-07-14 17:28:58', 'mohon di perbaiki', '8889', 'sudah selesai', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250711004', 13, 29, 'Trusmiland Dawuan', 'C09', 'CS2501200006', 'Anwar sunandi', 'Buspro (Berkas)', 'Haloo kapan akad nih trusmilend.\r\nKan rumah sudah jadi bank mandiri sudah siap hayu kapan akadnya. ', 6, 100, 2, 4, '2025-07-14 14:50:59', '2025-07-15 23:00:00', '2025-07-15', '2025-07-15 17:17:21', NULL, NULL, '2025-07-11 15:09:40', 5428, NULL, NULL, NULL, '2025-07-11 15:09:40', 0, '', NULL, 2397, 'Firman Tigoastomo Basuki ', '2025-07-14 14:51:57', 'mohon dikoordinasikan dengan KOnsumen terkait, untuk penjadwalan Akad nya', '1898', 'untuk proses administrasi sudah selesai, namun masih menunggu proses antar bank untuk pengakadan, dan sedang kami kejar untuk percepatan prosesnya', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250711005', 12, 29, 'Trusmiland Dawuan', 'A05', 'CS2405020072', 'Maharani Donny Putri', 'Estate', 'Kami selaku warga Perumahan Rumah Ningrat (Trusmiland Dawuan) ingin menyampaikan keluhan terkait kondisi sungai yang berada tepat di depan area perumahan kami. Saat ini, sungai tersebut tidak memiliki tanggul atau pembatas yang memadai, sehingga sangat rawan terjadi luapan air terutama saat musim hujan. terbukti saat tidak hujan sungai dapat kiriman air dan rembes ke area depan rumah kami.\r\n\r\nKetiadaan pembatas sungai, tanah yang bergerak, tandus, dan terkikis membuat air mudah meluap ke area perumahan ketika debit air meningkat. Hal ini sangat meresahkan dan membahayakan keselamatan serta kenyamanan warga, terutama anak-anak dan lansia. Selain itu, kondisi ini juga dapat menyebabkan banjir yang berpotensi merusak fasilitas umum dan rumah warga.\r\n\r\nKami sangat berharap pihak berwenang dapat segera melakukan tindakan antisipatif, seperti pembangunan tanggul, pembatas beton, atau sistem drainase tambahan, guna mencegah potensi bencana yang lebih besar di kemudian hari.\r\n\r\nterkait keluhan sudah pernah kami sampaikan saat sungai dapat kiriman air langsung kami foto dan video kirim ke instagram rumah ningrat namun tidak ada respon yang signifikan dan tidak ada tindak lanjut dari respon yang kami kirim, begitupun kami sampaikan langsung ke marketing perumahan dan BM saat ada di rumah marketing rumah ningrat trusmiland Dawuan.\r\n\r\nMohon keluhan ini dapat segera ditindaklanjuti demi keselamatan dan kenyamanan bersama.\r\n\r\n', 5, 0, 0, 0, '2025-07-14 16:47:52', '0000-00-00 00:00:00', '2025-07-15', NULL, NULL, NULL, '2025-07-11 19:49:51', 5428, NULL, NULL, NULL, '2025-07-11 19:49:51', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-07-14 16:52:35', 'sedang di cek terlebih dahulu', '', NULL, 'https://drive.google.com/drive/folders/1SZMt5PJ4Zjtt-otfk2qKTHKAjXpimhlP?usp=sharing', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
