('C250716005', 8, 15, 'Trusmiland Tengah Tani', 'A17', 'CS221213145', 'Riki kurniawan', 'KWH Listrik', 'Tengtang token listrik PJU.\r\nToken listrik PJU mau habis, yang di takutkan Lampu PJU mati jalan perumahan gelap sehingga nanti ada ke tidak nyamanan warga disini, mohon untuk di bantu kepada pihak deplover supaya warga di perumahan trusmiland tengah tani tahap 1 lovina village 4 nyaman. salam saya terima kasih ', 5, 0, 0, 0, '2025-07-17 16:10:05', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-07-16 09:01:56', 5428, NULL, NULL, NULL, '2025-07-16 09:01:56', 0, '', NULL, 1186, 'Idham Nurhakim Dipura', '2025-07-17 16:10:19', 'dari developer tidak mengisi lagi karena pengelolaan sudah pada paguyuban', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
