('C250831003', 3, 70, 'RN Jayasampurna', 'D06', 'CS2501180137', 'Boni latif', 'Progres Bangunan', 'Perkenalkan saya boni.saya booking di RN di februari 2025 dengan dp 9,5 juta. saat itu saya mendapat promo dinding dapur 1,5 m, pagar, dan kompor. Saat ini rumah sudah mau selesai sedangkan dapur 1,5 m yang dijanjikan belum juga di bangun. Saya sudah di minta untuk akad, sedang rumah yang dijanjikan kepada saya belum selesai seperti perjanjian atau seperti promo yang saya dapat(dinding dapur 1.5 m belum dibangun). Mohon kiranya untuk di tindak lanjuti dan segera di bangun. Agar saya dapat melanjutkan untuk akad. Terima kasih \r\n', 5, 0, 0, 0, '2025-09-01 15:50:16', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-08-31 20:52:20', 5428, NULL, NULL, NULL, '2025-08-31 20:52:20', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-01 15:50:29', 'tidak ada spek dinding dapur 1,5 m di rn jayasampurna', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-02 15:03:38', 9189),
('C250831004', 3, 70, 'RN Jayasampurna', 'D22', 'CS2501150126', 'Dandi Muhakim Kihampelas', 'Progres Bangunan', 'Perkenalkan saya Dandi Muhakim Kihampelas telah booking perumahan di Rumah Ningrat Jayasampurna di bulan Januari dengan DP 9,500,000  saya dapat promo dinding dapur 1,5 meter, pagar, kompor listrik dan mesin air.\r\nDan saat ini pengerjaan rumah saya sudah hampir 100% selesai namun promo dinding dapur yang di janjikan ketika boking belum juga di bangun.\r\nSaya di tawari akad, sedangkan rumah belum finish 100%, rumah belum layak huni, dan dinding dapur yang di janjikan kepada saya belum di bangun.\r\nMohon segera di tindak lanjuti dan di bangun dinding dapur yang telah di janjikan, agar saya bisa melaksanakan akad.\r\nTerimakasih.', 5, 0, 0, 0, '2025-09-01 15:45:38', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-08-31 21:38:54', 5428, NULL, NULL, NULL, '2025-08-31 21:38:54', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-01 15:49:33', 'tidak ada spek dinding dapur 1,5 m di rn jayasampurna', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C250901001', 11, 70, 'RN Jayasampurna', 'G07', 'CS2502220085', 'risqi Supriyanto / Nova Prasticha', 'Finance', 'kalau ada tambahan biaya usahakan konfirmasi dari jauh-jauh hari ke konsumen jangan tiba-tiba dinaiki aja harganya, saya selaku konsumen dari blok G7 di jayasampurna ga suka cara kerja kalian ', 6, 100, 4, 2, '2025-09-03 19:35:17', '2025-09-04 23:00:00', '2025-09-04', '2025-09-04 15:12:50', NULL, NULL, '2025-09-01 11:42:57', 5428, NULL, NULL, NULL, '2025-09-01 11:42:57', 0, '', NULL, 76, 'Yeyen Nuryenti', '2025-09-03 19:42:54', 'Mohon dikomunikasikan kepada tim marketing terkait PPN atas kelebihan tanah dan pastikan tim marketing sudah menyampaikan ke konsumen sebelum revisi inputan sistem.', '365', 'Setelah di lakukan pengecekan, konsumen melakukan pembelian rumah di proyek RN Jayasampurna Blok G07\r\njika ditelusuri kemungkinan tambahan 2juta itu karena ada biaya PPN KLT yang belum masuk keperhitungan awal, Rincian terlampir', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-02 08:36:41', 9189),
('C250901002', 3, 68, 'RN Kendal 2', 'E01', 'CS2506080431', 'Harini', 'Progres Bangunan', 'Saya sudah akad kok rumah belum jadi\r\nIni masudnya gimana?\r\nMasak sudah lama masih sperti ini aja bangunnya', 6, 100, 3, 4, '2025-09-02 16:33:32', '2025-10-11 23:00:00', '2025-10-11', '2025-10-06 16:10:42', NULL, NULL, '2025-09-01 11:51:15', 5428, NULL, NULL, NULL, '2025-09-01 11:51:15', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-02 16:36:02', 'mohon dilanjutkan', '2296', 'Unit sudah 100%', '', 1, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-02 08:37:25', 9189),
('C250901003', 10, 20, 'Trusmiland 5', 'H14', 'CS2505150241', 'Fahrudho Hamdan Aditri Hutomo', 'Aftersales', 'Meteran pdam patah', 5, 0, 3, 0, '2025-09-02 14:44:32', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-09-01 19:36:48', 5428, NULL, NULL, NULL, '2025-09-01 19:36:48', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-02 14:45:31', 'Terima kasih atas pertanyaan dan perhatian Bapak/Ibu. Untuk informasi lebih detail terkait hal tersebut, kami sarankan Bapak/Ibu dapat langsung menghubungi pihak PDAM untuk perbaikannya. Semoga informasi ini membantu, dan kami siap mendukung apabila ada h', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-02 08:38:19', 9189),
('C250901004', 3, 70, 'RN Jayasampurna', 'F03', 'CS2502200177', 'Uhkti Atun Sholiha', 'Progres Bangunan', 'Pada awal penawaran unit, marketing menjelaskan kepada saya bahwa rumah ningrat akan dibangun dengan fasilitas free pagar, kompor listrik, shower, pompa air dan juga terdapat tembok dapur 1,5 meter.\r\n\r\nTetapi sampai saat akad/sampai saat ini dari progress pembangunan tidak ada tembok dapur 1,5meter seperti yang dijanjikan, selain itu untuk kompor listrik,shower, dan juga pompa air saya belum mendapat kabar apakah akan tetap ada atau tidak. \r\n\r\nSelain itu saya sudah melihat progress pembangunan rumah saya di blok F03, saat ini sudah tahap finishing tetapi kusen jendela kamar saya miring dan sangat terlihat kemiringannya, serta ada 2 pintu yang seret .\r\n\r\nMohon difollow up, \r\nTerimakasih', 5, 0, 3, 0, '2025-09-02 11:22:56', '2023-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-09-01 21:56:12', 5428, NULL, NULL, NULL, '2025-09-01 21:56:12', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-02 11:23:33', 'tidak ada spek dinding dapur 1,5 m di RN jayasampurna', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-02 08:39:04', 9189),
