('C250903009', 10, 49, 'RN Getasan', 'B47', 'CS2406230527', 'Teguh sulaeman', 'Aftersales', 'Sebelumnya sudah diperbaiki namun hanya di cat saja dan hasilnya belum maksimal, melendung-melendung temboknya', 6, 100, 3, 4, '2025-09-04 15:03:36', '2025-09-30 23:00:00', '2025-09-30', '2025-09-27 08:22:13', NULL, NULL, '2025-09-03 18:42:14', 5428, NULL, NULL, NULL, '2025-09-03 18:42:14', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-04 15:05:46', 'mohon di perbaiki', '2842', 'Status perbaikan \"Reject\" karena rumah belum dihuni dan komplain bukan kerusakan struktural', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-04 10:11:00', 9189),
('C250904001', 4, 17, 'Trusmiland Pamengkang', 'G70', 'CS2311050089', 'ALIVIA NABILA SEPTIANI', 'Infrastruktur', 'Lantainya naik semua sehingga lama kelamaan jadi pecah dan semakin tinggi. Awal diperbaiki saat afterseles sudah baik, namun hanya bertahan 3 bulan sajaa. Saya ingin komplain lagi namun perbaikan hanya sekali, dan komplain aftersales hanya berlaku 1 bulan setelah perbaikan sedangkan lantai rumah kembali naik sekitar 3/4 bulan setelah after sales itupun belum kami tempati. Hingga akhirnya kami menempati rumah dengan keadaan keramik yang naik, pecah dan terus semakin naik. Sangat disayangkan \"rumah siap huni\" tetapi awal ditinggalkan pun sudah dalam kondisi tidak baik. Barangkali ada solusi baik dari pihak developer untuk kualitas bangunannya bisa diperbaiki. Foto yang saya sematkan hanya beberapa, sebenarnya ada banyak lantai yang mengangkat dan lantai tidak rata (menggunung) semakin hari semakin tinggi. Terimakasih.', 5, 0, 0, 0, '2025-09-06 22:31:50', '0000-00-00 00:00:00', '2025-09-27', NULL, NULL, NULL, '2025-09-04 02:29:48', 5428, NULL, NULL, NULL, '2025-09-04 02:29:48', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-06 22:33:03', 'mohn maaf karena sudah dilakukan aftersales dan sudah lebih dari setahun dari tanggal serah terima kunci', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-04 10:10:07', 9189),
('C250904002', 3, 90, 'RN Sampora', 'J64', 'CS2505060304', 'Muhammad Fikri Addillah', 'PENAMBAHAN DAPUR', 'Konsumen sudah membayar tambahan promo dapur senilai Rp 5.000.000 (Lima Juta Rupiah) tetapi belum kunjung di bangun sampai sudah di lakukannya akad kredit. Memohon agar dapat memberikan deadline waktu pengerjaan dan selesai pengerjaan karena akan memberikan feedback ke konsumennya', 6, 100, 3, 3, '2025-09-12 22:28:59', '2025-10-04 23:00:00', '2025-09-30', '2025-09-30 19:52:28', NULL, NULL, '2025-09-04 09:29:48', 2896, NULL, NULL, NULL, '2025-09-04 09:29:48', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-06 22:29:41', 'mohon di bangun', '1637', 'pekerjaan sedang on progres oleh vendor samudi, sistem tidak bisa reschedule', '', NULL, 2, 0, 0, NULL, NULL, NULL, NULL, NULL, '2025-11-18 13:36:01', 10118),
