('C250907001', 10, 32, 'Trusmiland Cikoneng Majalengka', 'E32', 'CS2502160109', 'Lala Laelatul Musyarofah', 'Aftersales', 'Tidak ada saluran pembuangan air kotor ke depan seperti rumah yg lainnya. Mohon dibantu kroscek dan diperbaiki segera ya Min! Karena lumayan pr baru ke cek, antara pipanya cuman sampe dibawah teras, atau malah ketutup sama pondasian pager depan, jadi ga nyampe keluar pipa besar air kotornya. Video sudah dibantu up oleh marketing ke project dan afs', 6, 100, 3, 4, '2025-09-08 15:32:44', '2025-09-30 15:32:58', '2025-09-30', '2025-09-25 15:12:21', NULL, NULL, '2025-09-07 08:41:37', 5428, NULL, NULL, NULL, '2025-09-07 08:41:37', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-08 15:33:09', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-08 08:42:07', 9189),
('C250907002', 10, 32, 'Trusmiland Cikoneng Majalengka', 'E30', 'CS2411120065', 'Ruli Panji Permana', 'Aftersales', 'Plafond ambrol, posisi ruang tengah deket tembok kamar mandi. Kondisi bekas hujan. Kemungkinan akan mengalami hal yg sama di beberapa titik kalo tidak segera di perbaiki. Tolong dibantu oleh tim dri developer untuk segera melakukan perbaikan besok senin. Terimakasih sebelumnya.', 6, 100, 3, 4, '2025-09-08 15:32:07', '2025-09-30 23:00:00', '2025-09-30', '2025-09-25 15:00:16', NULL, NULL, '2025-09-07 10:21:01', 5428, NULL, NULL, NULL, '2025-09-07 10:21:01', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-08 15:32:34', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-08 08:41:36', 9189);
