('C250910001', 18, 0, '', '', '', '@habratnsundaz', 'Infrastruktur', '@endarch dimana lokasinya  percuma klo kga di kasih btsu  lokasi', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-10 21:15:51', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Cek lokasi yang dimaksud oleh konsumen dan pastikan lokasi tersebut didukung dengan BTSU yang memadai. Jika belum ada, koordinasikan dengan tim infrastruktur untuk pemasangan BTSU di lokasi tersebut.', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/p/DMMqanBMFdz/', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250911001', 10, 32, 'Trusmiland Cikoneng Majalengka', 'G33', 'CS2506250134', 'Bejo Alexander Limbong', 'Aftersales', 'Saluran pembuangan kamar mandi tidak ada dan tidak tersambung ke pembuangan ke depan\r\n\r\nPiting lampu kamar mandi tidak nyala\r\n\r\nPagar belum ada', 6, 100, 3, 3, '2025-09-11 14:20:03', '2025-10-04 23:00:00', '2025-10-04', '2025-09-25 14:56:46', NULL, NULL, '2025-09-11 11:09:26', 5428, NULL, NULL, NULL, '2025-09-11 11:09:26', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-11 14:20:36', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-11 11:32:57', 9189),
