('C250912001', 18, 0, '', '', '', '@fahmii_ikhwanss', 'Infrastruktur', 'Tetep aja itu ang ambrol gada kekuatan gotnya', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-12 06:04:01', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan pengecekan kondisi got yang ambrol dan perkuat struktur got dengan bahan yang sesuai standar. Koordinasikan dengan tim infrastruktur untuk perbaikan segera agar jangan sampai terjadi kerusakan lebih lanjut.', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/reel/DNvNJleZBiM/', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250912002', 3, 70, 'RN Jayasampurna', 'G18', 'CS2412300085', 'Moh Syakur', 'Progres Bangunan', 'sukses selalu untuk RN\r\n\r\npada hari ini tanggal 12/9/25 saya mengecek langsung di area rmah ningrat yang saya ambil di lokasi jayasampurna Blpck G1.8 , hasil pengamatan sbb di bawah ini\r\n1. kerapihan bangunan terkesan blepotan bila dilihat pembanding dengan bangunan yang di D dan C , tolong sebelum penyerahan pihak QC RN menindak lanjuti masalah ini.\r\n\r\n2. letak G1.8 seharusnya bedampingan dngan G19 tetapi secara dilapangan G1.9 blm terbangun, nah yang jd pertanyaan adalah , apakah sisi tembok samping akan dibiar kan tanpa plester , JIKA iya, tolong terangkan ARTI qualitas yg selalu didengungkan oleh pihak RN\r\n\r\n3. tolong untuk hargai waktu kami juga sebagai cust , karna kami pun punya plan waktu, punya mimpi dan harapan, yang semua itu sudah kita percayakan kepada RN', 6, 100, 3, 4, '2025-09-12 14:48:15', '2025-09-18 23:00:00', '2025-09-18', '2025-09-16 16:23:41', NULL, NULL, '2025-09-12 09:34:13', 5428, NULL, NULL, NULL, '2025-09-12 09:34:13', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-12 14:49:43', 'mohon diperbaiki', '8480', 'Sudah di plester', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-12 09:48:26', 9189),
