('C250927006', 1, 56, 'RN Majalengka 2', 'E12', 'CS2411100029', 'Linda Ananda H', 'Kunci Rumah', 'Saya melakukan Booking Perumahan Ningrat Majalengka 2 Sekitar bulan November 2024, Lalu saya melakukan akad rumah di Bank BTN pada tanggal 30 Mei 2025. Sampai dengan saat ini terhitung dari setelah akad ± 4 bulan saya belum serah terima kunci (dari Developer) Mohon bantuannya untuk segera diproses terkait serah terima kunci rumah karena hingga saat saya belum bisa nempati rumah tsb padahal cicilan sudah mau masuk ke 4bln karena sesuai aturan yang saya tau untuk serah terima kunci max 2 Minggu setelah akad.', 6, 100, 3, 3, '2025-09-29 12:30:32', '2025-09-30 23:00:00', '2025-09-30', '2025-09-29 14:25:57', NULL, NULL, '2025-09-27 10:39:00', 5428, NULL, NULL, NULL, '2025-09-27 10:39:00', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-09-29 12:31:00', 'mohon diserahkan', '7972', 'Kunci sudah diserahkan ke marketing', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-27 20:21:48', 9189),
('C250928001', 18, 70, 'RN Jayasampurna', 'G10', '', '@_yusuft', 'Infrastruktur', 'Halo Rumah Ningrat,\n\nSaya Yusuf Tielman, konsumen unit rumah di Rumah Ningrat Jayasampurna Bekasi Blok G No. 10. Saya sudah melakukan akad kredit pada tanggal 12 September 2025 dan saat ini sudah mulai membayar cicilan KPR. Namun rumah saya hingga sekarang masih belum bisa dihuni karena belum selesai pembangunan (tembok dapur), septictank dan belum tersambung air.\n\nMohon diberikan kejelasan tertulis mengenai:\n\n1. Jadwal serah terima rumah.\n\n2. Kompensasi atas keterlambatan serah terima.\n\n    3. Kapan pembangunan akan selesai.\n\nJika dalam waktu dekat tidak ada kejelasan, saya akan menindaklanjuti hal ini ke pihak bank serta lembaga perlindungan konsumen.\n\nTerima kasih.\nYusuf Tielman\n085842139997', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-28 08:14:58', 9791, NULL, NULL, NULL, '2025-09-29 11:41:12', 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim proyek untuk mendapatkan jadwal pasti serah terima rumah, cek progres pembangunan tembok dapur, septictank dan sambungan air. Berikan jadwal resmi serah terima rumah kepada konsumen, hitung dan sampaikan kompensasi keterlam', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250929001', 18, 35, 'RN Indramayu', 'E45', '', '@ameliapnew_', 'Infrastruktur', 'Udh di follow up lagi blm. Makin rusak bangunanya', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-29 10:43:27', 9791, NULL, NULL, NULL, '2025-09-29 10:51:41', 7804, 'Nilsen Yogawan', 'Segera kirim tim teknis untuk melakukan inspeksi dan perbaikan kerusakan bangunan. Laporkan hasil tindakan kepada konsumen.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250929002', 18, 35, 'RN Indramayu', 'E45', '', '@ameliapnew_', 'Progres Bangunan', 'Kalau ga saya kasih tau pembeli rumah ningrat 2 biar pada mikir\" ngambil RN kok bsa bangunanya serusak ini pdhal baru 1 tahun', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-29 10:44:44', 9791, NULL, NULL, NULL, '2025-09-29 11:42:01', 7804, 'Nilsen Yogawan', 'Segera lakukan inspeksi kondisi bangunan di lokasi untuk mengidentifikasi kerusakan. Koordinasikan dengan tim maintenance untuk perbaikan dan laporkan hasilnya kepada konsumen.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250929003', 18, 35, 'RN Indramayu', 'E45', '', '@ameliapnew_', 'Progres Bangunan', 'Jelas banget itu pasir semua ya kak semenyaa kemana?', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-29 10:46:14', 9791, NULL, NULL, NULL, '2025-09-29 11:42:23', 7804, 'Nilsen Yogawan', 'Segera cek di lokasi proyek dan pastikan penggunaan semen sesuai standar. Informasikan ke konsumen tentang progres pekerjaan dan penggunaan material yang benar.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
