('C250930002', 8, 70, 'RN Jayasampurna', 'G13', 'CS2505020010', 'Surya Adji Pangestu', 'KWH Listrik', 'Blok G13 Rumah Ningrat Jayasampurna Bekasi, KWH Listrik nya belum menyala (layar kwh kosong dan lampu hijau tidak menyala) jadi belum bisa digunakan dan belum bisa memanfaatkan layanan after sales. \r\n\r\nMohon segera ditindak lanjuti dan segera dinyalakan KWH Listrik nya. Terimakasih', 6, 100, 2, 3, '2025-10-01 17:25:33', '2025-10-08 23:00:00', '2025-10-08', '2025-10-03 17:14:17', NULL, NULL, '2025-09-30 13:16:39', 5428, NULL, NULL, NULL, '2025-09-30 13:16:39', 0, '', NULL, 8066, 'Larson Mario', '2025-10-01 17:26:28', 'tolong dikoordinasi ke pln ', '369', 'done kelistrikan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-30 14:23:42', 9189),
('C250930003', 3, 17, 'Trusmiland Pamengkang', 'E61', 'CS2306140318', 'Suryani ', 'Progres Bangunan', 'Rmhnya tdk bisa di tmptin dri awal akad, sudah komplain bbrpa kli perbaikan  tp msh blm bnr, tembok retak platfrom jg retak, pondasi g bgs, tanah gerak, skrng rmh tmpk miring ngeri roboh, keramik ngangkt', 5, 0, 0, 0, '2025-10-01 16:45:25', '0000-00-00 00:00:00', '2025-10-31', NULL, NULL, NULL, '2025-09-30 14:33:15', 5428, NULL, NULL, NULL, '2025-09-30 14:33:15', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-01 16:46:15', 'umur banguna sudah lebih dari setahun dari serah terima kunci, dan sudah pernah diperbaiki oleh aftersales', '', NULL, 'https://drive.google.com/file/d/19diwvJnGegYw_PY4MEXuNu7B8g5JZZXa/view?usp=drivesdk', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-01 08:40:25', 9189),
('C250930004', 14, 70, 'RN Jayasampurna', 'G67', 'CS2412250263', 'Apriyanto Abdul Rahmat', 'Legal (Perizinan/Sertifikat)', 'Bagaimana kelanjutannya rumah yg sudah saya booking, apakah ada masalah dengan pemecahan sertifikat nya atau apa ya? Kenapa tidak ada info lanjutannya terkait rumah tersebut. Terima kasih ', 6, 100, 4, 4, '2025-10-01 17:10:30', '2025-10-02 23:00:00', '2025-10-02', '2025-10-02 15:12:19', NULL, NULL, '2025-09-30 15:53:49', 5428, NULL, NULL, NULL, '2025-09-30 15:53:49', 0, '', NULL, 360, 'Puji Lestari Maulidah ', '2025-10-01 17:13:41', 'Cek plan sertifikasi apakah masuk area jual/tidak ', '1287', 'untuk saat ini bidang yang dimaksudkan Blok G67 sedang proses di BPN Kab Bekasi', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-01 08:41:14', 9189),
('C250930005', 18, 90, 'RN Sampora', 'K01', '', '@npriyantiutami', 'After Sales', 'Sore bu saly, saya mau update terkait penyelesaian masalah fraud manager marketing ningrat sampora (Pak Diky) bulan juni lalu, yg sdh didelegasikan ke pak firman dg point aduan sbb \nI. Sampai dengan detik ini pak Firman masih belum bisa menyelesaikan masalah kami, sepertinya kalah power dengan pelaku Fraud pak diky Manager marketing sampora \n2. Fraud yang dilakukan Pak Diky yaitu menyalahgunakan jabatan dengan menjual wayang kepada kami, hal itu merepresentasikan bahwa developer ningrat secara sah berjualan Wayang ,karena YBS pada saat itu statusnya sebagai Manager yg mewakili management sehingga kami percaye utk transfer uang wayang ke YBS. \n3. Uang kami yg dibawa oleh Pak Diky sisa 6,5 juta lagi yang belum dikembalikan. Janji pak firman akan ditalangin dulu oleh ningrat dibulan agustus. Faktanya hanya omong kosong sampa sekarang kami terkesan diabaikan. \n4. Kami awal rencana ambil 2 unit rumah blok k01 dan k16,tapi dengan sistem managemen ningrat yg seperti ni kami kawatir dan ragu p', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-30 16:55:30', 9791, NULL, NULL, NULL, '2025-09-30 17:04:14', 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan Pak Firman untuk memastikan pengembalian uang 6,5 juta kepada konsumen secara jelas dan terjadwal. Laporkan masalah ini ke manajemen pusat untuk tindakan tegas terhadap fraud dan tingkatan pengawasan internal. Sampaikan update ', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250930006', 18, 90, 'RN Sampora', 'K01', '', '@npriyantiutami', 'Finance, After Sales', 'Sore bu saly, saya mau update terkait penyelesaian masalah fraud manager marketing ningrat sampora (Pak Diky) bulan juni lalu, yg sdh didelegasikan ke pak firman dg point aduan sbb \nI. Sampai dengan detik ini pak Firman masih belum bisa menyelesaikan masalah kami, sepertinya kalah power dengan pelaku Fraud pak diky Manager marketing sampora \n2. Fraud yang dilakukan Pak Diky yaitu menyalahgunakan jabatan dengan menjual wayang kepada kami, hal itu merepresentasikan bahwa developer ningrat secara sah berjualan Wayang ,karena YBS pada saat itu statusnya sebagai Manager yg mewakili management sehingga kami percaye utk transfer uang wayang ke YBS. \n3. Uang kami yg dibawa oleh Pak Diky sisa 6,5 juta lagi yang belum dikembalikan. Janji pak firman akan ditalangin dulu oleh ningrat dibulan agustus. Faktanya hanya omong kosong sampa sekarang kami terkesan diabaikan.', 2, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-30 16:56:04', 9791, NULL, NULL, NULL, '2025-09-30 17:04:39', 7804, 'Nilsen Yogawan', 'Audit ulang transaksi dan cek status pengembalian dana, koordinasi dengan bagian finance dan legal untuk menindaklanjuti kasus fraud. Pastikan komunikasi dengan konsumen diperbarui secara rutin tentang progres penyelesaian.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250930007', 18, 90, 'RN Sampora', 'K01', '', '@npriyantiutami', 'After Sales', '4. Kami awal rencana ambil 2 unit rumah blok k01 dan k16,tapi dengan sistem managemen ningrat yg seperti ni kami kawatir dan ragu perumahan tersebut akan terbengkalai, karena banyak konsumen yg di rugikan oleh oknum manager marketing yg berjualan wayang demi mengejat target. Jadi kami putuskan hanya ambil rumah 1 unit saja k01 yg SS akad minggu lalu. \n5. Uang DP kami di blok k16 yg sudah masuk sisa 4 juta kami sudah minta refund tapi masit belum ada kejelasan sampai detik ini. \n6. After sales yg terkesan buruk, setelah kami menyelesaikan akad k01 kemarin tiba-tiba pak firman slow respon sekali. \nDemikian aduan kekecewaan kami, mohon dibantu bu saly total uang yg belum kembalikan ke kami Rp 10.500.000. Kami benar2 tidak percaya dengan management ningrat . besar harapan kami ibu selly bisa menjadi pintu jalan keluar kami agar kami tidak dirugikan terus menerus terkait waktu dan materi.', 2, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-09-30 16:56:06', 9791, NULL, NULL, NULL, '2025-09-30 17:05:04', 7804, 'Nilsen Yogawan', 'Segera hubungi bagian keuangan untuk proses refund DP sebesar Rp 4.000.000 dan pastikan refund tersebut diproses dalam waktu maksimal 3 hari kerja. Koordinasikan dengan tim after sales untuk meningkatkan respons pak Firman dalam menanggapi pelanggan, khus', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C250930008', 10, 32, 'Trusmiland Cikoneng Majalengka', 'G33', 'CS2506250134', 'Bejo Alexander Limbong', 'Aftersales', 'Atap / plafon kamar belakang bocor\r\nPagar belum terpasang', 6, 100, 3, 4, '2025-10-01 16:46:25', '2025-10-30 23:00:00', '2025-10-30', '2025-10-04 07:39:17', NULL, NULL, '2025-09-30 19:52:59', 5428, NULL, NULL, NULL, '2025-09-30 19:52:59', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-01 16:47:47', 'mohon diperbaiki dan dipasang pagar', '2842,8079', 'done', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-01 08:41:59', 9189),
('C251001001', 13, 90, 'RN Sampora', 'K01', 'CS2508140167', 'Dede Mahpudin', 'Buspro (Berkas)', 'Sore bu selly, saya mau update terkait penyelesaian masalah fraud manager marketing ningrat sampora (Pak Diky) bulan juni lalu, yg sdh didelegasikan ke pak firman dg point aduan sbb:\r\n\r\n1.	Sampai dengan detik ini pak Firman masih belum bisa menyelesaikan masalah kami, sepertinya kalah power dengan pelaku Fraud pak diky Manager marketing sampora.\r\n\r\n2.          Fraud yang dilakukan Pak Diky yaitu menyalahgunakan jabatan dengan menjual wayang kepada kami, hal itu merepresentasikan bahwa developer ningrat secara sah berjualan Wayang ,karena YBS pada saat itu statusnya sebagai Manager yg mewakili management sehingga kami percaya utk transfer uang wayang ke YBS.\r\n\r\n3.	Uang kami yg dibawa oleh Pak Diky sisa 6,5 juta lagi yang belum dikembalikan. Janji pak firman akan ditalangin dulu oleh ningrat dibulan agustus. Faktanya hanya omong kosong sampai sekarang kami terkesan diabaikan.\r\n\r\n4.	Kami awal rencana ambil 2 unit rumah blok k01 dan k16 ,tapi dengan sistem management ningrat yg seperti ini kami kawatir dan ragu perumahan tersebut akan terbengkalai, karena banyak konsumen yg di rugikan oleh oknum manager marketing yg berjualan wayang demi mengejar target. Jadi kami putuskan hanya ambil rumah 1 unit saja k01 yg sdh akad minggu lalu.\r\n\r\n5.	Uang DP kami di blok k16 yg sudah masuk sisa 4 juta  kami sudah minta refund tapi masih belum ada kejelasan sampai detik ini.\r\n\r\n6.	After sales yg terkesan buruk, setelah kami menyelesaikan akad k01 kemarin tiba-tiba pak firman slow respon sekali.\r\n\r\nDemikian aduan kekecewaan kami, mohon dibantu bu selly total uang yg belum kembalikan ke kami Rp 10.500.000. Kami benar2 tidak percaya dengan management ningrat . besar harapan kami ibu selly bisa menjadi pintu jalan keluar kami agar kami tidak dirugikan terus menerus terkait waktu dan materi.', 6, 100, 1, 5, '2025-10-03 19:58:42', '2025-10-08 23:00:00', '2025-10-08', 