('C251006005', 18, 20, 'Trusmiland 5', 'G33', '', '@_driandia', 'After Sales', 'Wktu itu aku ke rumah ningrat di klayan. Lalu marketing menanyakan mau tenor brpa tahun. \nSaya jwb 15 tahun. Dan sudah pemberkasan, BI cheking aman, lalu booking  (DP) dan sudah survei pekerjaan juga. Kenapa tiba2 marketing mengabari dadakan kalau tenor harus berubah jdi 20 tahun. Ya saya kaget dong ko dari awal ga diksih tau sama marketing perihal syarat tenor dari umur, dan tiba2 aja disuru rubah tenor jadi 20 tahun. Tolong dong apakah ini kebijakan dari rumah ningrat seperti itu? Kenapa ketika pertemuan awal si marketing ga memberitahu. Malah klau cancel katanya DP hilang.', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-06 19:45:01', 9791, NULL, NULL, NULL, '2025-10-07 16:43:41', 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim marketing untuk klarifikasi kebijakan tenor dan penyampaian informasi ke pelanggan. Pastikan informasi syarat dan ketentuan tenor disampaikan di awal pertemuan selanjutnya agar tidak ada miskomunikasi. Tawarkan opsi untuk m', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251006006', 18, 20, 'Trusmiland 5', 'G33', '', '@_driandia', 'After Sales', 'Untuk marketing di kalayan tidak memberitahu kami perihal syarat tenor sejak awal saya survei tempat. Dan saya ingin tetap 15 tahun', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-06 19:48:21', 9791, NULL, NULL, NULL, '2025-10-07 16:43:08', 7804, 'Nilsen Yogawan', 'Hubungi tim marketing segera untuk memberikan penjelasan lengkap mengenai syarat tenor dan konfirmasi kemungkinan tenor 15 tahun sesuai permintaan konsumen.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251006007', 10, 70, 'RN Jayasampurna', 'F54', 'CS2505020225', 'Jaka Wanura', 'Aftersales', 'untuk melakukan pengecekan rumah blok F54 antara saya dengan pak hanif kapan dilaksanakannya ?\r\nsaya sudah menunggu lama tolong secepatnya dikabari', 6, 100, 3, 3, '2025-10-07 16:37:41', '2025-10-15 23:00:00', '2025-10-15', '2025-10-08 11:29:50', NULL, NULL, '2025-10-06 20:09:11', 5428, NULL, NULL, NULL, '2025-10-06 20:09:11', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-07 16:38:30', 'Mohon dijadwalkan', '8066', 'Sudah melaksanakan BAST', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-10 09:25:22', 9189),
('C251007001', 15, 64, 'RN Pejambon', 'E21', 'CS2502110111', 'Rifqi Aqso Alhuda', 'Sales/Mkt (Area Cirebon)', 'Untuk Program Free Angsuran 3x belum masuk padahal hari ini sudah jatuh tempo nya. Sudah info 1minggu sebelum nya ke sales. Saya tanya ke sales jawaban nya kurang memuaskan termasuk perihal serah terima kunci, padahal sudah lunas semua pembayaran baik DP maupun Lebihan Hook. Terima Kasih', 6, 100, 2, 3, '2025-10-08 17:03:18', '2025-10-09 23:00:00', '2025-10-09', '2025-10-09 21:31:53', NULL, NULL, '2025-10-07 13:34:25', 5428, NULL, NULL, NULL, '2025-10-07 13:34:25', 0, '', NULL, 340, 'Muhamad Irfannudin ', '2025-10-08 17:04:21', 'cek dan ajukan ke admin panji', '767,807', 'Sudah bertemu dengan konsumen kamis sore ', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 13:43:00', 9189),
('C251007002', 13, 70, 'RN Jayasampurna', 'D02', 'CS2501240127', 'Suhendi', 'Buspro (Berkas)', 'Maaf saya ijin mengajukan pertnyaan kepada rumah ningrat,perihal after sales:\r\n1.menegenai deposit 2jt,knpa konsumen harus membayar deposit 2jt ketika ingin melakukan pembangunan seprti (pembangunan tembok dapur,septictank,dll)\r\n2.mengenai pembayaran IPL bulanan sebesar 100rbu,sedangakan diperjanjian yg tertulis diSurat Perjanjian Bersama itu hanya 50rbu.(Subsidi) Dan rumah komersil 100rbu/bln\r\n', 5, 0, 2, 4, '2025-10-08 20:00:01', '2025-10-09 23:00:00', '2025-10-09', NULL, NULL, NULL, '2025-10-07 21:53:49', 5428, NULL, NULL, NULL, '2025-10-07 21:53:49', 0, '', NULL, 2397, 'Firman Tigoastomo Basuki ', '2025-10-08 20:01:18', 'Mohon dikonfirmasi kepada Konsumen via CRM untuk dapat input ulang dengan category Estate', '4138', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-08 10:21:10', 9189),
('C251007003', 18, 62, 'RN Gegunung', 'B36', '', '@loviaaditya', 'Progres Bangunan', 'Kak sya mau nnya surt2 kan sudh slsai smua, materai sdh dikmpln dan pembayaran lunas semua tpi kenapa blm ada survei 2 sdh 2 mnggu gada kabar2 pihak DEPOLOPER nya', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-07 23:04:38', 9791, NULL, NULL, NULL, '2025-10-08 17:30:55', 7804, 'Nilsen Yogawan', 'Segera hubungi pihak developer untuk menanyakan status survei 2 dan minta mereka memberikan update ke konsumen paling lambat 2 hari kerja. Update progres ini juga harus diinformasikan ke konsumen secara berkala hingga survei selesai.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251008001', 18, 77, 'Pabedilan', 'F34', '', '@anggihilda06', 'After Sales', 'Sudah tapi marketing nya gak respon', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-08 06:25:50', 9791, NULL, NULL, NULL, '2025-10-08 17:31:25', 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim marketing untuk memastikan respon cepat ke konsumen dan update status komunikasi ke konsumen.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251008002', 10, 26, 'Trusmiland ITB Komersil', 'E11', 'CS2411030066', 'Suwani  SH', 'Arus listrik belum ada ', 'Kamar depan blok E11 belum ada kelistrikan lampu dan saklar', 6, 100, 3, 3, '2025-10-09 15:32:59', '2025-10-23 23:00:00', '2025-10-23', '2025-10-23 17:06:22', NULL, NULL, '2025-10-08 09:25:35', 4011, NULL, NULL, NULL, '2025-10-08 09:25:35', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-09 15:33:51', 'mohon diperbaiki', '68', 'Sudah Copy ke Aftersales', '', NULL, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, '2025-11-12 10:55:18', 10118),
('C251008003', 4, 29, 'Trusmiland Dawuan', 'A38', 'CS2405090021', 'Mohamad Dahlan Sumantri, SE', 'Infrastruktur', 'Kami dari perwakilan paguyuban trusmiland dawuan blok A dan B meminta agar disediakan fasilitas berupa tempat bermain anak seperti perumahan trusmiland yang lainnya seperti trusmiland Indramayu yg begitu lengkap sarana bermain anak dan olagraga', 5, 0, 3, 0, '2025-10-09 15:27:01', '2023-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-10-08 10:23:41', 5428, NULL, NULL, NULL, '2025-10-08 10:23:41', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-09 15:32:33', 'Maaf Secara desain perumahan fasum yg di sediakan hanya mushola, terimakasih', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-08 10:39:07', 9189),
('C251008004', 13, 70, 'RN Jayasampurna', 'F09', 'CS2502010054', 'Yogi Pratama', 'Buspro (Berkas)', 'Rumah subsidi yg katanya rasa komersil, kenapa harus ada yang namanya deposit 2jt utk renovasi? Sedangkan dirumah subsidi manapun itu setiap konsumen yg mau merenovasi itu free ga ada deposit sama sekali, ini bener\"\" Merugikan semua konsumen nya! Ada lagi perihal Biaya IPL yg katanya gratis selama 2tahun, tapi dimana letak gratis nya? Waktu aftersales konsumen disuruh bayar IPL senilai 100rb/bulan dan itu harus dibayar langsung 3bulan, kalaupun memang harus bayar IPL, tagihan IPL untuk rumah subsidi itu hanya 50rb/bulan bukan 100rb. Dan untuk pdam tolong segera soalnya banyak konsumen yg masih harus bayar kontrakan dan angsuran RN yg skrng sudah berjalan,sedangkan rumah blm bisa di tempatin. jadi untuk semua pihak yg terikat di rumah ningrat tolong kerjasamanya dan komunikasi nya yg jelas! ', 5, 0, 2, 4, '2025-10-08 20:01:43', '2025-10-09 23:00:00', '2025-10-09', NULL, NULL, NULL, '2025-10-08 17:21:37', 5428, NULL, NULL, NULL, '2025-10-08 17:21:37', 0, '', NULL, 2397, 'Firman Tigoastomo Basuki ', '2025-10-08 20:02:40', 'Mohon konfirmasi kepada KOnsumen vai CRM untuk dapat input ulang pengaduan dengan category Estate', '4138', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C251008005', 18, 0, '', '', '', '@radenmuhmuyassar_', 'Infrastruktur', 'Tolong segera perbaiki lampu jln nya mati', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-08 18:31:07', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Kirim tim teknisi untuk memeriksa dan memperbaiki lampu jalan sesegera mungkin agar penerangan kembali normal.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
