('C251009001', 12, 70, 'RN Jayasampurna', 'F09', 'CS2502010054', 'Yogi Pratama', 'Estate', 'Rumah subsidi yg katanya rasa komersil, kenapa harus ada yang namanya deposit 2jt utk renovasi? Sedangkan dirumah subsidi manapun itu setiap konsumen yg mau merenovasi itu free ga ada deposit sama sekali, ini bener\"\" Merugikan semua konsumen nya! Ada lagi perihal Biaya IPL yg katanya gratis selama 2tahun, tapi dimana letak gratis nya? Waktu aftersales konsumen disuruh bayar IPL senilai 100rb/bulan dan itu harus dibayar langsung 3bulan, kalaupun memang harus bayar IPL, tagihan IPL untuk rumah subsidi itu hanya 50rb/bulan bukan 100rb. Dan untuk pdam tolong segera soalnya banyak konsumen yg masih harus bayar kontrakan dan angsuran RN yg skrng sudah berjalan,sedangkan rumah blm bisa di tempatin. jadi untuk semua pihak yg terikat di rumah ningrat tolong kerjasamanya dan komunikasi nya yg jelas!	\r\n', 6, 100, 3, 3, '2025-10-10 16:35:26', '2025-10-18 23:00:00', '2025-10-18', '2025-10-11 13:08:01', NULL, NULL, '2025-10-09 08:33:56', 5428, NULL, NULL, NULL, '2025-10-09 08:33:56', 0, '', NULL, 2951, 'Teuku Raja Sri Mustika ', '2025-10-10 16:36:10', 'mohon di jelaskan terkait ini', '8066', 'Menanggapi keluhan yang disampaikan, dapat kami jelaskan bahwa ketentuan dan aturan estate diterapkan untuk menjaga lingkungan perumahan agar tetap teratur, seragam, dan nyaman bagi seluruh penghuni. Adapun ketentuan deposit renovasi sebesar Rp2.000.000 b', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-10 08:23:58', 9189),
('C251009002', 18, 35, 'RN Indramayu', 'E45', '', '@ameliapnew_', 'After Sales', 'Mana yaaa ningrat tanggung jawabnya', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-09 09:02:39', 9791, NULL, NULL, NULL, '2025-10-09 14:23:12', 7804, 'Nilsen Yogawan', 'Segera hubungi Ningrat untuk klarifikasi dan tindak lanjut tanggung jawabnya. Pastikan komunikasi jelas dan solusi cepat diberikan kepada konsumen.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251009003', 18, 17, 'Trusmiland Pamengkang', 'O11', '', '@radenmuhmuyassar_', 'Infrastruktur', 'Tolong segera di atasin dong\nSaya kalo tengah malam pulang itu jalan masuk perumahan penerangan lampu sebagian mati jadi gelap udah masuk seperti hutan ga ada lampu penerangan', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-09 09:36:16', 9791, NULL, NULL, NULL, '2025-10-09 14:22:34', 7804, 'Nilsen Yogawan', 'Segera kirim tim teknisi untuk memeriksa dan memperbaiki lampu penerangan yang mati di jalan masuk perumahan. Pastikan semua lampu menyala dengan baik sehingga penerangan cukup dan aman untuk pengguna jalan.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251009004', 18, 17, 'Trusmiland Pamengkang', 'O11', '', '@radenmuhmuyassar_', 'Infrastruktur', 'Iya segera di atasi, klo sdh diatas jam 7 malam masuk perumahan seperti hutan lampu penerangan mati dan gelap ,', 2, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-09 09:43:30', 9791, NULL, NULL, NULL, '2025-10-09 14:21:37', 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim maintenance untuk memeriksa dan memperbaiki lampu penerangan jalan di perumahan sebelum jam 7 malam agar penerangan tidak mati saat malam hari.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
