('C251030001', 18, 0, '', '', '', '@hannantsabita', 'Infrastruktur', 'Mohon direspon keluhan kami terkait jalan di blok H dr no 16-19 yg selalu terkena genangan air dan banjir ketika hujan. Sangat mengganggu kenyamanan', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-30 08:44:50', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Lakukan inspeksi kondisi drainase di blok H no 16-19, perbaiki atau bersihkan saluran drainase, dan kerjakan perbaikan jalan atau pengerasan jika diperlukan untuk menghilangkan genangan air.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251030002', 18, 0, '', '', '', '@hannantsabita', 'Infrastruktur', 'Trusmiland Arjawinangun tahap 2 no 16-19. kami sampai berinisiatif sendiri utk sedikit meninggikan krn sangat tidak nyaman jika terkena genangan. Sudah menyampaikan komplain tp responnya hanya genangan air katanya sehingga tidak ditindaklanjuti padahal hal ini bs mencoreng nama baik trusmiland. Dari inisiatif kami meninggikan sedikit itu berakibat jalan menjadi tidak rata dan tidak sedap dipandang mata. Mohon segera ditindaklanjuti. Terimakasih atas perhatiannya', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-10-30 08:48:51', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan survei ulang kondisi genangan dan ketinggian jalan di lokasi. Koordinasikan dengan tim teknik untuk membuat perbaikan yang tepat dan estetis agar genangan air tidak terjadi kembali dan jalan jadi rata. Berikan update progres penanganan kepa', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251030003', 6, 40, 'Arjawinangun ByPass', 'D74', 'CS2505140201', 'Rizqy Dwi Nurrochman', 'PDAM', 'Selamat pagi.. Mohon maaf di Rumah Ningrat Arjawinangun Bypass Kab. Cirebon di blok D74 air PDAM nya sudah 5 hari belum nyala.. Tolong agar diperbaiki\r\nTerimakasih', 5, 0, 2, 0, '2025-11-12 17:54:52', '2023-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-10-30 09:33:21', 5428, NULL, NULL, NULL, '2025-11-11 12:07:43', 10118, 'SHELYA AYUDHA', 'Sudah 5 hari air PDAM mati, tolong perbaiki agar konsumen dapat memakai airnya', 8066, 'Larson Mario', '2025-11-12 17:57:32', 'dari developer hanya bertanggung jawab dari sisi pemasangan unit saja, untuk penyalaan air dan maintenance bisa langsung ke PDAM setempat, terimakasih..', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-11 11:59:52', 10118),
