('C251104001', 13, 56, 'RN Majalengka 2', 'B04', 'CS2510060093', 'Ridwan', 'Buspro (Berkas)', 'Saya beli cash keras tgl 25 Oktober 2025, dijanjikan ttd AJB dgn Notaris 1 pekan setelah pembayaran lunas. Tapi sampai sekarang belum ada kejelasan. Mohon ditanggapi', 6, 100, 2, 4, '2025-11-05 19:33:46', '2025-11-08 23:00:00', '2025-11-08', '2025-11-07 11:30:02', NULL, NULL, '2025-11-04 07:15:56', 5428, NULL, NULL, NULL, '2025-11-04 11:00:59', 5768, 'Ceppy Chandra', 'Mohon ditindaklanjuti', 2397, 'Firman Tigoastomo Basuki ', '2025-11-05 19:34:45', 'MOhon untuk dilakukan konfirmasi penjadwalan Akad atas Konsumen tersebut', '2787', 'setelah dikoordinasikan dengan notaris, pelaksanaan akad bisa dilakukan pada tanggal 08 november 2025 pukul 10.00 wib. tempat dilaksanakannya akad berada di kantor notaris raka bintang gumilang. terima kasih..', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-18 16:08:25', 10118),
('C251104002', 12, 43, 'RN Kaliwadas', 'A01', 'CS2309200370', 'Rio Andalas', 'Estate', 'Tolong untuk projek RN Kaliwadas harap ditinjau ulang dan perbaiki untuk dimaksimalkan mengenai pos Security , menimbang pos Security yang ada saat ini dirasa sangat tidak manusiawi, \r\n1. Jika hujan penjaga pasti kehujanan dan penjaga selalu cari tempat untuk neduh\r\n2. Kalau siang sangat panas sekali di pos tersebut karena terbuat dari bahan yang tidak menyerap panas\r\n3. Tidak fasilitas listrik seperti lampu dan colokan\r\n4. Tidak ada toilet sehingga yang jaga kerap ikut kerumah warga untuk BAK dll.\r\n\r\nTolong untuk diperbaiki saya perwakilan dari warga perumahan yang punya grup Wa sendiri merasa kasian dengan Security yang jaga di pos karena jika pos nyaman pasti yang jaga pun akan lebih maksimal', 5, 0, 3, 0, '2025-11-05 11:32:00', '0000-00-00 00:00:00', '2025-11-28', NULL, NULL, NULL, '2025-11-04 10:47:57', 5428, NULL, NULL, NULL, '2025-11-04 11:06:43', 5768, 'Ceppy Chandra', 'mohon di cek dan dipertimbangkan usulan warga RN kaliwadas', 2951, 'Teuku Raja Sri Mustika ', '2025-11-05 11:33:52', 'ini solusi dari estate untuk diadakan pos security dan konsumen sudah lebih dari setahun semenjak serah terima kunci', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C251104003', 10, 26, 'Trusmiland ITB Komersil', 'C15', 'CS2307010709', 'Edy Djunaedi/Fikrie pratiwi', 'Progres Bangunan', 'Tanah/plesteran/garasi depan rumah ambles, membuat lubang rongga di dalam garasi. Sangat berbahaya kalau tidak segera diperbaiki', 3, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-04 13:20:50', 5428, NULL, NULL, NULL, '2025-11-05 08:59:00', 5768, 'Ceppy Chandra', 'Setelah di cek umur bangunan sudah lebih dari 1 tahun', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('C251104004', 0, 70, 'RN Jayasampurna', 'F62', 'CS2409010129', 'nurul dwi maulana', 'Aftersales', 'foto 1.terdapat plesteran di jendela depan tidak rapih \r\n2.keramik dan cor coran lantai depan tidak rapih, keramik terangkat tidak sejajar\r\n3.pintu kamar mandi tidak pas, susah di buka tutup\r\n4.lantai kamar ke 2 kopong dan kotor\r\n5.cat pintu belakang tidak rata terkesan kotor\r\n6.pintu belakang arah area dapur tidak pas saat di tutup tidak bisa dikunci\r\n7.keramik pecah dikamar 1 dan kotor\r\n8.keramik dipasang sisaan potongan keramik menjadi tidak rapih\r\n9.tembok depan kamar ke 2 tidak rata atau bergelombang\r\n10.kamar 1 plafond rembes berjamur', 3, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-04 16:02:00', 5428, NULL, NULL, NULL, '2025-11-05 09:24:28', 5768, 'Ceppy Chandra', 'Krn aftersales om progres', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
