('C251107001', 13, 32, 'Trusmiland Cikoneng Majalengka', 'E01', 'CS221123013', 'Iqbal Fasyah', 'Legal (Perizinan/Sertifikat)', ' Masih Belum Menerima Sertifikat/SHGB Tanah Lebih, Sudah hampir 3 tahun.\r\n\r\nSaya membeli tanah hook/lebih -+ 30m2. Semenjak akad sampai sekarang rumah sudah lebih dari 800 hari. Saya masih belum menerima Sertifikat/SHGB tanah lebih tersebut. Sebelumnya sudah dijanjikan tahun lalu penanda tanganan di Notaris mengenai tanah lebih ini, tapi sampai saat ini saya menghubungi Notaris masih belum ada balasan. Tolong dari Trusmi membantu akan hal ini.', 6, 100, 2, 3, '2025-11-07 11:08:12', '2025-11-08 23:00:00', '2025-11-08', '2025-11-08 14:05:49', NULL, NULL, '2025-11-07 08:07:33', 5428, NULL, NULL, NULL, '2025-11-07 10:30:26', 5768, 'Ceppy Chandra', 'Mohon di tindaklanjuti komplainan konsumen', 2397, 'Firman Tigoastomo Basuki ', '2025-11-07 11:09:22', 'Mohon dilakukan tracking posisi Sertifikat, apakah sudah ready di Notaris atau masih dalam proses, segera report ke Konsumen untuk Hal tersebut', '2787', 'Sehuhungan telah selesainya BN, sertipikat bisa diambil di kantor notaris erlan, majalengka. Terima kasih.', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-11 14:22:02', 10118),
('C251107002', 10, 90, 'RN Sampora', 'J59', 'CS2505300547', 'Farhatur Rohmah', 'Plester', 'Area Carport dan halaman depan rumah yang harus ditambahkan BATU SEPRIT, \r\nHasil perbaikan after sales beberapa waktu lalu, dan ini kondisi nya rusak karena kekurangan semen dan pasir.\r\nJembatan Cor Pagar yang harus diperbaiki, semen nya terkelupas\r\n', 6, 100, 2, 3, '2025-11-07 13:11:18', '2025-11-13 23:00:00', '2025-11-13', '2025-11-12 10:53:47', NULL, NULL, '2025-11-07 08:46:42', 5428, NULL, NULL, NULL, '2025-11-07 10:42:21', 5768, 'Ceppy Chandra', 'Mohon ditindaklanjuti krn aftersalesnya masih onprogres', 2951, 'Teuku Raja Sri Mustika ', '2025-11-07 13:12:11', 'mohon di perbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-14 11:03:04', 10118),
