('C251112008', 10, 65, 'TL Cempaka 2', 'E09', 'CS2506260472', 'Gazul fiqri Zaman', 'Progres Bangunan', 'Ini saya baru pindah belum nyampe sebulan tp tembok bocor udah kaya air terjun. Pulang kerja harus ngepelin terus lantai karena bocor dr tembok dan genteng. Saya beli rumah kaya beli rumah2an kesannya ???? tolong bagian projek harus lebih memperhatikan, jangan cuma asal-asalan. Anak SD jg bisa kalo cuma bikin asal-asalan mh', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-12 18:48:15', 5428, NULL, NULL, NULL, '2025-11-14 10:21:14', 10118, 'SHELYA AYUDHA', 'Tidak mengajukan aftersales dan rumah langsung dihuni', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-13 13:17:53', 10118),
