('C251112010', 18, 0, '', '', '', '@jffar_12', 'Finance', 'Nah setelah pembayaran semua dari Oktober sampai November ini ngga tau statusnya apa, uang semua sudah masuk', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-12 20:18:47', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera cek status pembayaran di sistem keuangan dan berikan laporan status pembayaran yang jelas kepada konsumen. Update juga status pembayaran pada database agar mudah dipantau pelanggan.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
