('C251113001', 18, 0, '', '', '', '@dwips94', 'After Sales', 'Ini gimana gapernah ada perbaikan? \nRumah saya selalu jd korban, yg lain kering tp saya sendiri kena imbasnya. Saya sama-sama bayar cicilan tiap bulan tp jd yg paling gak nyaman tinggal.', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-13 07:04:43', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera identifikasi masalah perbaikan rumah konsumen dan jadwalkan perbaikan sesegera mungkin. Tingkatkan komunikasi dengan konsumen untuk memberikan update progres perbaikan secara rutin.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251113002', 4, 20, 'Trusmiland 5', 'S80', 'CS220807065', 'Dwi purnamasari', 'Infrastruktur', 'Ini gimana gapernah ada perbaikan? \r\nRumah saya selalu jd korban, yg lain kering tp saya sendiri kena imbasnya. Saya sama-sama bayar cicilan tiap bulan tp jd yg paling gak nyaman tinggal.\r\nRumah saya selalu yg pertama dan terkadang satu-satunya yg kena dampak banjir. Mengganggu aktifitas, selalu ketakutan tiap banjir. Tolong dong tindak lanjutnya dan solusinya. Saya mau nyaman tinggal dirumah saya sendiri, dari awal percaya klo tinggal disni itu akan nyaman tp ternyata selalu begini. ', 6, 100, 2, 4, '2025-11-14 17:29:02', '2025-12-06 23:00:00', '2025-12-06', '2025-11-17 11:30:17', NULL, NULL, '2025-11-13 07:10:17', 5428, NULL, NULL, NULL, '2025-11-13 14:19:11', 10118, 'SHELYA AYUDHA', 'Mohon untuk di cek kembali agar tidak terjadi lagi kebanjiran di area tersebut', 2951, 'Teuku Raja Sri Mustika ', '2025-11-14 17:31:05', 'air mengalir ke tempat yang lebih rendah di perlukan pompa air ', '8066', 'Penyerahan pompa air dari developer kepada warga trusmiland klayan 5 untuk penanggulangan banjir dilengkapi dengan berita acara serah terima dan foto dokumentasi penyerahan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-13 14:00:46', 10118),
('C251113003', 1, 42, 'RN Kendal', 'B16', 'CS2508300234', 'Fitri Mardiyani Afifah', 'Progres Bangunan', '1. Pintu masuk depan rumah tidak tegak lurus sehingga susah di tutup, dan pintunya berbeda dengan tetangga sekitar yg masih dalam area Rumah Ningrat, ini pintunya triplek\r\n2. Terdapat rembesan di bagian atas kamar depan\r\n3. Pintu kamar yg di depan kamar mandi (kamar utama) seperti di congkel, tidak rapet\r\n4. Jendela di kamar utama tidak presisi', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-13 11:05:30', 5428, NULL, NULL, NULL, '2025-11-13 16:36:02', 10118, 'SHELYA AYUDHA', 'Belum Serah Terima Kunci', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-13 14:04:30', 10118),
