('C251115001', 10, 32, 'Trusmiland Cikoneng Majalengka', 'E15', 'CS2506110007', 'FIKRI ALFAN FASHA', 'Aftersales', 'Saya sudah mengajukan aftersales dengan detail pengajuan yang diinput melalui web pada 23 Oktober 2025. Per hari ini, saya kembali mengecek status di web aftersales dan tertulis bahwa pekerjaan sudah selesai. Namun setelah saya cek langsung kondisi rumah, masih terdapat beberapa bagian yang belum diperbaiki, yaitu:\r\n\r\n1. Bidang penghubung antara rumah dan jalan (di atas saluran) masih terlalu miring.\r\n\r\n\r\n2. Colokan listrik di ruang tamu terlepas/copot.\r\n\r\n\r\n3. Pintu kamar mandi tidak pas saat ditutup.\r\n\r\n\r\n4. Tembok kamar belakang mengalami rembes.\r\n\r\n\r\n5. Pintu kamar belakang tidak pas saat ditutup.\r\n\r\n\r\n\r\nMohon agar perbaikan dapat segera ditindaklanjuti sesuai laporan yang sudah saya ajukan. Terima kasih.\r\n', 6, 100, 2, 4, '2025-11-17 15:05:59', '2026-01-19 23:00:00', '2026-01-19', '2026-01-19 19:30:03', NULL, NULL, '2025-11-15 12:15:07', 5428, NULL, NULL, NULL, '2025-11-17 10:35:20', 10118, 'SHELYA AYUDHA', 'Perbaikan AFS masih banyak yang belum selesai. Tolong dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-11-17 15:06:45', 'mohon diperbaiki', '2842', 'Penjadwalan ulang mpp', '', 1, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-17 09:57:25', 10118),
('C251115002', 18, 0, '', '', '', '@_nugifauzi23_', 'Infrastruktur', 'rn 1 indramayu bangunannya merudul pake terigu tah komposisinya fuck 👎🏻', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-15 13:14:46', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Periksa ulang komposisi bahan bangunan dan pastikan menggunakan material yang sesuai standar. Lakukan perbaikan struktur bangunan segera dengan bahan yang tepat.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251115003', 10, 19, 'RN Kayangan', 'K17', 'CS2501120054', 'Sifa Fitria Ramdaniah', 'Aftersales', 'Dari batas waktu pengerjaan aftersales sampai batas waktunya selesai pada tanggal 13 oktober pas di cek 1 minggu sekali sampai sekarang Pada bagian kamer ke 2 dinding bagian bawah dari ujung ke ujung cat nya pada ngelupas semua iya tidak ada perubahan nya sama sekali dan Pada bagaian ruang tamu, kamar 1, kamar 2 dan kamar mandi pada bocor semua, dan bocor nya lumayan besar', 6, 100, 3, 4, '2025-11-18 10:15:24', '2025-12-15 23:00:00', '2025-12-15', '2025-12-15 14:20:17', NULL, NULL, '2025-11-15 14:18:56', 5428, NULL, NULL, NULL, '2025-11-17 16:41:22', 10118, 'SHELYA AYUDHA', 'Perbaikan AFS belum selesai, mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-11-18 10:15:54', 'mohon diperbaiki', '2842', 'Pekerjaan Perbaikan Sudah Selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-17 09:59:40', 10118),
