('C251129004', 10, 27, 'Trusmiland Diamond', 'E10', 'CS2501300273', 'Mhd Rizky Rahmadsyah Lubis', 'Aftersales', 'DINDING KAMAR BELAKANG YANG BOCOR OLEH KARENA AKIBAT REMBESANAN AIR TALANG RUMAH TETANGGA BELAKANG, MOHON SISI LUAR DINDING BELAKANG RUMAH UNTUK DI PLASTER AGAR DINDING KAMAR BELAKANG TIDAK BOCOR LAGI', 5, 0, 3, 0, '2025-12-01 15:24:20', '0000-00-00 00:00:00', '2025-12-13', NULL, NULL, NULL, '2025-11-29 14:34:17', 5428, NULL, NULL, NULL, '2025-12-01 09:25:09', 10118, 'SHELYA AYUDHA', 'Terdapat kebocoran pada dinding kamar belakang', 2951, 'Teuku Raja Sri Mustika ', '2025-12-01 15:29:31', 'terkait tembok belakang secara spek tidak di plester', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-01 09:19:40', 10118),
('C251129005', 18, 0, '', '', '', '@wawan55347', 'Infrastruktur', 'Itu karang sari yang Deket setikes yang sering banjir itu tidak', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-29 14:37:19', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Koordinasikan dengan tim infrastruktur untuk memeriksa saluran air dan sistem drainase di lokasi Karang Sari dekat setikes, lakukan perbaikan atau pembersihan agar tidak terjadi banjir.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251129006', 10, 40, 'Arjawinangun ByPass', 'F27', 'CS2409260312', 'Ahmad zahid', 'Aftersales', 'Minta tlong pak di samping rumah ini kan masi tanah kosong blm ada pembangunan, rumah saya bocor parah karna rembesan dari tembok samping yg blm di plester hanya batako saja. Bisakah kalo tidk ada pembangunan tembok smping saya ini di plester atau di benerin biar airnya gamasuk kerumah sya pak merugikan banget kalo hujan gede air masuk smpe banjir grgr dari rembesan dan kebocoran tembok yang blm di plester minta tolong untuk solusinya sy merasa di rugikan. Terimkasih. Mohon untuk seecepatnya di tanganin karna ini dampaknya akan sangat buruk di rumah sy. Tolong segera cari solusi juga untuk kebanjiran di blok F paling belakang ini jika hujan trus2an bisa2 masuk ke dlm rumah warga yg lain juga, perumahan elit tapi sering banjir tolong di bantu pak ', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-29 20:35:56', 5428, NULL, NULL, NULL, '2025-12-02 10:26:19', 10118, 'SHELYA AYUDHA', 'Mohon maaf untuk standar tembok samping memang tidak di plester.', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-01 09:28:01', 10118),
('C251130001', 18, 0, '', '', '', '@shareramiw', 'After Sales', 'Belum terima kunci', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-11-30 14:36:59', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera hubungi bagian pengiriman untuk memastikan status pengiriman kunci dan informasikan kepada konsumen perkiraan waktu penerimaan kunci.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251130002', 1, 53, 'Indramayu 2 (Margadadi)', 'I47', 'CS2504100014', 'Ade kurniawan, S.AP. MH', 'Kunci Rumah', 'Sudah mau masuk angsuran ke-3 per-bulan desember tapi progres serah terima kunci belum ada, sehingga belum bisa mengajukan komplain masalah kondisi fisik unit bangunan.\r\nSetiap minggu saya selalu kontrol kondisi rumah, tapi sepertinya tidak ada perubahan di beberapa bagian-bagian yang perlu diperbaiki.', 6, 100, 2, 4, '2025-12-01 15:13:13', '2025-12-13 23:00:00', '2025-12-13', '2025-12-13 11:58:03', NULL, NULL, '2025-11-30 18:30:10', 5428, NULL, NULL, NULL, '2025-12-01 10:17:35', 10118, 'SHELYA AYUDHA', 'Sudah mau angsuran ke-3 namun konsumen masih belum mendapatkan kunci. Mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-12-01 15:22:10', 'masih belum lolos qc passed, dilakukan perbaikan qc terlebih dahulu', '7972', 'sudah lolos qc ', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-01 09:30:09', 10118),
