('C251209001', 10, 20, 'Trusmiland 5', 'G08', 'CS2505060106', 'Muhamad Wahyudin', 'Progres Bangunan', 'Saluran Air Bawah tanah tidak tersambung dengan baik, saya minta dibereskan untuk saluran nya, moso pipa nya ga nyambung ke saluran buang nya, ini gimana trusmiland\r\n\r\nposisi paralon juga pecah', 6, 100, 2, 4, '2025-12-12 15:49:02', '2025-12-31 23:00:00', '2025-12-31', '2025-12-30 10:06:38', NULL, NULL, '2025-12-09 10:51:38', 5428, NULL, NULL, NULL, '2025-12-12 08:10:07', 10118, 'SHELYA AYUDHA', 'Mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-12-12 15:49:30', 'mohon diperbaiki', '8888', 'sudah selesai dikerjakan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-10 16:36:38', 10118),
('C251209002', 18, 0, '', '', '', '@_vanpratama', 'Infrastruktur', 'Untuk RN Jayasampurna tolong untuk perhatiannya lagi di Air, Jalan, dan Listrik, kasihan banyak warga yang tidak bisa pindah karena Belum tersedia Akses yang memadai, khususnya untuk Air (2 Toren satu Pompa untuk 100 kk?, menurut saya kurang logis, jikalau memang dari PDAM tidak bisa support, mungkin bisa beralih ke Opsi lan, dulu kan janji di awalnya sumur BOR dan Pompa di provide tapi tiba2 ganti ke PDAM, dan sekarang full issue), Thanks', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 17:20:38', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Lakukan evaluasi segera terhadap ketersediaan dan kapasitas air, listrik, dan akses jalan di RN Jayasampurna. Prioritaskan penyelesaian kendala air dengan mengkaji opsi sumur bor dan pompa tambahan jika PDAM tidak mendukung. Koordinasikan dengan pihak ter', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251209003', 10, 20, 'Trusmiland 5', 'G20', 'CS2504210256', 'Wanto', 'Aftersales', 'Pintu yg kurang panjang/ menggantung, jd ada space yg bisa membuat ular masuk ke rumah! ', 6, 100, 2, 4, '2025-12-11 16:03:24', '2026-01-05 23:00:00', '2026-01-05', '2025-12-18 16:20:09', NULL, NULL, '2025-12-09 17:57:17', 5428, NULL, NULL, NULL, '2025-12-11 10:27:39', 10118, 'SHELYA AYUDHA', 'Mohon dicek pemasangan pintunya', 2951, 'Teuku Raja Sri Mustika ', '2025-12-11 16:04:04', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 08:48:25', 10118),
('C251209004', 4, 20, 'Trusmiland 5', 'S80', 'CS220807065', 'Dwi purnamasari', 'Infrastruktur', 'Tanggung jawab pihak developer gimana ya? \r\nHarus komplain berapa kali supaya ditanggapi? \r\nSolusi dari rumah saya yg selalu banjir sendirian itu gmna? \r\nHanya kasih pompa lalu lepas tangan? \r\nTindak lanjut dong cari solusi! ', 5, 0, 3, 0, '2025-12-12 16:53:11', '2025-12-31 23:00:00', '2025-12-31', NULL, NULL, NULL, '2025-12-09 19:09:21', 5428, NULL, NULL, NULL, '2025-12-11 11:14:07', 10118, 'SHELYA AYUDHA', 'Mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-12-12 16:55:06', 'Maaf bapak / ibu dari kami sudah di beri pompa untuk penanganannya, dan sebelumnya sudah dilakukan pengerjaan turap, bak control, saluran, crossingan,  tim sudah banyak berupaya untuk menangani itu, terimakasii', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 16:52:53', 10118),
('C251209005', 18, 0, '', '', '', '@wirwiraaa', 'After Sales', 'lagi butuh kasur buat dirumah , soalnya kasur dirumah udah rusak , paku nya keluar keluar jadi tidur pake tiker doang', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 21:22:45', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim logistik untuk mengirimkan kasur pengganti kepada konsumen, dan lakukan pengecekan kualitas sebelum pengiriman untuk memastikan tidak ada cacat.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251209006', 18, 0, '', '', '', '@triyanni17', 'Infrastruktur', 'Butuhhh no dropp minn, buat atap rumah yang lagi bocor di musim hujan ini 🥲', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 21:42:45', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera kirimkan tim teknisi untuk melakukan pemeriksaan dan perbaikan atap bocor. Pastikan bahan waterproofing tersedia untuk menutup kebocoran sementara jika diperlukan.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251209007', 18, 0, '', '', '', '@nashya_sq', 'After Sales', 'Butuh cat tambok buat rumah sama ubin yg udh retak', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 22:01:05', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera kirimkan tim perawatan untuk melakukan pengecatan ulang dan perbaikan ubin yang retak. Pastikan cat dan bahan perbaikan sesuai standar.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251209008', 18, 0, '', '', '', '@stirisma_', 'Infrastruktur', 'akuuu butuh air bersih minn di ningrat jayasampurna udah bnyak yg pindahan tapi pdam nya gamasuk2😭', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 22:24:01', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan bagian PDAM untuk investigasi pemasangan sambungan baru di wilayah Ningrat Jayasampurna. Pastikan proses pemasangan dilakukan secepatnya dan informasikan progress kepada konsumen secara berkala.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251209009', 18, 0, '', '', '', '@taurus.girl58_', 'Sales Support', 'Gak mau apa-apa minrat.\nCuma Butuh dicariin konsumen  yg mau beli cash atau kredit motor honda baru Khusus warga JABODETABEK supaya bisa dapet Gaji, kalo gak ada penjualan saya gak dapet gaji min. Apalagi kemaren saya habis kena tipu 5 jt huhuhu mana uangnya sisa satu-satunya lagi, nangissss banget minrat😭😭', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-09 23:35:23', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera hubungi tim Sales Support untuk membantu mencari konsumen potensial khusus wilayah JABODETABEK. Berikan update rutin dan data calon pembeli cash atau kredit motor Honda baru. Ingatkan juga agar lebih berhati-hati dan laporkan masalah penipuan ke ba', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
