('C251210002', 4, 70, 'RN Jayasampurna', 'D05', 'CS2504300283', 'RYAN NOVIAN', 'Estate', 'tolong jalanan diperbaiki. walawpun untuk jalur proyek tapi kami warga juga berhak dapat jalanan yg seengganya bisa dilaluin. kalao kaya gini jangankan motor, jalan kaki aja susah. banyak orang hampir terjatuh karna jalanan licin. ', 6, 100, 2, 4, '2025-12-12 11:19:00', '2025-12-31 23:00:00', '2025-12-31', '2025-12-30 17:03:39', NULL, NULL, '2025-12-10 06:45:43', 5428, NULL, NULL, NULL, '2025-12-11 09:00:10', 10118, 'SHELYA AYUDHA', 'Mohon dicek kapan pembangunan jalan akan dilakukan', 2951, 'Teuku Raja Sri Mustika ', '2025-12-12 11:19:29', 'mohon diperbaiki', '8480,1637', 'sudah selesai di perbaiki', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 08:53:49', 10118),
('C251210003', 13, 20, 'Trusmiland 5', 'J32', 'CS2508300042', 'SULAIMAN', 'Buspro (Berkas)', 'Saya sulaiman kenapa spr ini pengajuannya 15 tahun padahal waktu diawal saya bilang 10 th tanpa apa konfirmasi ke saya, tau2 di akhir ini baru ketahuan hasil dri bank awalnya dari pengajuan dari pihak dev 15th. Disini saya gak ttd kertas ini dan nik saya pun beda. Tgl lahir saya pun beda!!', 6, 100, 2, 3, '2025-12-12 18:57:25', '2025-12-15 23:00:00', '2025-12-15', '2025-12-15 20:00:37', NULL, NULL, '2025-12-10 16:00:57', 5428, NULL, NULL, NULL, '2025-12-11 08:56:35', 10118, 'SHELYA AYUDHA', 'Mohon dicek dan dijelaskan kepada konsumen terkait tenor yang didapat', 2397, 'Firman Tigoastomo Basuki ', '2025-12-12 18:58:23', 'Mohon dilakukan penyelidikan dan penjelasan ke Konsumen dengan baik', '4138', 'Sudah dijelaskan oleh sales dan orang bank bahwa jika pengajuannya 10 TAHUN itu akan terkena reject RPC oleh bank karena penghasilan tidak mencukupi, karena itu yang diajukan oleh data collect saat itu (Puji Pamungkas) adalah 15 TAHUN dengan sepengetahuan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 08:55:06', 10118),
