('C251211004', 10, 70, 'RN Jayasampurna', 'G04', 'CS2504260155', 'Dian Ardiansyah Harry', 'Aftersales', 'Selamat pagi, \r\nsaya Dian Ardiansyah Harry \r\nPerumahan Rumah ningrat jayasampurna bekasi\r\nBlok G04\r\nMau melaporkan kamar belakang saya sekarang rembes parah, masuk semua air gara2 ada kobangan besar di belakang rumah. Tolong solusinya\r\n\r\nKobangan air di belakang rumah awalnya kecil, lama kelamaan besar karena tidak ada aliran seperti selokan dan airnya mengalir ke belakang rumah saya sampai banjir di dalam rumah ', 6, 100, 2, 4, '2025-12-11 15:29:37', '2025-12-20 23:00:00', '2025-12-20', '2025-12-20 16:04:29', NULL, NULL, '2025-12-11 11:17:42', 5428, NULL, NULL, NULL, '2025-12-11 11:27:02', 10118, 'SHELYA AYUDHA', 'Mohon untuk dicek dan diperbaiki', 2951, 'Teuku Raja Sri Mustika ', '2025-12-11 15:30:30', 'mohon diperbaiki', '8480', 'Sesuai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-11 11:21:00', 10118),
('C251211005', 19, 70, 'RN Jayasampurna', 'C86', 'CS2507310242', 'Armansyah', 'CCTV', 'CCTV blm bisa di akses dari aplikasi kluarga Ningrat knp ya?? ', 5, 0, 3, 0, '2025-12-13 10:30:52', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2025-12-11 20:51:40', 5428, NULL, NULL, NULL, '2025-12-12 14:49:40', 10118, 'SHELYA AYUDHA', 'Tolong dibantu pengecekan', 2951, 'Teuku Raja Sri Mustika ', '2025-12-13 10:31:41', 'mohon maaf konsumen belum bisa akses cctv karena konsumen belum stk ', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 08:53:00', 10118),
('C251211006', 4, 70, 'RN Jayasampurna', 'D07', 'CS2501120167', 'Firdaus fatchur rachman', 'Infrastruktur', 'Mohon pihak developer agar lebih memperhatikan lagi akses jalan di depan rumah kami, akses jalan di depan rumah kami tidak bisa dilalui kendaran maupun jalan kaki. \r\nIni harus jadi perhatian penting untuk developer \r\nMengingat kita sebagai konsumen ,seharusnya setelah akad kredit sudah mendapatkan hunian yang layak. \r\n\r\nDan sekarang yang kami alami jauh dari kata hidup lebih baik, . \r\n', 6, 100, 2, 4, '2025-12-12 11:17:57', '2025-12-31 23:00:00', '2025-12-31', '2025-12-30 17:04:16', NULL, NULL, '2025-12-11 21:02:52', 5428, NULL, NULL, NULL, '2025-12-12 08:42:16', 10118, 'SHELYA AYUDHA', 'Mohon dicek kapan pembangunan jalannya', 2951, 'Teuku Raja Sri Mustika ', '2025-12-12 11:18:49', 'mohon diperbaiki', '8480,1637', 'jalan sudah selesai diperbaiki', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 08:39:21', 10118),
