('C251212002', 10, 40, 'Arjawinangun ByPass', 'D54', 'CS2508170188', 'Hermanta', 'Infrastruktur', 'Pintu depan dan pintu kamar ga bisa di buka sepenuhnya karna lantai sudah berbumbung.\r\nTrus tembok juga sudah pada retak', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 12:43:26', 5428, NULL, NULL, NULL, '2025-12-13 08:27:08', 10118, 'SHELYA AYUDHA', 'Sedang melakukan Aftersales. Double input.', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 16:56:30', 10118),
('C251212003', 10, 62, 'RN Gegunung', 'B54', 'CS2407190037', 'KARTO', 'Infrastruktur', '1. gagang pintu belakang rusak\r\n2. tembok bagian dalam pecah\r\n3. pintu depan ngelupas kayunya\r\n4. besi di bagian pintu penyok \r\n5. tembok bagian depan lembab sehingga ngelupas \r\n6. pintu kamar mandi ga ada gagangnya \r\n7. tembok bagian belakang gompel ngelupas \r\n8. lampu semua ruangan ga ada\r\n9. tembok retak retak\r\n10. cat ga rapih\r\n', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 15:53:45', 5428, NULL, NULL, NULL, '2025-12-13 10:16:44', 10118, 'SHELYA AYUDHA', 'Dialihkan untuk pengajuan perbaikan pada web Aftersales', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-12 16:58:03', 10118);
