('C251216002', 4, 20, 'Trusmiland 5', 'I20', 'CS2412170059', 'Hazizah Nurul Aeni', 'Infrastruktur', 'Tahap 6 blok H I J hujan baru 4 jam sudah banjir se betis. TOLONG SEGERA BENAHI ALIRAN AIR AGAR TIDAK BANJIR LAGI MENGINGAT MUSIM HUJAN. KARNA DI BLOK H I J RUMAH LEBIH RENDAH DARI JALAN KALAU MASALAH ALIRAN INI GK SEGERA DIBENAHI HUJAN 2 HARI BISA TENGGELAM. ', 6, 100, 2, 3, '2025-12-17 13:25:39', '2025-12-18 23:00:00', '2025-12-18', '2025-12-18 17:36:17', NULL, NULL, '2025-12-16 13:00:16', 5428, NULL, NULL, NULL, '2025-12-16 13:40:33', 10118, 'SHELYA AYUDHA', 'Mohon ditindaklanjuti terkait kebanjiran yang terjadi', 2951, 'Teuku Raja Sri Mustika ', '2025-12-17 13:26:51', 'mohon di normalisasi', '8888', 'done', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-16 13:33:45', 10118),
('C251216003', 10, 34, 'Trusmiland Caracas', 'D52', 'CS2509130101', 'Eko Wahyu Rohadi', 'Aftersales', 'Pengajuan after sales saya belum di tindak lanjut, sebelumnya saya dijanjikan tanggal 15 selesai by wa offcial after sales rumah ningarat. Tapi sudah tanggal 16 belum juga dikerjakan. Mau sampai kapan? Saya complain kebetuln ada vendor dan tukangnya disitu, dia bilng tidak ada list dan laporn untuk pengerjaan blok d52. Ini maksudnya gimana? Harus bagaimana saya? Mana artesis belum terpasang.\r\n\r\nDitambah ada complainan baru selain plafond bocor.\r\n\r\nTembok rembes apabila hujan\r\n\r\nAir belum terpasang dan saya lihat jalur air ko depan carpot. Berti jalur capot itu harus di bobok lagi gitu? Aneeeeh\r\n\r\nGenting bagian depan serti habis injak permukanya tidak rata\r\n\r\nPintu kamar mandi tidak rata dan tidak bisa ditutup rapat\r\n\r\nCarpot tidak rata\r\n\r\n tolong pasang ram anti nyamuk untuk dijendel bagian atas\r\n\r\nTembok penyangga pagar pecah dan retak.\r\n\r\nTolong segera penyelesainya, jangan hanya janji.\r\n\r\n', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-16 14:00:44', 5428, NULL, NULL, NULL, '2025-12-17 13:57:10', 10118, 'SHELYA AYUDHA', 'Sedang dilakukan pengajuan Aftersales sehingga double input perbaikan', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-17 10:07:40', 10118),
