('C251219002', 3, 53, 'Indramayu 2 (Margadadi)', 'F52', 'CS2508160024', 'Diana Puspita', 'Infrastruktur', 'rumah saya masih banyak yang kurang padahal sudah akad, seperti belum ada pagar, belum ada jembatan penghubung dr jalan ke rumah, dan cat sebelah rumah di bagua hook saya cat tidak merata', 6, 100, 2, 4, '2025-12-19 16:15:25', '2025-12-29 23:00:00', '2025-12-29', '2025-12-29 11:19:17', NULL, NULL, '2025-12-19 10:14:57', 5428, NULL, NULL, NULL, '2025-12-19 15:06:22', 10118, 'SHELYA AYUDHA', 'Mohon ditindaklanjuti ', 2951, 'Teuku Raja Sri Mustika ', '2025-12-19 16:16:09', 'mohon diperbaiki', '8890', 'sudah selesai dikerjakan', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-19 14:56:40', 10118),
