('C251219004', 10, 20, 'Trusmiland 5', 'G29', 'CS2509100044', 'Abdul holik', 'Infrastruktur', 'Mohon perbaikan untuk pengajuan komplain setelah afyersales banyak yg belum sesuai, Cat tembok bawah jendela depan mengelupas, \r\nTembok pintu kamar mandi gompal, \r\nGenteng di kamar utama tidak rata/ jeblos, \r\nKeramik di teras depan retak dan nat tidak rapat, \r\nPemasangan kilometer PAM belum terpasang, \r\nAtap depan kamar utama berjamur, \r\nTembok bawah kamar utama ada rembesan air, \r\nSaluran pembuangan air belum ditembuskan ke selokan, \r\nPintu kamar mandi bolong / rusak, \r\nPipa air PAM belum terpasang.', 6, 100, 2, 4, '2025-12-22 16:24:05', '2026-01-17 23:00:00', '2026-01-17', '2025-12-26 08:45:24', NULL, NULL, '2025-12-19 18:33:25', 5428, NULL, NULL, NULL, '2025-12-22 08:51:18', 10118, 'SHELYA AYUDHA', 'Perbaikan Aftersales banyak yang belum dikerjakan. Mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-12-22 16:35:07', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 08:46:39', 10118),
('C251219005', 8, 53, 'Indramayu 2 (Margadadi)', 'F55', 'CS2509110056', 'Sayyidatus Sadiyah', 'KWH Listrik', 'Harap disegerakan pemasangan listrik ', 6, 100, 3, 3, '2025-12-24 19:13:58', '2026-02-09 23:00:00', '2026-02-09', '2026-02-14 19:41:28', NULL, NULL, '2025-12-19 19:39:06', 5428, NULL, NULL, NULL, '2025-12-22 13:37:31', 10118, 'SHELYA AYUDHA', 'Mohon segera dilakukan pemasangan KWH Listrik', 8066, 'Larson Mario', '2025-12-24 19:14:34', 'Dalam proses, mohon ditunggu', '369', 'tgl 14 blm terpasang, suda melakukan konfirmasi dari PLN akan dilakukan pemasangan tgl 15 feb 2026', '', 1, 2, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 08:53:02', 10118),
('C251220001', 18, 0, '', '', '', '@betsyafifah', 'After Sales', 'Tembok rumah saya udh pd retak dan ambrol, plafon udah rubuh. Padahal baru 3th. Ada garansi?', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-20 05:23:50', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera cek kondisi rumah konsumen dan verifikasi garansi. Jika masih dalam masa garansi, atur perbaikan gratis secepatnya.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251220002', 10, 53, 'Indramayu 2 (Margadadi)', 'H114', 'CS2411280209', 'Wiwiek rizki', 'Aftersales', 'Sudah selesai perbaikan aftersales tapi masih ada yang belum diperbaiki, dibagian depan gerbang tidak bisa kekunci dengan baik, atap rumah bagian depan ada yang miring, di kamar depan bagian plafon ada retak rambut, kamer belakang masih ada sisa rembesen air, sama dibagian tembok belakang kotor cat tidak rata', 6, 100, 2, 4, '2025-12-22 16:35:22', '2026-01-17 23:00:00', '2026-01-17', '2026-01-17 14:40:11', NULL, NULL, '2025-12-20 10:27:34', 5428, NULL, NULL, NULL, '2025-12-22 08:57:13', 10118, 'SHELYA AYUDHA', 'Perbaikan Aftersales belum selesai. Mohon untuk dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2025-12-22 16:35:55', 'mohon diperbaiki', '2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 08:54:53', 10118),
('C251221001', 18, 0, '', '', '', '@yoga_adprtm', 'Infrastruktur', 'Min tolong pengawasan proect di lapangannya dong. Dawuan c36. Itu udah sampe gegunung. MIRING BANGUNANNYA. Nyerong (mengerucut).\n\nTolong follow up ke bagian lapangannya. Ini saya gamau lanjut klo STRUKTUR nya aja fatal spt ini.', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-21 14:20:35', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera kirim tim inspeksi ke lokasi Dawuan c36 untuk mengecek kondisi struktur bangunan. Laporkan hasil inspeksi dan ambil langkah perbaikan segera jika ditemukan cacat struktural.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C251221002', 5, 34, 'Trusmiland Caracas', 'D52', 'CS2509130101', 'Eko Wahyu Rohadi', 'Artesis', 'Kapang dipasang air? Sudah hampir satu bulan pasca akad dan terima kunci? Kemarin janji minggu beres. Saya cek blm ada pengerjaan sama sekali? Jadinya bisa selsei kapan? Kenapa janji minggu selesei kalo gak sanggup ngerjain. Mana posisi tanag aer di dpn carpo. Ini meteran mau dipasang depan carpot? Apa gak ke lindes motor or mobil?', 6, 100, 1, 4, '2025-12-24 19:09:10', '2026-01-07 23:00:00', '2026-01-07', '2026-01-05 16:31:57', NULL, NULL, '2025-12-21 16:13:27', 5428, NULL, NULL, NULL, '2025-12-22 13:17:03', 10118, 'SHELYA AYUDHA', 'Mohon dicek kapan pemasangan air nya', 8066, 'Larson Mario', '2025-12-24 19:13:30', 'Sudah tercopy ke PIC, masih dalam proses, mohon ditunggu', '369', 'sudah terpasang meteran dan perbaikan pipa di carport', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 09:03:50', 10118),
('C251221003', 8, 29, 'Trusmiland Dawuan', 'B12', 'CS2508250072', 'Nurul aeni', 'Aftersales', 'Listrik ditak nyala, di kilometer tidak ada mcbnya', 6, 100, 3, 3, '2025-12-22 14:55:26', '2025-12-31 23:00:00', '2025-12-31', '2026-01-02 17:07:28', NULL, NULL, '2025-12-21 17:46:41', 5428, NULL, NULL, NULL, '2025-12-22 09:46:18', 10118, 'SHELYA AYUDHA', 'MCB pada kilometer KWH tidak ada. Mohon untuk dicek kembali', 8066, 'Larson Mario', '2025-12-22 14:56:24', 'Disampaikan ke pic untuk di proses, mohon ditunggu', '369', 'sudah disetting kwhnya', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 09:06:24', 10118),
('C251221004', 10, 53, 'Indramayu 2 (Margadadi)', 'H17', 'CS2505270157', 'Niawati Halim', 'Infrastruktur', 'Bagian Depan :\r\n1. Pagar belum dipasang\r\n2. Ada kerusakan tembok dibagian dudukan pagar\r\n3. Tembok pembatas blok H16 & H17 retak dan goyang\r\n4. Atap antara blok H16 & H17 hancur\r\n5. Dinding Kamar bagian depan warnanya tidak rata\r\n\r\nBagian dalam :\r\n1. Slot gagang pintu depan rusak\r\n2. Daun pintu depan rusak, banyak dempul dimana mana, dan dibagian bawah tripleknya sudah terbuka\r\n3. Saklar on/off miring\r\n4. Ada 1 keramik dibagian ruang tengah kopong, ketika diinjak bunyi\r\n5. Pintu toilet gesrek\r\n6. Daun pintu toilet rusak\r\n7. Tembok bagian frame pintu toilet tidak simetris\r\n8. Tembok antara pintu toilet & pintu belakang kasar\r\n9. Daun pintu kamar belakang kasar\r\n', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-21 19:47:56', 5428, NULL, NULL, NULL, '2025-12-22 13:39:26', 10118, 'SHELYA AYUDHA', 'Dialihkan untuk mengajukan Aftersales terlebih dahulu', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, 'https://drive.google.com/drive/folders/1JpZoVNKtwmMVnP2LfTay_9cJdANx9KVM', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 09:07:47', 10118),
