('C251222002', 10, 19, 'RN Kayangan', 'J25', 'CS2403240063', 'MAULANA ISHAQ', 'Progres Bangunan', '\r\nplapon hampir ambruk,tembok ruang tamu sekelilingnya retak parah,kamar jga pda retsk semua,keramik ngangkat dan pda pecah,kamar mandi keramik tembok jg temboknya copot,jga  wcnya keramiknya pda pecah dinding jg retak,dari kamar mandi sebelah rembes masuk kamar belakang,halaman dan garasi tanahnya amblas, di atas kamar mandi plafon retak ', 6, 100, 2, 4, '2025-12-27 14:15:06', '2026-02-07 23:00:00', '2026-02-07', '2026-02-07 21:46:58', NULL, NULL, '2025-12-22 11:51:12', 5428, NULL, NULL, NULL, '2025-12-26 14:49:57', 10118, 'SHELYA AYUDHA', 'Mohon dicek apakah konsumen masih dapat garansi perbaikan atau tidak', 2951, 'Teuku Raja Sri Mustika ', '2025-12-27 14:15:45', 'mohon diperbaiki', '1637', 'pekerjaan utama sudah selesai sisa finishing', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-23 09:14:48', 10118),
('C251222003', 4, 20, 'Trusmiland 5', 'R16', 'CS220808180', 'Nurhidayat, S.I.Kom', 'Infrastruktur', 'Tolong tanggungjawabnya, masalah banjir di Trusmiland Klayan 5 sudah meresahkan warga. Di Blok S, Blok K, LM, HIJ , kemarin saat hujan besar air menggenang di jalan sampai setinggi lutut. \r\nPerlu penanganan dengan cara:\r\n1. Penin jalan/paving di blok yang jalannya rendah\r\n2. Perlu peninggian dan peningkatan kualitas turap\r\n3. Perlu memaksimalkan gorong-goronh agar air hujan tidak menggenang.\r\n\r\nKami khawatir kalau hujan deras lg selalu terjadi banjir.', 6, 100, 2, 4, '2025-12-23 15:21:50', '2025-12-31 23:00:00', '2025-12-31', '2025-12-30 10:08:29', NULL, NULL, '2025-12-22 14:57:50', 5428, NULL, NULL, NULL, '2025-12-23 10:15:10', 10118, 'SHELYA AYUDHA', 'Mohon untuk ditindaklanjuti agar dapat mengurangi kebanjiran yang terjadi', 2951, 'Teuku Raja Sri Mustika ', '2025-12-23 15:22:40', 'Mohon diperbaiki', '8888', 'sudah selesai dikerjakan untuk peninggian turap', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-23 09:16:13', 10118),
('C251222004', 10, 61, 'Bekasi 2 (Sukajadi)', 'D08', 'CS2410160187', 'Puguh', 'Aftersales', '1. Pintu pagar lubang kunci tidak pas\r\n2. Kunci pintu depan rusak\r\n3. Tanah turun sekitar spite tank (perlu ditimbun rata)\r\n4. Slot kunci kamar 1 sebelah kiri (jika berhadapan dengan rumah) terkunci sekali\r\n5. Pemasangan lubang kunci slot (kamar 1/ kiri) tidak rapi\r\n6. Pemasangan lubang kunci slot (kamar 2/ kanan) tidak rapi\r\n7. Pemasangan lubang kunci slot (pintu depan) tidak rapi\r\n8. Pemasangan shocket lampu depan tidak kencang\r\n9. Pemasangan shocket lampu belakang tidak kencang\r\n10.Belakang pintu kamar 2/ kanan pecah\r\n11.Kriplek depan pintu kamar 1/ kiri kurang rapi\r\n12. Saluran air PAM untuk kamar mandi belum tersambung\r\n13.Rumput liar tumbuh lebat', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-22 17:06:17', 5428, NULL, NULL, NULL, '2025-12-23 14:37:55', 10118, 'SHELYA AYUDHA', 'Double input komplainan. Konsumen sedang melakukan Aftersales', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-23 09:19:24', 10118);
