('C251230001', 10, 53, 'Indramayu 2 (Margadadi)', 'F25', 'CS2505080083', 'Noviawati', 'KWH Listrik', 'Pengait kabel PLN membuat atap/genteng rusak', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 09:52:37', 5428, NULL, NULL, NULL, '2025-12-31 09:38:46', 10118, 'SHELYA AYUDHA', 'Mohon maaf, komplainan Kakak dengan ID Complain C251230001, kami reject karena Kakak tidak mengajukan Aftersales. Berdasarkan ketentuan perusahaan yang berlaku, pengajuan perbaikan pada web complain hanya dapat diklaim saat konsumen sudah melakukan Afters', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 15:23:09', 10118),
('C251230002', 3, 53, 'Indramayu 2 (Margadadi)', 'H39', 'CS2410200251', 'Ridwan Fauzi', 'KWH Listrik', 'KWH Listrik belum terpasang ', 6, 100, 2, 3, '2025-12-31 15:01:26', '2026-01-05 23:00:00', '2026-01-05', '2026-01-05 17:20:06', NULL, NULL, '2025-12-30 10:11:50', 5428, NULL, NULL, NULL, '2025-12-31 09:43:26', 10118, 'SHELYA AYUDHA', 'MCB di dalam rumah belum dipasang. Mohon untuk dicek kembali. ', 2951, 'Teuku Raja Sri Mustika ', '2025-12-31 15:01:57', 'mohon diperbaiki', '8890', 'mcb sudah terpasang', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 15:26:21', 10118),
('C251230003', 1, 53, 'Indramayu 2 (Margadadi)', 'H29', 'CS2507160288', 'MOKHAMAD ISYA ANSORI', 'Kunci Rumah', 'Ada nomor pusat Ningrat yg bisa di hubungi, \r\n\r\nKarena kalopun datang ke galeri marketing Indramayu percuma, \r\nJawaban nya selalu sama masih dalam proses QC\r\n\r\nIni sudah berjalan cicilan 3.bln \r\nYg lain sudah Terima kunci\r\nBahkan ada juga yg sudah di tempati\r\n\r\nPadahal kan kondisi dan ke adaan sama toh, \r\n\r\nLalu apa yg di bedakan,', 6, 100, 3, 4, '2025-12-31 10:38:56', '2026-01-10 23:00:00', '2026-01-10', '2026-01-10 11:15:05', NULL, NULL, '2025-12-30 10:50:25', 5428, NULL, NULL, NULL, '2025-12-30 16:17:16', 10118, 'SHELYA AYUDHA', 'Mohon dicek kendalanya', 2951, 'Teuku Raja Sri Mustika ', '2025-12-31 10:39:51', 'sedang dalam proses perbaikan qc', '7972', 'kunci sudah diserahkan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 15:37:41', 10118),
('C251230004', 10, 20, 'Trusmiland 5', 'F36', 'CS2505140034', 'Jamal Hariri S T', 'Aftersales', 'Keluhan :\r\n1. isian banyak yg kopong/berongga mengakibatkan kramik banyak yg pecah\r\n2. lantai ruang tegah/tamu terjadi peningkatan volume mengakibatkan lantai kramik bergelombang\r\n3. Sering terjadi kebocoran ketika turun hujan di posisi kamar 2/kamar belakang, mengakibatkan atap berjamur dan tembok lembab\r\n4. cek tembokan diatas (skat antara rumah 36 dan 37) sudah rapuh dan yg belakang hanya dibiarkan menganga sehingga air masuk kedalam rumah\r\n5. dinding tembok kamar 1 lembab dan cat mengelupas mengakibatkan dinding berjamur\r\n6. cat dinding depan rumah mengelupas dan berjamur', 6, 100, 2, 4, '2025-12-31 10:36:47', '2026-01-30 23:00:00', '2026-01-30', '2026-01-30 09:23:01', NULL, NULL, '2025-12-30 15:54:04', 5428, NULL, NULL, NULL, '2025-12-30 16:30:26', 10118, 'SHELYA AYUDHA', 'Mohon untuk dicek dan diperbaiki', 2951, 'Teuku Raja Sri Mustika ', '2025-12-31 10:37:48', 'mohon diperbaiki', '168,2842', 'Pekerjaan perbaikan sudah selesai', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 16:29:11', 10118),
('C251230005', 1, 29, 'Trusmiland Dawuan', 'C40', 'CS2510120267', 'MOHAMAD NOOR FADHLI', 'Kunci Rumah', 'Rumah Blok C40 sudah selesai pembangunan, kira kira untuk penyerahan kunci dan pompa air kapan ya? mohon di percepat untuk proses penyerahan kunci', 6, 100, 3, 4, '2025-12-31 11:12:05', '2026-01-12 23:00:00', '2026-01-12', '2026-01-12 17:05:48', NULL, NULL, '2025-12-30 16:04:55', 5428, NULL, NULL, NULL, '2025-12-30 16:32:46', 10118, 'SHELYA AYUDHA', 'Mohon untuk dicek terkait kendala penyerahan kunci', 2951, 'Teuku Raja Sri Mustika ', '2025-12-31 11:51:41', 'mohonn diserahkan', '7972', 'Kunci lengkap 12', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-30 16:31:41', 10118),
