('C251231009', 10, 53, 'Indramayu 2 (Margadadi)', 'H101', 'CS2505200420', 'Iis Dania', 'Infrastruktur', 'Pengerjaan masih rembes di plafond kamar 2,\r\nCat pintu depan kurang tebal dan rapih\r\nJendela di depan kamar 1 tidak bisa dikunci 1 kaca\r\nGerbang depan nyender', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-31 18:05:46', 5428, NULL, NULL, NULL, '2026-01-02 09:29:23', 10118, 'SHELYA AYUDHA', 'Double input. Perbaikan Aftersales sedang On Progress.', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-02 08:47:35', 10118),
('C251231010', 17, 53, 'Indramayu 2 (Margadadi)', 'H35', 'CS2504300347', 'ACHMAD SUHADA', 'Penjualan/Mkt (Area Indramayu, Bekasi, Kendal)', 'Masalah angsuran yg telat \r\nJadi gini pak/buk kan setelah tuh kebanyakan udh pada Nerima kunci/unit nya ini kan blm setelah akad blm Nerima kunci bakan rumah juga blm jadi \r\n  Nah harusnya begitu akad truss bulan depan nya udh mulai angsuran pertama saya mah blm bayar \r\n  Soalnya dpt omongan dari marketing nya kalo udh Akad truss rumah blm di tempatin atau blm Nerima kunci angsuran bakal di tanggung sama developer nah jadikan saya santai ya\r\nEh ga tau nya skarang angsuran katanya cuma masuk bulan 10 nya aja bulan 11 sama 12 nya blm \r\n Saya sih ga masalahin yg angsuran bulan 12 mah karna saya juga Nerima kunci nya di tanggal 24-12-2025 \r\n Angsuran jatuh tempo pada setiap 23\r\n\r\n  Jadi menurut bapak/ibu itu gmna soalnya org dari pihak bank maupun dari rumah ningrat nya juga kan selalu WA ke saya \r\n\r\n', 6, 100, 3, 2, '2026-01-03 17:38:57', '2026-01-05 23:00:00', '2026-01-05', '2026-01-05 16:35:01', NULL, NULL, '2025-12-31 18:27:17', 5428, NULL, NULL, NULL, '2026-01-02 15:47:44', 10118, 'SHELYA AYUDHA', 'Mohon untuk dijelaskan kembali kepada konsumen', 476, 'Angga Prabowo ', '2026-01-03 17:40:41', '1. Tolong cari tahu terlebih dahulu salesnya siapa, dan bagaimana kronologis saat memberikan informasi terhadap konsumen\n2. Coba bantu komunikasikan dengan pihak bank terkait kendala tersebut', '3013', 'Dilakukan pengajuan subsidi cicilan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-02 08:54:16', 10118),
('C251231011', 10, 20, 'Trusmiland 5', 'F29', 'CS2505160338', 'Ahmad faisal', 'Progres Bangunan', 'Ngerembes klo hujan, trs air masuk ke dalam rumah. Karna latar depan nya tinggi kya bukit', 3, 0, 3, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-31 18:31:15', 5428, NULL, NULL, NULL, '2026-01-02 13:57:32', 10118, 'SHELYA AYUDHA', 'Mohon maaf. Berdasarkan ketentuan perusahaan, syarat garansi perbaikan dapat diklaim adalah konsumen telah mengajukan perbaikan Aftersales setelah serah terima kunci. Apabila konsumen tidak mengajukan perbaikan Aftersales, maka garansi tidak dapat diklaim', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-02 09:30:54', 10118),
('C251231012', 18, 0, '', '', '', '@suss4883', 'Infrastruktur', 'Harus renovasi depan belakang kanopi n pagar belum dipasang', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2025-12-31 22:46:46', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera jadwalkan renovasi kanopi dan pemasangan pagar di bagian depan dan belakang sesuai kebutuhan konsumen. Koordinasikan dengan tim lapangan untuk pengerjaan dan pastikan material tersedia.', NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.instagram.com/p/DM3ZihLAbxj/', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
