('C260110001', 1, 53, 'Indramayu 2 (Margadadi)', 'G93', 'CS2507280138', 'Nela Nifa Nafilah', 'Kunci Rumah', 'Sudah akad rumah dari Oktober 2025 tapi belum terima kunci, di sistem progres rumahnya sudah 100%. Mohon dipercepat untuk pemasangan listrik dan air nya, terima kasih.', 6, 100, 2, 4, '2026-01-12 16:45:35', '2026-01-31 23:00:00', '2026-01-31', '2026-01-30 09:56:31', NULL, NULL, '2026-01-10 07:57:34', 5428, NULL, NULL, NULL, '2026-01-10 13:59:42', 10118, 'SHELYA AYUDHA', 'Mohon dicek kapan konsumen dapat serah terima kunci karena sudah akad sedari Oktober', 2951, 'Teuku Raja Sri Mustika ', '2026-01-12 16:46:42', 'mohon diserahkan dan dipercepat pemasangan listrik dan airnya', '7972', 'kunci sudah diserahkan ke marketing', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-10 10:57:22', 10118),
('C260110002', 10, 40, 'Arjawinangun ByPass', 'D77', 'CS2508270068', 'Meki Maizi Putra', 'Aftersales', 'assalamualikum pak tolong bantu saya pak \r\nsaya minta uversal aja pak tukang nya pak yasin aj klw yang lain percuma ya pak kerja ny ga ada benar pak\r\n- Pagar sebaelah kiri roboh \r\n- teras depan kramik di bokar \r\n- ruang tamu semua kramik di bongkar \r\n- kamar 1 dan Kamar 2 Kramik di bongkar\r\n- wc kramik di bongkar\r\n- diding di kamar 2 masih banyak yang retak dan cat mengelupas \r\nTolong cepat di beresin supaya saya bisa nempatin rumah nya karna kontrakan jalan trus saya mintak uversal tukang nya pak yasin aja pak', 8, 65, 2, 4, '2026-01-12 16:47:03', '2026-02-28 23:00:00', '2026-02-28', NULL, NULL, NULL, '2026-01-10 11:34:38', 5428, NULL, NULL, NULL, '2026-01-10 13:54:21', 10118, 'SHELYA AYUDHA', 'Perbaikan Aftersales belum selesai. Mohon dicek kembali', 2951, 'Teuku Raja Sri Mustika ', '2026-01-12 16:47:36', 'mohon diperbaiki', '168', 'Proses pemasangan sudutan kramik', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-10 13:53:33', 10118),
