('C260110004', 10, 15, 'Trusmiland Tengah Tani', 'F05', 'CS2412160242', 'Arief Maulana', 'Aftersales', 'Plafon sudah pada jebol dan bocor dari talang air tembok pada ngerembes saat hujan cat tembok pada ngelupas banyak yang harus diperbaikan tolong kalo bisa di after sales lagi pada rusak semua belum ada 1 tahun nungguin rumah udah ada aja perbaikan mohon dari pihak trusmiland meninjau kerumah saya blok F05 trusmiland perumahan lovine ', 8, 0, 2, 4, '2026-01-12 16:48:14', '2026-02-28 23:00:00', '2026-02-28', NULL, NULL, NULL, '2026-01-10 13:41:29', 5428, NULL, NULL, NULL, '2026-01-10 14:06:10', 10118, 'SHELYA AYUDHA', 'Mohon dicek dan diperbaiki ', 2951, 'Teuku Raja Sri Mustika ', '2026-01-12 16:48:45', 'mohon diperbaiki', '168', 'Mpp masih mengerjakan unit lain', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-10 14:04:17', 10118),
