('C260116003', 10, 34, 'Trusmiland Caracas', 'F34', 'CS2310300028', 'Jaenudin', 'Infrastruktur', 'Mengalami kebocoran terus di ruang tamu dan kamar belakang ????sudah d perbaiki sendiri tapi ttep saja bocor lagi udah kaya air terjun????', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-16 18:33:03', 5428, NULL, NULL, NULL, '2026-01-17 10:13:10', 10118, 'SHELYA AYUDHA', 'Mohon maaf. Sesuai ketentuan perusahaan, terkait garansi perbaikan sudah tidak bisa diklaim lagi karena sudah lebih dari setahun sejak tanggal serah terima kunci. ', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-17 10:07:17', 10118),
