('C260117002', 10, 42, 'RN Kendal', 'B39', 'CS2503300204', 'Kristanto', 'Progres Bangunan', 'Kamar depan dan kamar belakang banyak yang bocor parah', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-17 10:48:44', 5428, NULL, NULL, NULL, '2026-01-19 09:04:12', 10118, 'SHELYA AYUDHA', 'Mohon maaf. Sesuai ketentuan perusahaan, garansi perbaikan dapat diklaim dengan syarat konsumen telah mengajukan perbaikan aftersales setelah serah terima kunci. Apabila konsumen tidak mengajukan perbaikan Aftersales maka garansi perbaikan tidak dapat dik', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-19 09:01:46', 10118),
('C260117003', 10, 20, 'Trusmiland 5', 'G16', 'CS2506070061', 'Cakido', 'Progres Bangunan', 'Saya sudah habis lebih dari 10 juta untuk memperbaiki rumah ini. Mohon dibantu tanggung jawabnya karena saya sama sekali belum menempati rumah ini:\r\n1. Plafon area toilet Bocor + cat ulang\r\n2. Plafon area kamar sebelah kanan bocor + cat ulang\r\n3. Plafon area kamar sebelah kiri Bocor + cat ulang\r\n4. Ruang tamu , tembok retak\r\n5. Area pagar pada ambrol, dan batas dg tetangga tidak jelas ....\r\n6. Area tampak depan bocor , atap harus di semen\r\n7. Cat tembok area depan terkelupas\r\n8. Genteng di rapih, alias pada ambles\r\n9. Keramik area depan pada retak\r\n10. Selokan atau pembuat air Toilet tidak keluar alias Mambek\r\n11. Keramik area ruang tamu pada kopong dan retak , alias mau ambles\r\n12. Area toilet , keramik pada ambles...', 4, 0, 2, 4, '2026-01-19 15:57:01', '2026-02-23 23:00:00', '2026-02-23', NULL, NULL, NULL, '2026-01-17 11:08:52', 5428, NULL, NULL, NULL, '2026-01-17 11:17:46', 10118, 'SHELYA AYUDHA', 'Mohon dicek dan diperbaiki terkait kerusakan yang ada', 2951, 'Teuku Raja Sri Mustika ', '2026-01-19 15:57:33', 'mohon diperbaiki', '168,5534', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-17 11:14:59', 10118),
