('C260117010', 10, 53, 'Indramayu 2 (Margadadi)', 'H95', 'CS2502110048', 'Muhamad Salman Zaka Nur Sanjaya', 'Aftersales', 'Pintu depan belum diperbaiki, tapi status komplen sdh selesai dan pintu pagar yang penyok tidak diperbaiki hanya dicat ulang saja, serta ada car tembok yang menggelembung (harus dikupas terlebih dahulu)', 4, 0, 2, 4, '2026-01-20 16:58:16', '2026-02-22 23:00:00', '2026-02-22', NULL, NULL, NULL, '2026-01-17 19:02:24', 5428, NULL, NULL, NULL, '2026-01-19 11:50:01', 10118, 'SHELYA AYUDHA', 'Mohon dicek kembali pengerjaan Aftersalesnya karena banyak yang belum sesuai', 2951, 'Teuku Raja Sri Mustika ', '2026-01-20 16:58:58', 'mohon diperbaiki', '5534', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-19 11:46:27', 10118),
