('C260126004', 18, 0, '', '', '', '@_kyand.bayiberuang_', 'Infrastruktur', 'Setelah banjir surut, aroma selokan tercium sampai dalam rumah.', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-26 07:06:22', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan penyemprotan disinfektan pada area sekitar selokan dan bersihkan saluran air di sekitar rumah konsumen untuk menghilangkan bau tidak sedap.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C260126005', 18, 0, '', '', '', '@dessy_com', 'Infrastruktur', 'Dari eternit bocor, tembok belah, keramik hancur', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-26 07:11:47', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan inspeksi lokasi untuk menilai kerusakan secara menyeluruh. Perbaiki eternit yang bocor, perkuat struktur tembok yang retak, dan ganti keramik yang rusak. Pastikan pekerjaan ini dilakukan oleh tim teknis yang kompeten dan gunakan bahan berku', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
