('C260126007', 18, 0, '', '', '', '@_kyand.bayiberuang_', 'Progres Bangunan', 'Estimasi kapan, Kak? Butuh kepastian, kalau enggak langsung ditangani benar-benar jadi danau ini, Kak.', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-01-26 08:18:10', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera hubungi tim teknis untuk mendapatkan estimasi penyelesaian proyek dan lakukan koordinasi dengan konsumen untuk memberikan kepastian waktu.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
