('C260202004', 10, 20, 'Trusmiland 5', 'I01', 'CS2408270424', 'Ilyasa', 'Rumah dan Bangunan', 'Tembok rembes sama atap plafon bocor ', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-02 11:25:33', 5428, NULL, NULL, NULL, '2026-02-03 14:09:32', 10118, 'Shelya Ayudha', 'Berdasarkan dengan ketentuan perusahaan, syarat klaim garansi perbaikan adalah konsumen telah mengajukan perbaikan Aftersales setelah serah terima kunci . Apabila konsumen tidak mengajukan perbaikan Aftersales setelah serah terima kunci, maka garansi perb', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-02 14:52:42', 10118),
