('C260212005', 18, 0, '', '', '', '@iba.thoyibah', 'After Sales', 'Pas sebelum akad dipastikan nanti setelah akad ga akan sampai 45 hari kalo kebih dari itu dapat subsidi 50% pas udah lebih bilangnyaa ngga bisa dapat subsidi ternyata kalo lebih dari 3 bulan beda2 terus', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-12 10:17:43', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Pastikan informasi tentang subsidi dan batas waktu penyelesaian disampaikan dengan jelas dan konsisten kepada konsumen sebelum akad. Lakukan pengecekan timeline penyelesaian proyek dan komunikasikan secara transparan jika ada keterlambatan serta pastikan ', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C260212006', 18, 0, '', '', '', '@iba.thoyibah', 'Progres Bangunan', 'Progres udah lebihhh dari 45 hari', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-12 10:18:08', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Periksa jadwal proyek dan evaluasi hambatan yang terjadi, kemudian buat rencana percepatan dengan menambah sumber daya atau mengoptimalkan proses agar progres sesuai target.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C260212007', 10, 34, 'Trusmiland Caracas', 'B20', 'CS2408030231', 'Riki', 'Estate', '1. Carport retak \r\n2. Kamar 2 plafond jatuh sama rembes\r\n3. Bagian luar nya rembes\r\n4. Ruang tamu tembok nya rembes dari atas, bawah sampai ke lantai\r\n5. Ruang dapur tembok rembes sama atap nya\r\n6. Kamar mandi rembes bagian atap nya', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-12 14:32:50', 5428, NULL, NULL, NULL, '2026-02-14 08:46:58', 10118, 'Shelya Ayudha', 'Double input dengan komplain sebelumnya', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 08:40:36', 10118),
('C260212008', 18, 0, '', '', '', '@iba.thoyibah', 'Progres Bangunan', 'Iya ka sebelum akad dia bilangnya kayagitu terus januari udah bisa ditempatinya \nTernyata sampai februari masih kayagitu progresnya kecewa 😭😭', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-12 14:35:13', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', '1. Hubungi tim proyek untuk cek progres terkini. 2. Informasikan update progres dan jadwal realistis ke konsumen. 3. Koordinasi percepatan pengerjaan jika memungkinkan. 4. Berikan kompensasi atau solusi jika keterlambatan tetap terjadi. 5. Jaga komunikasi', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
