('C260212016', 10, 53, 'Indramayu 2 (Margadadi)', 'H01', 'CS2505220078', 'Nuryadi', 'Infrastruktur', 'minta pertanggung jawaban ini rumah saya cash keras blok H01 kesenggol excavator, bagian pinggir ruag tamu tembok samping langsung retak', 6, 100, 2, 4, '2026-02-14 11:09:11', '2026-02-21 23:00:00', '2026-02-21', '2026-02-21 13:59:55', NULL, NULL, '2026-02-12 17:10:25', 5428, NULL, NULL, NULL, '2026-02-14 09:12:46', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti karena kerusakan terjadi karena pihak excavator yang tidak hati hati', 2951, 'Teuku Raja Sri Mustika ', '2026-02-14 11:09:35', 'mohon diperbaiki', '8890', 'sudah di perbaiki dengan konsumen sendiri', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 09:08:33', 10118),
('C260212017', 10, 90, 'RN Sampora', 'I24', 'CS2503200027', 'Jaka Ardian', 'Rumah dan Bangunan', 'pada saat hujan gede bocor  ruang tamu kamar 2 kmr mandi dn dapur, sblumnya g bocor hr ini parah bocornya banyak tetesan air dari atas, kamar 1 plafon atap jamuran , akibat tetesan air ahirnya becek banjir msuk terus\"san  airhujan. jd mengakibatkan kasur barang\"  dsb spt pakaian pada lembab jamuran. platon jamuran apkah bisa dicat ga dari komplen tersebut? ', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-12 19:27:04', 5428, NULL, NULL, NULL, '2026-02-14 09:50:20', 10118, 'Shelya Ayudha', 'Double input dengan komplain sebelumnya', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 09:18:07', 10118),
('C260213001', 18, 0, '', '', '', '@pera_pera18', 'Infrastruktur', 'Assalamu\'alaikum pak punten menggangu waktunya. Saya warga trusmiland klayan tahap 5 blok J16. Ini gimna kebanjiran terus rumahnya, mending banjirnya cuma dijalan doang ini masuk rumah pak, kasur pada basah. Cape hati pikiran sama tenaga juga harus tiap minggu bersihin lumpur bekas banjir. \nMana dulu pas ngambil dpnya mahal 12jt belum sama shm belum sama materai kurang lebih habis 15jtan.\nMana DP mahal kebanjiran pula, terus ini keramiknya pada ngangkat pa jadi keluar air dari sela2 keramik. \nMau minta garansinya mau ditinggiin keramik rumahnya biar ga kebanjiran terus. Saya harap dm nya di baca dan garansinya bisa segera di acc, terimakasih 🙏', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-13 11:19:34', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera koordinasikan dengan tim teknis untuk inspeksi lokasi kebanjiran dan keramik terangkat, lakukan evaluasi sistem drainase dan kondisi lantai, siapkan perbaikan dan usulan peninggian keramik sesuai garansi. Sampaikan update ke konsumen secara berkala', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C260213002', 4, 20, 'Trusmiland 5', 'J16', 'CS2408110168', 'Vicky Septian', 'Rumah dan Bangunan', 'Rumah saya kebanjiran airnya masuk rumah. Waktu ngambil dp nya mahal sekitar 12jtan belum termasuk shm dll. Mana dp mahal kebanjiran pula. Yang orang lain dpnya cuma 2jtan itu free pagar mana keramik d ganti semua. Yang saya tidak. \r\nSekarang mau minta garansi keramik di tinggiin diganti semua biar air ga masuk rumah. Soalnya air juga ada yang masuk lewat sela2 keramik juga dari sawah belakang. Mohon segera ditindak lanjuti', 5, 0, 3, 0, '2026-02-18 21:41:43', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2026-02-13 13:56:33', 5428, NULL, NULL, NULL, '2026-02-16 16:31:12', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti terkait kebanjiran yang terjadi', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 21:42:21', 'Terkait banjir, kami sedang menangani di blok RS dan HIJ,\n\nDan kami akan evaluasi hasil perbaikanya untuk tau hasilnya apakah efektif atau tidak.\n\nKami akan segera kaji kembali terkait komplainan bapak/ibu.\n\nMohon maaf dan terimakasih atas pengertianya', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 10:01:41', 10118),
('C260213003', 4, 56, 'RN Majalengka 2', 'B54', 'CS2504120113', 'Daniel Kris hamonangan', 'Rumah dan Bangunan', 'teras dan carport kebanjiran karena selokan tertutup material. tolong bersihkan teras dan carport terdampak banjir dan pemindahan material yang menutup selokan. terima kasih.', 6, 100, 2, 4, '2026-02-14 11:11:05', '2026-02-21 23:00:00', '2026-02-21', '2026-02-18 13:33:25', NULL, NULL, '2026-02-13 14:06:24', 5428, NULL, NULL, NULL, '2026-02-14 10:09:59', 10118, 'Shelya Ayudha', 'Mihon untuk ditindaklanjuti', 2951, 'Teuku Raja Sri Mustika ', '2026-02-14 11:12:28', 'mohon diperbaiki', '8888', 'sudah selesai dikerjakan', '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 10:06:16', 10118),
('C260213004', 10, 77, 'Pabedilan', 'F29', 'CS2412050301', 'Buyung Arifin', 'Aftersales', '1. Kamar 1 masih bocor\r\n2. Kamar 2 bocor\r\n3. Jendela tidak bisa di tutup di kamar 2', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-13 15:31:26', 5428, NULL, NULL, NULL, '2026-02-14 11:30:48', 10118, 'Shelya Ayudha', 'Double input dengan pengajuan perbaikan Aftersales', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 10:15:00', 10118),
('C260213005', 4, 70, 'RN Jayasampurna', 'G14', 'CS2408270164', 'Mohammad saef agus', 'Infrastruktur', 'APAKAH JALAN SEPERTI INI LAYAK?\nAPAKAH HARUS NUNGGU WARGA JATUH TERUS DI PERBAIKI?\nAPAKAH HARUS DI KOMPLAIN TERLEBIH DAHULU TERUS DI PERBAIKI?\n\nINGET SEKARANG RUMAH NINGRAT JAYASAMPURNA 3 SUDAH ADA WARGA NYA BUKAN HANYA SALES ATAU TUKANG BANGUNAN AJA!!!', 5, 0, 3, 0, '2026-02-14 13:29:38', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2026-02-13 16:47:29', 5428, NULL, '2026-02-13 16:47:29', NULL, '2026-02-14 10:54:22', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti. Walaupun jalur logistik sedang dibuat tapi alangkah baiknya dibuatkan jalur khusus motor yang layak jalan karena jika jalan tersebut terus berlumpur maka akan sangat membahayakan warga ', 2951, 'Teuku Raja Sri Mustika ', '2026-02-14 13:30:55', 'mohon maaf bapak/ibu kondisi jalan di depan g14 dalam kondisi layak', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 10:37:30', 10118),
