('C260213012', 4, 15, 'Trusmiland Tengah Tani', 'A20', 'CS221119001', 'Emon Endang Suryawiratno', 'Infrastruktur', 'Sudah pertengahan bulan februari mushola dan musholla kapan dimulai pembangunan. ', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-13 20:05:44', 5428, NULL, NULL, NULL, '2026-02-14 11:11:58', 10118, 'Shelya Ayudha', 'Izin menginfokan terkait pembangunan Masjid/Musholla pada Trusmiland Tengah Tani. Info dari tim terkait, sudah masuk plan infrastruktur akhir februari 2026. Adapun deadline penyelesaiannya di tanggal 31 Maret 2026 ????', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 11:07:55', 10118),
('C260213013', 4, 20, 'Trusmiland 5', 'K50', 'CS2508300025', 'Sri Ainun Hardiyanti', 'Rumah dan Bangunan', 'Alooo min. Mengenai bencana banjir tolong dong jgn yg d respon di BLOK RSHIJ AJA. BLOK K GE SAMA KENA BANJIR MIN. MASAIYA CM KARNA GA SPEAK UP D MEDSOS AJA GA SAMA PENANGGULANGAN BANJIRNYA????. BLOK K PALING UJUNG YG TERDAPAK BANJIR PALING PARAH DRPD BLOK K DEPANNYA. TANAH GE GA SAMA TOLONG YAA BANTU PERBAIKI', 4, 0, 2, 4, '2026-02-18 17:07:23', '2026-03-31 23:00:00', '2026-03-31', NULL, NULL, NULL, '2026-02-13 20:28:52', 5428, NULL, NULL, NULL, '2026-02-14 11:23:57', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti terkait kebanjiran yang terjadi di blok K Trusmiland Klayan 5', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 17:08:11', 'sedang dimaping untuk penanganannya', '8889', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 11:22:07', 10118),
('C260213014', 10, 56, 'RN Majalengka 2', 'B14', 'CS2410130320', 'MUHAMAD NAHROWI ST', 'Aftersales', 'Genteng kamar belakang ambruk menimpa plafon dan jebol. Sejak 9 November 2026 saya komplen melalui marketing (Pak Romy Kris) dan pengawas lapangan (Pak Yagung) tapi sampai sekarang (3 bulan lebih) belum diperbaiki. Air hujan masuk ke dalam rumah (kamar belakang). \r\nSaluran air bersih/pipa dari pompa ke kran kamar mandi dan teras depan bocor. Setiap isi toren tanpa buka kran toren jadi kosong. ', 4, 0, 3, 4, '2026-03-28 15:58:03', '2026-04-06 23:00:00', '2026-04-06', NULL, NULL, NULL, '2026-02-13 22:59:36', 5428, NULL, NULL, NULL, '2026-02-16 16:34:30', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 15:58:48', 'mohon diperbaiki', '5534', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 11:26:42', 10118),
('C260214001', 1, 65, 'TL Cempaka 2', 'F42', 'CS2510190043', 'Riswadi', 'Kunci Rumah', 'terima kunci rumah lama sekali', 4, 0, 2, 4, '2026-02-18 15:59:23', '2026-02-28 23:00:00', '2026-02-28', NULL, NULL, NULL, '2026-02-14 09:30:38', 5428, NULL, NULL, NULL, '2026-02-14 11:36:04', 10118, 'Shelya Ayudha', 'Mohon ubtuk segera ditindaklanjuti agar konsumen dapat serah terima kunci', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 16:00:11', 'belum lolos qc ', '7972', NULL, '-', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 11:34:01', 10118),
('C260214002', 16, 34, 'Trusmiland Caracas', 'F21', 'CS2405130050', 'Dadan Maulidina', 'Finance', 'Tolong di cek komplain saya di tanggal 7 februari, karena saya ga dapet jawaban sama sekali, kayanya penjelasan saya kurang jelas, jadi gini bapak ibu, saya beli rumah ini tanpa tahu bahwa rumah ini split surat tanah nya, saya tau pada saat akad, itu pun saya tau dari notaris bukan dari karyawan trusmiland caracas, posisi saat itu sudah akad dengan bank, saat saya mau meningkatkan surat saya dari HGB ke SHM saya baru di kasih tau oleh notaris bahwa surat saya split dan otomatis harus membayar 2 surat, jadi saya tidak jadi untuk meningkatkan surat saya ke SHM karena saya tidak tau sebelum nya surat tanah nya split, lalu saya berkoordinasi dengan marketing yang mengurus rumah saya, dan saya juga ke kantor trusmi di cirebon, dua dua nya menjawab hal yang sama, bahwa biasa nya biaya peningkatan SHM untuk yang split 1 surat biaya nya di tanggung oleh perusahaan trusmiland, jawaban komplain saya di tanggal 7, tadi saya lihat menjelaskan bahwa surat itu sudah done, sudah done itu maksud nya apa ?, yang saya tanyakan kelanjutan untuk backup biaya surat tanah saya untuk di tingkatkan ke SHM, kalau memang sudah di backup tolong kirim bukti nya, saya mau meningkatkan ke SHM jadi terkendala karena permasalahan ini tidak kunjung selesai dan lambat sampai sudah mau 2 tahun, tolong beri saya kontak orang yang bisa saya ajak ngobrol', 6, 100, 2, 3, '2026-02-19 16:36:32', '2026-02-23 12:00:00', '2026-02-19', '2026-02-19 20:27:39', NULL, NULL, '2026-02-14 10:18:17', 5428, NULL, NULL, NULL, '2026-02-18 09:49:50', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti terkait biaya peningkatan SHM yang ditanggung developer', 340, 'Muhamad Irfannudin ', '2026-02-19 16:37:28', 'segera komunikasikan konsumen tersebut', '2896,341', 'Akan di lakukan eskalasi lebih lanjut ', '', 1, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 11:42:57', 10118),
('C260214003', 10, 43, 'RN Kaliwadas', 'B29', 'CS2312290012', 'Eni Nuryati', 'Other', 'Area kamar 2 rembes parah, dari plafond sampai ke dinding bawah\r\ndinding belakang tidak menyatu dengan unit lain, dan tidak diplester\r\n', 5, 0, 2, 0, '2026-02-18 09:37:19', '0000-00-00 00:00:00', '0000-00-00', NULL, NULL, NULL, '2026-02-14 13:11:42', 5428, NULL, NULL, NULL, '2026-02-16 10:25:10', 10118, 'Shelya Ayudha', 'Mohon untuk dicek dan diperbaiki terkait rembesan yang terjadi', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 09:38:06', 'sudah lebih dari setahun, dan sudah perbaikan aftersales', '', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:15:01', 10118),
('C260214004', 10, 20, 'Trusmiland 5', 'I09', 'CS2504220212', 'Heri', 'Infrastruktur', 'Tutup spiteng jebol lagi\r\n', 4, 0, 2, 4, '2026-03-28 16:01:13', '2026-04-06 23:00:00', '2026-04-06', NULL, NULL, NULL, '2026-02-14 13:43:19', 5428, NULL, NULL, NULL, '2026-02-16 10:22:37', 10118, 'Shelya Ayudha', 'Mohon untuk dicek dan diperbaiki terkait tutup spiteng yang jebol', 2951, 'Teuku Raja Sri Mustika ', '2026-02-18 16:02:03', 'mohon diperbaiki', '5534', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:16:55', 10118),
('C260214005', 18, 0, '', '', '', '@mohammadfaisal9833', 'Infrastruktur', 'Rumah ningrat, trusmiland klayan cirebon tahap 5 dong minta perbaikannya ini banjir terus, banyak dari kami yang kecewa karna banjirrnya di setiap hujan. Ga ada pembuangannya, lokasi blok rumah lebih rendah dari jalan utama. Yang akhirnya banjir terus', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 14:38:51', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan survei lokasi untuk mengevaluasi sistem drainase dan ketinggian lahan. Koordinasi dengan tim teknis untuk membuat rencana perbaikan drainase dan elevasi tanah agar air bisa mengalir dengan baik dan menghindari banjir.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
('C260214006', 10, 34, 'Trusmiland Caracas', 'E07', 'CS2504100047', 'Rifatun Nisa', 'Rumah dan Bangunan', 'Hampir seluruh pinggiran rumah mengalami kebocoran, sudah dua kali perbaikan.', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-14 16:54:23', 5428, NULL, NULL, NULL, '2026-02-16 12:04:12', 10118, 'Shelya Ayudha', 'Mohon maaf Bapak/Ibu. Berdasarkan ketentuan perusahaan, garansi perbaikan hanya dapat diklaim jika konsumen sudah mengajukan perbaikan Aftersales. Apabila konsumen tidak mengajukan, maka garansi perbaikan tidak dapat diklaim', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:36:17', 10118),
