('C260216001', 10, 20, 'Trusmiland 5', 'G33', 'CS2509090260', 'Muhamad Bayu Pratama', 'Other', 'dalam perbaikan plafond asal asalan ketika hujan kembali bocor dan lebih parah, mohon di bantu semaksimal mungkin', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:22:09', 5428, NULL, NULL, NULL, '2026-02-16 15:32:42', 10118, 'Shelya Ayudha', 'Double input. Pengajuan perbaikan Aftersales masih berstatus \"On Progress\"', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 15:25:33', 10118),
('C260216002', 18, 0, '', '', '', '@dickoagustian', 'After Sales', 'Oke, mohon jangan sampai ada kasus penipuan ya. Dari masalah complain saja bermasalah ini ngga tuntas tuntas kalian . Kalau vendor ga cocok coba tegas ganti vendor nya', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:26:46', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Evaluasi vendor saat ini, jika tidak sesuai standar segera ganti dengan vendor yang lebih kompeten. Perbaiki komunikasi dan tindak lanjut keluhan agar masalah cepat terselesaikan dan hindari risiko penipuan.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
