('C260216004', 10, 90, 'RN Sampora', 'J47', 'CS2501170148', 'Refangga Febriwijaya', 'Estate', 'Minta tolong segera diperbaiki karena di khawatirkan akan bertambah parah rusakanya\r\n1.teras depan retak\r\n2.tembok kamar retak besar \r\n3.plapon atap ruang tamu retak\r\n4.tembok kamar mandi retak besar \r\n5.tembok kamar tidur 1 rembesan ', 3, 0, 4, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 10:45:35', 5428, NULL, NULL, NULL, '2026-02-16 16:14:49', 10118, 'Shelya Ayudha', 'Mohon maaf Bapak/Ibu untuk komplain dengan ID Complain C260216004 saya reject karena akan saya satukan dengan komplain C260117005  agar tidak terjadi double input', 2951, 'Teuku Raja Sri Mustika ', NULL, NULL, NULL, NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 16:05:25', 10118);
