('C260216008', 9, 20, 'Trusmiland 5', 'F43', 'CS2510050313', 'IAN TRIANDANA', 'Estate', 'Halo kak, saya sudah akad dan lagi cek unit tapi pas liat diunit milik saya penempatan tiang listriknya didepan persis pagar rumah saya... dan ini mengganggu, tolong untuk dipindah letak tiang listrik nya, karena ini persis banget didepan pagar, saya mau masuk kerumah juga susah untuk buka handle pagarnya... terimakasih ', 4, 0, 2, 4, '2026-02-18 17:05:47', '2026-03-21 23:00:00', '2026-03-21', NULL, NULL, NULL, '2026-02-16 14:53:17', 5428, NULL, NULL, NULL, '2026-02-16 16:28:28', 10118, 'Shelya Ayudha', 'Mohon untuk ditindaklanjuti', 8066, 'Larson Mario', '2026-02-18 17:06:53', 'disampaikan ke pic untuk komunikasi dengan pln terkait pemindahan tiang, terimakasih', '369', NULL, '', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 16:26:36', 10118),
('C260216009', 18, 0, '', '', '', '@3_yoooo', 'Infrastruktur', 'Di tunggu info selanjutnya ka membahaya rawan terjadi amblas', 1, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16 15:57:03', 9791, NULL, NULL, NULL, NULL, 7804, 'Nilsen Yogawan', 'Segera lakukan pengecekan lokasi untuk memastikan kondisi tanah. Koordinasi dengan tim lapangan untuk menilai risiko amblas dan buat laporan lengkap. Sampaikan hasil pengecekan dan langkah penanganan kepada konsumen secepatnya.', NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL),
